                break :blk if (start + du > len) len - start else du;
            };
            const item_count = if (args.len > 2) args.len - 2 else 0;
            if (item_count > del and len > 9007199254740991 - (item_count - del))
                return self.throwError("TypeError", "Invalid array length");
            const removed = try self.arraySpeciesCreate(Value.obj(o), del);
            // A plain dense Array `removed` preserves holes; a custom-species
            // result is CreateDataProperty'd per present index.
            const rdense = removed.asObj().is_array and removed.asObj().accessors == null and removed.asObj().attrs == null and removed.asObj().proxy_handler == null;
            var i: usize = 0;
            while (i < del) : (i += 1) {
                if (try self.arrIndexPresent(o, start + i)) {
                    try self.arrayResultPush(removed, i, try self.arrIndexGet(o, start + i)); // CreateDataPropertyOrThrow
                } else if (rdense) { // preserve a hole in the removed array
                    try removed.asObj().appendElement(self.arena, Value.undef());
                    try removed.asObj().markHole(self.arena, i);
                }
            }
            try self.arraySetLengthThrowing(removed.asObj(), del);
            const inserts: []const Value = if (args.len > 2) args[2..] else &.{};
            // Dense fast path: an ordinary array with no holes/accessors/sparse
            // tail can splice its contiguous value store directly.
            if (o.is_array and arrayLenWritable(o) and o.accessors == null and
                try o.splicePackedDenseElements(self.arena, start, del, inserts))
            {
                return removed;
            }
            // Generic Array.prototype.splice: shift the tail through [[Get]]/[[Set]]/
            // [[Delete]] (so holes move and an array-like `this` is updated), then
            // SetLength. Honour deletion failures (non-configurable) with a throw.
            if (item_count < del) {
                var k = start;
                while (k < len - del) : (k += 1) {
                    if (try self.arrIndexPresent(o, k + del))
                        try self.arrIndexSetOrThrow(o, k + item_count, try self.arrIndexGet(o, k + del))
                    else
                        try self.arrIndexDeleteOrThrow(o, k + item_count);
                }
                var k2 = len;
                while (k2 > len - del + item_count) : (k2 -= 1) try self.arrIndexDeleteOrThrow(o, k2 - 1);
            } else if (item_count > del) {
                var k = len - del;
                while (k > start) : (k -= 1) {
                    if (try self.arrIndexPresent(o, k + del - 1))
                        try self.arrIndexSetOrThrow(o, k + item_count - 1, try self.arrIndexGet(o, k + del - 1))
                    else
                        try self.arrIndexDeleteOrThrow(o, k + item_count - 1);
                }
            }
            for (inserts, 0..) |it, off| try self.arrIndexSetOrThrow(o, start + off, it);
            const new_len: f64 = @floatFromInt(len - del + item_count);
            if (!try self.setMemberResult(Value.obj(o), "length", Value.num(new_len), Value.obj(o)))
                return self.throwError("TypeError", "Cannot set length");
            return removed;
        }
        if (eq(name, "copyWithin")) {
            const len = ilen;
            const target = try relIndex(self, arg0(args), len, 0);
            const start = try relIndex(self, arg(args, 1), len, 0);
            const end = try relIndex(self, arg(args, 2), len, @floatFromInt(len));
            var count = @min(if (end > start) end - start else 0, len - target);
            if (count > (1 << 22)) return null;
            // Copy through [[Get]]/[[Set]] over the full length; a hole at the
            // source deletes the target (so holes move correctly). Walk backward
            // when the ranges overlap with target after source.
            var from = start;
            var to = target;
            var backward = false;
            if (from < to and to < from + count) {
                backward = true;
                from += count - 1;
                to += count - 1;
            }
            while (count > 0) {
                if (try self.arrIndexPresent(o, from))
                    try self.arrIndexSetOrThrow(o, to, try self.arrIndexGet(o, from))
                else
                    try self.arrIndexDeleteOrThrow(o, to);
                count -= 1;
                if (count == 0) break;
                if (backward) {
                    from -= 1;
                    to -= 1;
                } else {
                    from += 1;
                    to += 1;
                }
            }
            return Value.obj(o);
        }
        if (eq(name, "flatMap")) {
            const cb = arg0(args); // callability checked up front (cb_methods)
            const result = try self.arraySpeciesCreate(Value.obj(o), 0);
            var target_index: usize = 0;
            var i: usize = 0;
            while (i < ilen) : (i += 1) {
                if (!(try self.arrIndexPresent(o, i))) continue; // skip holes
                const el = try self.arrIndexGet(o, i);
                const m = try self.callValueWithThis(cb, &.{ el, Value.num(@floatFromInt(i)), Value.obj(o) }, cb_this);
                // FlattenIntoArray with depth 1: a mapped array (including a
                // Proxy for an array) is spread one level.
                if (m.isObject() and try objectToStringIsArray(self, m.asObj())) {
                    target_index = try self.flattenInto(result, m.asObj(), 0, target_index);
                } else {
                    try self.arrayResultPush(result, target_index, m);
                    target_index += 1;
                }
            }
            return result;
        }
        if (eq(name, "findLast") or eq(name, "findLastIndex")) {
            const want_index = eq(name, "findLastIndex");
            const cb = arg0(args);
            var i: usize = ilen;
            while (i > 0) {
                i -= 1;
                const el = try self.arrIndexGet(o, i); // visits holes (undefined)
                if ((try self.callValueWithThis(cb, &.{ el, Value.num(@floatFromInt(i)), Value.obj(o) }, cb_this)).toBoolean())
                    return if (want_index) Value.num(@floatFromInt(i)) else el;
            }
            return if (want_index) Value.num(-1) else Value.undef();
        }
        if (eq(name, "values")) return try self.iteratorOf(Value.obj(o));
        if (eq(name, "keys")) return try self.makeCursorIteratorWithKind(Value.obj(o), 1);
        if (eq(name, "entries")) return try self.makeCursorIteratorWithKind(Value.obj(o), 2);
        if (eq(name, "toString")) {
            // Array.prototype.toString does a dynamic Get(O, "join") and calls
            // it when callable. Typed arrays share this function object, so this
            // must reach %TypedArray%.prototype.join and its ValidateTypedArray.
            const recv = Value.obj(o);
            const join = try self.getProperty(recv, "join");
            if (join.isCallable()) return try self.callValueWithThis(join, &.{}, recv);
            return try objectProtoToStringFn(@ptrCast(self), recv, &.{});
        }
        return null;
    }

    /// FlattenIntoArray: walk `src`'s logical length, *skipping holes*
    /// (HasProperty) and recursing into nested arrays up to `depth`. The result
    /// is packed — flat does not preserve holes.
    fn flattenInto(self: *Interpreter, dst: Value, src: *value.Object, depth: f64, start: usize) EvalError!usize {
        const len: usize = if (src.is_array) src.arrayLength() else blk: {
            const lv = try self.toPrimitive(try self.getProperty(Value.obj(src), "length"), .number);
            break :blk toLen(lv.toNumber());
        };
        return self.flattenIntoLen(dst, src, len, depth, start);
    }

    fn flattenIntoLen(self: *Interpreter, dst: Value, src: *value.Object, len: usize, depth: f64, start: usize) EvalError!usize {
        var target_index = start;
        var i: usize = 0;
        while (i < len) : (i += 1) {
            if (!(try self.arrIndexPresent(src, i))) continue; // flat skips holes
            const el = try self.arrIndexGet(src, i);
            if (depth > 0 and el.isObject() and try objectToStringIsArray(self, el.asObj())) {
                target_index = try self.flattenInto(dst, el.asObj(), depth - 1, target_index);
            } else {
                try self.arrayResultPush(dst, target_index, el); // CreateDataPropertyOrThrow
                target_index += 1;
            }
        }
        return target_index;
    }

    /// SortCompare: `undefined` always sorts after everything else and is never
    /// handed to the comparator; otherwise defer to `sortCompare`.
    fn sortCompareSpec(self: *Interpreter, a: Value, b: Value, cmp: Value) EvalError!f64 {
        const a_u = a.isUndefined();
        const b_u = b.isUndefined();
        if (a_u or b_u) return if (a_u and b_u) 0 else if (a_u) 1 else -1;
        return self.sortCompare(a, b, cmp);
    }

    /// Comparator for Array.prototype.sort: >0 if `a` sorts after `b`.
    fn sortCompare(self: *Interpreter, a: Value, b: Value, cmp: Value) EvalError!f64 {
        if (cmp.isObject() and cmp.asObj().isCallableObject()) {
            const r = try self.callValue(cmp, &.{ a, b });
            const n = try self.toNumberV(r);
            return if (std.math.isNan(n)) 0 else n;
        }
        const as = try self.toStringV(a);
        const bs = try self.toStringV(b);
        return switch (std.mem.order(u8, as, bs)) {
            .lt => -1,
            .eq => 0,
            .gt => 1,
        };
    }

    fn numberMethod(self: *Interpreter, n: f64, name: []const u8, args: []const Value) EvalError!?Value {
        if (eq(name, "valueOf")) return Value.num(n);
        // Number.prototype.toLocaleString(locales, options) ===
        // new Intl.NumberFormat(locales, options).format(this).
        if (eq(name, "toLocaleString")) {
            const o = (try self.newObject()).asObj();
            try self.setProp(o, "\x00intl", Value.str("NumberFormat"));
            const locs = try canonicalizeLocaleList(self, if (args.len > 0) args[0] else Value.undef());
            const loc = if (locs.elements.items.len > 0) locs.elements.items[0].asStr() else "en";
            try self.setProp(o, "\x00locale", Value.str(loc));
            const ro = try nfProcessOptions(self, if (args.len > 1) args[1] else Value.undef());
            try self.setProp(o, "\x00opts", Value.obj(ro));
            return try intlNumberFormatFn(@ptrCast(self), Value.obj(o), &.{Value.num(n)});
        }
        if (eq(name, "toString")) {
            var radix: usize = 10;
            if (args.len > 0 and !args[0].isUndefined()) {
                const r = @trunc(try self.toNumberV(args[0]));
                if (std.math.isNan(r) or r < 2 or r > 36)
                    return self.throwError("RangeError", "toString() radix must be an integer between 2 and 36");
                radix = @intFromFloat(r);
            }
            if (radix == 10) return Value.str(try value.numberToString(self.arena, n));
            if (std.math.isNan(n)) return Value.str("NaN");
            if (std.math.isInf(n)) return Value.str(if (n < 0) "-Infinity" else "Infinity");
            return Value.str(try numberToRadix(self.arena, n, radix));
        }
        if (eq(name, "toFixed")) {
            // ToIntegerOrInfinity(fractionDigits) runs first (can throw TypeError
            // on a Symbol/BigInt or a throwing valueOf) — BEFORE the range check
            // and the not-finite return, per spec step order.
            const f = try self.toNumberV(arg0(args));
            const fi = if (std.math.isNan(f)) @as(f64, 0) else @trunc(f);
            if (fi < 0 or fi > 100)
                return self.throwError("RangeError", "toFixed() digits must be between 0 and 100");
            if (std.math.isNan(n) or std.math.isInf(n))
                return Value.str(try value.numberToString(self.arena, n));
            return Value.str(try toFixed(self.arena, n, @intFromFloat(fi)));
        }
        if (eq(name, "toExponential")) {
            const has_arg = args.len > 0 and !args[0].isUndefined();
            // Coerce the argument first (observable + can throw), then handle a
            // non-finite receiver.
            const f = try self.toNumberV(arg0(args));
            if (std.math.isNan(n)) return Value.str("NaN");
            if (std.math.isInf(n)) return Value.str(if (n < 0) "-Infinity" else "Infinity");
            var frac: ?usize = null;
            if (has_arg) {
                const fi = if (std.math.isNan(f)) @as(f64, 0) else @trunc(f);
                if (fi < 0 or fi > 100) return self.throwError("RangeError", "toExponential() argument must be between 0 and 100");
                frac = @intFromFloat(fi);
            }
            return Value.str(try toExponentialStr(self.arena, n, frac));
        }
        if (eq(name, "toPrecision")) {
            // `precision === undefined` returns ToString(x) without coercion;
            // otherwise ToIntegerOrInfinity(precision) runs before the not-finite
            // return.
            if (args.len == 0 or args[0].isUndefined()) return Value.str(try value.numberToString(self.arena, n));
            const p = try self.toNumberV(args[0]);
            if (std.math.isNan(n)) return Value.str("NaN");
            if (std.math.isInf(n)) return Value.str(if (n < 0) "-Infinity" else "Infinity");
            const pf = if (std.math.isNan(p)) @as(f64, 0) else @trunc(p);
            if (pf < 1 or pf > 100) return self.throwError("RangeError", "toPrecision() argument must be between 1 and 100");
            return Value.str(try toPrecisionStr(self.arena, n, @intFromFloat(pf)));
        }
        return null;
    }

    fn booleanMethod(self: *Interpreter, b: bool, name: []const u8, args: []const Value) EvalError!?Value {
        _ = self;
        _ = args;
        if (eq(name, "valueOf")) return Value.boolVal(b);
        if (eq(name, "toString")) return Value.str(if (b) "true" else "false");
        return null;
    }

    /// The well-known Symbol whose method backs a String regex-protocol method
    /// (`replaceAll` shares `Symbol.replace`), or null for a plain method.
    fn stringProtocolSymbol(_: *Interpreter, name: []const u8) ?[]const u8 {
        if (eq(name, "split")) return "split";
        if (eq(name, "match")) return "match";
        // `matchAll`/`replaceAll` are intentionally absent: their branches perform
        // the full spec dispatch (IsRegExp/global-flag check, GetMethod for objects).
        if (eq(name, "search")) return "search";
        if (eq(name, "replace")) return "replace";
        return null;
    }

    /// IsRegExp(v): true if `v` is an object whose `[Symbol.match]` is truthy
    /// (or, when that property is absent, has a [[RegExpMatcher]] — `is_regex`).
    pub fn isRegExp(self: *Interpreter, v: Value) EvalError!bool {
        if (!v.isObject()) return false;
        if (self.wellKnownSymbolKey("match")) |mkey| {
            const m = try self.getProperty(v, mkey);
            if (!m.isUndefined()) return m.toBoolean();
        }
        return v.asObj().is_regex;
    }

    fn stringProtocolDispatch(self: *Interpreter, name: []const u8, receiver: Value, args: []const Value) EvalError!?Value {
        const sym = self.stringProtocolSymbol(name) orelse return null;
        const target = arg0(args);
        if (!builtins.isRealObject(target)) return null;
        const key = self.wellKnownSymbolKey(sym) orelse return null;
        const method = try self.getProperty(target, key);
        if (method.isUndefined() or method.isNull()) return null;
        if (!method.isCallable()) return self.throwError("TypeError", "String.prototype protocol method is not callable");
        var argv: std.ArrayListUnmanaged(Value) = .empty;
        try argv.append(self.arena, receiver);
        if (args.len > 1) try argv.appendSlice(self.arena, args[1..]);
        return try self.callValueWithThis(method, argv.items, target);
    }

    fn replaceAllProtocolDispatch(self: *Interpreter, receiver: Value, args: []const Value) EvalError!?Value {
        const search = arg0(args);
        if (search.isUndefined() or search.isNull()) return null;
        if (try self.isRegExp(search)) {
            const flags_v = try self.getProperty(search, "flags");
            if (flags_v.isUndefined() or flags_v.isNull())
                return self.throwError("TypeError", "String.prototype.replaceAll called with a RegExp whose flags is undefined or null");
            const flags_s = try self.toStringV(flags_v);
            if (std.mem.indexOfScalar(u8, flags_s, 'g') == null)
                return self.throwError("TypeError", "String.prototype.replaceAll must be called with a global RegExp");
        }
        if (!builtins.isRealObject(search)) return null;
        const key = self.wellKnownSymbolKey("replace") orelse return null;
        const method = try self.getProperty(search, key);
        if (method.isUndefined() or method.isNull()) return null;
        if (!method.isCallable()) return self.throwError("TypeError", "searchValue[Symbol.replace] is not callable");
        return try self.callValueWithThis(method, &.{ receiver, arg(args, 1) }, search);
    }

    /// ToIntegerOrInfinity(v) clamped into `[0, len]` — the position argument of
    /// `includes`/`startsWith`/`endsWith` (a Symbol/BigInt throws via toNumberV).
    fn clampPos(self: *Interpreter, v: Value, len: usize) EvalError!usize {
        const n = try self.toNumberV(v);
        if (std.math.isNan(n) or n <= 0) return 0;
        const flen: f64 = @floatFromInt(len);
        if (n >= flen) return len;
        return @intFromFloat(@trunc(n));
    }

    fn stringMethod(self: *Interpreter, s: []const u8, name: []const u8, args: []const Value, check_protocol: bool) EvalError!?Value {
        if (eq(name, "valueOf") or eq(name, "toString")) return Value.str(s);
        if (check_protocol and eq(name, "replaceAll"))
            if (try self.replaceAllProtocolDispatch(Value.str(s), args)) |r| return r;
        // Well-known Symbol method protocol: `split`/`match`/`matchAll`/`search`/
        // `replace`/`replaceAll` first check their first argument for the matching
        // `Symbol.*` method and, if it is callable, delegate to it (with `this` =
        // that argument and the string as the first parameter). RegExp instances
        // use the protocol for methods whose spec algorithms are implemented.
        if (check_protocol) if (try self.stringProtocolDispatch(name, Value.str(s), args)) |r| return r;
        if (eq(name, "charAt")) {
            const pos = try self.stringPosition(s, arg0(args)) orelse return Value.str("");
            const cu = stringCodeUnitAt(s, pos) orelse return Value.str("");
            return Value.str(try self.stringFromCodeUnit(cu.unit));
        }
        if (eq(name, "charCodeAt")) {
            const pos = try self.stringPosition(s, arg0(args)) orelse return Value.num(std.math.nan(f64));
            const cu = stringCodeUnitAt(s, pos) orelse return Value.num(std.math.nan(f64));
            return Value.num(@floatFromInt(cu.unit));
        }
        if (eq(name, "indexOf")) {
            // ToString(searchString) precedes ToInteger(position), and each runs
            // the argument's valueOf/toString (so an abrupt completion in either
            // propagates in spec order).
            const sub = try self.toStringV(arg0(args));
            const start = try self.clampPos(arg(args, 1), s.len);
            return Value.num(if (std.mem.indexOfPos(u8, s, start, sub)) |idx| @floatFromInt(idx) else -1);
        }
        if (eq(name, "includes")) {
            if (try self.isRegExp(arg0(args))) return self.throwError("TypeError", "First argument to String.prototype.includes must not be a regular expression");
            const sub = try self.toStringV(arg0(args));
            const pos = try self.clampPos(arg(args, 1), s.len);
            return Value.boolVal(std.mem.indexOf(u8, s[pos..], sub) != null);
        }
        if (eq(name, "startsWith")) {
            if (try self.isRegExp(arg0(args))) return self.throwError("TypeError", "First argument to String.prototype.startsWith must not be a regular expression");
            const sub = try self.toStringV(arg0(args));
            const pos = try self.clampPos(arg(args, 1), s.len);
            return Value.boolVal(std.mem.startsWith(u8, s[pos..], sub));
        }
        if (eq(name, "endsWith")) {
            if (try self.isRegExp(arg0(args))) return self.throwError("TypeError", "First argument to String.prototype.endsWith must not be a regular expression");
            const sub = try self.toStringV(arg0(args));
            // `endPosition` defaults to the string length; the match ends there.
            const end_pos = if (args.len > 1 and !args[1].isUndefined()) try self.clampPos(args[1], s.len) else s.len;
            return Value.boolVal(std.mem.endsWith(u8, s[0..end_pos], sub));
        }
        if (eq(name, "slice")) {
            const len = utf16LenOfString(s);
            const start = try relIndex(self, arg0(args), len, 0);
            const end = try relIndex(self, arg(args, 1), len, @floatFromInt(len));
            return Value.str(if (start < end) try self.stringSliceUtf16(s, start, end) else "");
        }
        if (eq(name, "substring")) {
            const len = utf16LenOfString(s);
            var a0 = try self.stringClampPosition(s, arg0(args), 0);
            var b0 = try self.stringClampPosition(s, arg(args, 1), len);
            if (a0 > b0) {
                const t = a0;
                a0 = b0;
                b0 = t;
            }
            return Value.str(try self.stringSliceUtf16(s, a0, b0));
        }
        if (eq(name, "toUpperCase") or eq(name, "toLocaleUpperCase")) {
            if (eq(name, "toLocaleUpperCase")) {
                const locs = try canonicalizeLocaleList(self, if (args.len > 0) args[0] else Value.undef());
                const loc = if (locs.elements.items.len > 0) locs.elements.items[0].asStr() else "";
                if (localeIsLithuanian(loc)) return Value.str(try lithuanianUpper(self, s));
                if (localeIsTurkic(loc)) return Value.str(try turkicUpper(self, s));
            }
            return Value.str(try unicode_case.toUpper(self.arena, s));
        }
        if (eq(name, "toLowerCase") or eq(name, "toLocaleLowerCase")) {
            if (eq(name, "toLocaleLowerCase")) {
                const locs = try canonicalizeLocaleList(self, if (args.len > 0) args[0] else Value.undef());
                const loc = if (locs.elements.items.len > 0) locs.elements.items[0].asStr() else "";
                if (localeIsLithuanian(loc)) return Value.str(try lithuanianLower(self, s));
                if (localeIsTurkic(loc)) return Value.str(try turkicLower(self, s));
            }
            return Value.str(try unicode_case.toLower(self.arena, s));
        }
        if (eq(name, "trim")) return Value.str(jsTrim(s, true, true));
        if (eq(name, "repeat")) {
            const rn = try self.toNumberV(arg0(args));
            if (rn < 0 or std.math.isInf(rn)) return self.throwError("RangeError", "Invalid count value");
            const n = toLen(rn);
            var buf: std.ArrayListUnmanaged(u8) = .empty;
            var i: usize = 0;
            while (i < n) : (i += 1) try buf.appendSlice(self.arena, s);
            return Value.str(try buf.toOwnedSlice(self.arena));
        }
        if (eq(name, "concat")) {
            var buf: std.ArrayListUnmanaged(u8) = .empty;
            try buf.appendSlice(self.arena, s);
            for (args) |a| try buf.appendSlice(self.arena, try self.toStringV(a));
            return Value.str(try buf.toOwnedSlice(self.arena));
        }
        if (eq(name, "split")) {
            const result = try self.newArray();
            const out = &result.asObj().elements;
            // No separator → the whole string as the sole element.
            if (args.len == 0 or args[0].isUndefined()) {
                const lim: usize = if (args.len > 1 and !args[1].isUndefined()) value.Value.uint32FromF64(try self.toNumberV(args[1])) else std.math.maxInt(u32);
                if (lim == 0) return result;
                try out.append(self.arena, Value.str(try self.arena.dupe(u8, s)));
                return result;
            }
            // `limit` (ToUint32; absent -> effectively unbounded) is converted
            // before the separator's ToString, but `limit === 0` is checked after.
            const lim: usize = if (args.len > 1 and !args[1].isUndefined()) value.Value.uint32FromF64(try self.toNumberV(args[1])) else std.math.maxInt(u32);
            // Regex separator: split on each match, inserting capture groups, per
            // the String.prototype.split(@@split) algorithm.
            if (args[0].isObject() and args[0].asObj().is_regex) {
                const re = try self.compileRegex(args[0].asObj());
                if (lim == 0) return result;
                if (s.len == 0) {
                    // Empty input: [""] unless the pattern matches the empty string.
                    if ((re.find(s) catch null) == null) try out.append(self.arena, Value.str(s));
                    return result;
                }
                var p: usize = 0; // end of the previous piece
                var q: usize = 0; // scan cursor
                while (q < s.len) {
                    const m = re.find(s[q..]) catch null orelse break;
                    const m_start = q + m.start;
                    const m_end = q + m.end;
                    if (m_end == p) { // empty match flush against the last split — skip
                        q = m_start + 1;
                        continue;
                    }
                    try out.append(self.arena, Value.str(try self.arena.dupe(u8, s[p..m_start])));
                    if (out.items.len >= lim) return result;
                    for (0..m.captures.len) |ci| {
                        try out.append(self.arena, try self.captureVal(m, ci));
                        if (out.items.len >= lim) return result;
                    }
                    p = m_end;
                    q = if (m_end > m_start) m_end else m_end + 1;
                }
                try out.append(self.arena, Value.str(try self.arena.dupe(u8, s[p..])));
                return result;
            }
            const sep = try self.toStringV(args[0]);
            if (lim == 0) return result;
            if (sep.len == 0) {
                for (s) |c| {
                    if (out.items.len >= lim) return result;
                    try out.append(self.arena, Value.str(try self.arena.dupe(u8, &.{c})));
                }
                return result;
            }
            var it = std.mem.splitSequence(u8, s, sep);
            while (it.next()) |part| {
                if (out.items.len >= lim) return result;
                try out.append(self.arena, Value.str(try self.arena.dupe(u8, part)));
            }
            return result;
        }
        if (eq(name, "at")) {
            const n = try self.toNumberV(arg0(args));
            const fl = if (std.math.isNan(n)) 0 else @trunc(n);
            if (std.math.isInf(fl)) return Value.undef();
            const slen = utf16LenOfString(s);
            const slen_f = @as(f64, @floatFromInt(slen));
            if (fl < -slen_f or fl >= slen_f) return Value.undef();
            const idx: i64 = if (fl < 0) @as(i64, @intCast(slen)) + @as(i64, @intFromFloat(fl)) else @intFromFloat(fl);
            if (idx < 0 or idx >= slen) return Value.undef();
            const cu = stringCodeUnitAt(s, @intCast(idx)) orelse return Value.undef();
            return Value.str(try self.stringFromCodeUnit(cu.unit));
        }
        if (eq(name, "trimStart")) return Value.str(jsTrim(s, true, false));
        if (eq(name, "trimEnd")) return Value.str(jsTrim(s, false, true));
        if (eq(name, "isWellFormed")) {
            // Well-formed UTF-16 has no LONE surrogate. An astral code point is a
            // 4-byte UTF-8 sequence here; a high+low surrogate pair (e.g. from
            // concatenation, WTF-8-encoded) is also well-formed.
            var i: usize = 0;
            while (i < s.len) {
                if (wtf8SurrogateAt(s, i)) |first| {
                    if (isHighSurrogate(first)) {
                        if (wtf8SurrogateAt(s, i + 3)) |second| if (isLowSurrogate(second)) {
                            i += 6; // a valid pair
                            continue;
                        };
                    }
                    return Value.boolVal(false); // lone (or trailing low) surrogate
                }
                i += utf8SeqLen(s, i);
            }
            return Value.boolVal(true);
        }
        if (eq(name, "toWellFormed")) {
            // Replace every LONE surrogate with U+FFFD, leaving valid pairs intact.
            var buf: std.ArrayListUnmanaged(u8) = .empty;
            var i: usize = 0;
            while (i < s.len) {
                if (wtf8SurrogateAt(s, i)) |first| {
                    if (isHighSurrogate(first)) {
                        if (wtf8SurrogateAt(s, i + 3)) |second| if (isLowSurrogate(second)) {
                            try buf.appendSlice(self.arena, s[i .. i + 6]);
                            i += 6;
                            continue;
                        };
                    }
                    try buf.appendSlice(self.arena, "\u{FFFD}");
                    i += 3;
                } else {
                    const n = utf8SeqLen(s, i);
                    try buf.appendSlice(self.arena, s[i .. i + n]);
                    i += n;
                }
            }
            return Value.str(try buf.toOwnedSlice(self.arena));
        }
        if (eq(name, "padStart") or eq(name, "padEnd")) {
            const target = toLen(try self.toNumberV(arg0(args)));
            const len = utf16LenOfString(s);
            if (len >= target) return Value.str(try self.arena.dupe(u8, s));
            const pad = if (args.len > 1 and !args[1].isUndefined()) try self.toStringV(args[1]) else " ";
            const pad_units = utf16LenOfString(pad);
            if (pad_units == 0) return Value.str(try self.arena.dupe(u8, s));
            var buf: std.ArrayListUnmanaged(u8) = .empty;
            var fill_len = target - len;
            if (eq(name, "padEnd")) try buf.appendSlice(self.arena, s);
            while (fill_len >= pad_units) : (fill_len -= pad_units) try buf.appendSlice(self.arena, pad);
            if (fill_len > 0) try self.appendStringUtf16Prefix(&buf, pad, fill_len);
            if (eq(name, "padStart")) try buf.appendSlice(self.arena, s);
            return Value.str(try buf.toOwnedSlice(self.arena));
        }
        if (eq(name, "replace") or eq(name, "replaceAll")) {
            const all = eq(name, "replaceAll");
            const repl_val = arg(args, 1);
            const is_func = repl_val.isCallable();
            const a = self.arena;
            var buf: std.ArrayListUnmanaged(u8) = .empty;

            // Regex pattern: replace each match (all matches when global/replaceAll),
            // expanding `$` substitutions or invoking a function replacer.
            if (!all and arg0(args).isObject() and arg0(args).asObj().is_regex) {
                const ro = arg0(args).asObj();
                const g = all or std.mem.indexOfScalar(u8, ro.regex_flags, 'g') != null;
                const re = try self.compileRegex(ro);
                const template: []const u8 = if (is_func) "" else try self.toStringV(repl_val);
                var last: usize = 0; // end of the last copied region
                var search: usize = 0; // absolute scan cursor
                while (search <= s.len) {
                    const m = re.find(s[search..]) catch null orelse break;
                    const mstart = search + m.start;
                    const mend = search + m.end;
                    try buf.appendSlice(a, s[last..mstart]);
                    if (is_func) {
                        var call_args: std.ArrayListUnmanaged(Value) = .empty;
                        try call_args.append(a, Value.str(try a.dupe(u8, m.slice)));
                        for (0..m.captures.len) |i| try call_args.append(a, try self.captureVal(m, i));
                        try call_args.append(a, Value.num(@floatFromInt(mstart)));
                        try call_args.append(a, Value.str(s));
                        const r = try self.callValue(repl_val, call_args.items);
                        try buf.appendSlice(a, try self.toStringV(r));
                    } else {
                        const groups = try self.regexGroups(re, m);
                        try self.getSubstitution(&buf, template, m.slice, s, mstart, m.captures, groups);
                    }
                    last = mend;
                    search = if (mend > mstart) mend else mend + 1; // step past an empty match
                    if (!g) break;
                }
                try buf.appendSlice(a, s[last..]);
                return Value.str(try buf.toOwnedSlice(a));
            }

            // String pattern: replace the first occurrence (or all for replaceAll).
            const pat = try self.toStringV(arg0(args));
            const template: []const u8 = if (is_func) "" else try self.toStringV(repl_val);
            var from: usize = 0;
            while (from <= s.len) { // `from` stays in-bounds so the search never reads past the end
                const idx = std.mem.indexOfPos(u8, s, from, pat) orelse break;
                try buf.appendSlice(a, s[from..idx]);
                if (is_func) {
                    const r = try self.callValue(repl_val, &.{ Value.str(pat), Value.num(@floatFromInt(idx)), Value.str(s) });
                    try buf.appendSlice(a, try self.toStringV(r));
                } else {
                    try self.getSubstitution(&buf, template, pat, s, idx, &.{}, null);
                }
                from = idx + pat.len;
                if (pat.len == 0) { // empty pattern: copy one char and step past it
                    if (from < s.len) try buf.append(a, s[from]);
                    from += 1;
                }
                if (!all) break;
            }
            if (from <= s.len) try buf.appendSlice(a, s[from..]);
            return Value.str(try buf.toOwnedSlice(a));
        }
        if (eq(name, "codePointAt")) {
            // ToIntegerOrInfinity(pos): a position outside [0, len) yields undefined
            // (so a negative position is undefined, not clamped to index 0).
            const pos = try self.stringPosition(s, arg0(args)) orelse return Value.undef();
            const cu = stringCodeUnitAt(s, pos) orelse return Value.undef();
            if (cu.astral) |cp| return Value.num(@floatFromInt(cp));
            if (isHighSurrogate(cu.unit)) {
                if (stringCodeUnitAt(s, pos + 1)) |next| if (isLowSurrogate(next.unit)) {
                    const cp: u21 = 0x10000 + ((@as(u21, cu.unit) - 0xD800) << 10) + (@as(u21, next.unit) - 0xDC00);
                    return Value.num(@floatFromInt(cp));
                };
            }
            return Value.num(@floatFromInt(cu.unit));
        }
        if (eq(name, "lastIndexOf")) {
            // ToString(searchString) then ToNumber(position): a NaN position
            // (incl. the default `undefined`) searches the whole string; otherwise
            // the match must start at or before the clamped position.
            const sub = try self.toStringV(arg0(args));
            const np = try self.toNumberV(arg(args, 1));
            const limit: usize = if (std.math.isNan(np)) s.len else if (np <= 0)
                0
            else if (np >= @as(f64, @floatFromInt(s.len))) s.len else @intFromFloat(@trunc(np));
            if (sub.len == 0) return Value.num(@floatFromInt(@min(limit, s.len)));
            // A match starting at k (k ≤ limit) occupies s[k .. k+sub.len); the
            // largest such k is the last occurrence within s[0 .. limit+sub.len].
            const hi = @min(limit + sub.len, s.len);
            return Value.num(if (std.mem.lastIndexOf(u8, s[0..hi], sub)) |idx| @floatFromInt(idx) else -1);
        }
        if (eq(name, "substr")) {
            // `substr(start, length)`: start may count from the end.
            const start = try relIndex(self, arg0(args), s.len, 0);
            const remaining = s.len - start;
            const len: usize = if (args.len > 1 and !arg(args, 1).isUndefined()) blk: {
                const l = arg(args, 1).toNumber();
                if (std.math.isNan(l) or l <= 0) break :blk 0;
                if (std.math.isInf(l) or l >= @as(f64, @floatFromInt(remaining))) break :blk remaining;
                const lu: usize = @intFromFloat(@trunc(l));
                break :blk @min(lu, remaining);
            } else remaining;
            return Value.str(try self.arena.dupe(u8, s[start .. start + len]));
        }
        if (eq(name, "trimLeft")) return Value.str(jsTrim(s, true, false));
        if (eq(name, "trimRight")) return Value.str(jsTrim(s, false, true));
        // Annex B B.2.3 HTML wrapper methods (CreateHTML).
        {
            const HtmlSpec = struct { m: []const u8, tag: []const u8, attr: []const u8 };
            const html = [_]HtmlSpec{
                .{ .m = "anchor", .tag = "a", .attr = "name" },
                .{ .m = "big", .tag = "big", .attr = "" },
                .{ .m = "blink", .tag = "blink", .attr = "" },
                .{ .m = "bold", .tag = "b", .attr = "" },
                .{ .m = "fixed", .tag = "tt", .attr = "" },
                .{ .m = "fontcolor", .tag = "font", .attr = "color" },
                .{ .m = "fontsize", .tag = "font", .attr = "size" },
                .{ .m = "italics", .tag = "i", .attr = "" },
                .{ .m = "link", .tag = "a", .attr = "href" },
                .{ .m = "small", .tag = "small", .attr = "" },
                .{ .m = "strike", .tag = "strike", .attr = "" },
                .{ .m = "sub", .tag = "sub", .attr = "" },
                .{ .m = "sup", .tag = "sup", .attr = "" },
            };
            for (html) |h| {
                if (!eq(name, h.m)) continue;
                var buf: std.ArrayListUnmanaged(u8) = .empty;
                try buf.append(self.arena, '<');
                try buf.appendSlice(self.arena, h.tag);
                if (h.attr.len != 0) {
                    const v = try self.toStringV(arg0(args));
                    try buf.append(self.arena, ' ');
                    try buf.appendSlice(self.arena, h.attr);
                    try buf.appendSlice(self.arena, "=\"");
                    for (v) |ch| {
                        if (ch == '"') try buf.appendSlice(self.arena, "&quot;") else try buf.append(self.arena, ch);
                    }
                    try buf.append(self.arena, '"');
                }
                try buf.append(self.arena, '>');
                try buf.appendSlice(self.arena, s);
                try buf.appendSlice(self.arena, "</");
                try buf.appendSlice(self.arena, h.tag);
                try buf.append(self.arena, '>');
                return Value.str(try buf.toOwnedSlice(self.arena));
            }
        }
        if (eq(name, "localeCompare")) {
            const other = try self.toStringV(arg0(args));
            const opts = try collatorOptionsFrom(self, if (args.len > 1) args[1] else Value.undef(), if (args.len > 2) args[2] else Value.undef());
            return Value.num(try collatorCompareStrings(self, s, other, opts));
        }
        if (eq(name, "normalize")) {
            // The form (default "NFC") is ToString'd — a Symbol throws TypeError —
            // and must be one of the four Unicode normalization forms.
            const form = if (args.len > 0 and !arg0(args).isUndefined()) try self.toStringV(arg0(args)) else "NFC";
            const nf: unicode_normalize.Form = if (eq(form, "NFC"))
                .nfc
            else if (eq(form, "NFD"))
                .nfd
            else if (eq(form, "NFKC"))
                .nfkc
            else if (eq(form, "NFKD"))
                .nfkd
            else
                return self.throwError("RangeError", "The normalization form should be one of NFC, NFD, NFKC, NFKD");
            return Value.str(try unicode_normalize.normalize(self.arena, s, nf));
        }
        if (eq(name, "search")) {
            const re_obj = try self.toRegexObject(arg0(args));
            if (self.wellKnownSymbolKey("search")) |key| {
                const method = try self.getProperty(Value.obj(re_obj), key);
                return try self.callValueWithThis(method, &.{Value.str(s)}, Value.obj(re_obj));
            }
            return try self.regexpSearch(Value.obj(re_obj), s);
        }
        if (eq(name, "match")) {
            const re_obj = try self.toRegexObject(arg0(args));
            if (self.wellKnownSymbolKey("match")) |key| {
                const method = try self.getProperty(Value.obj(re_obj), key);
                return try self.callValueWithThis(method, &.{Value.str(s)}, Value.obj(re_obj));
            }
            return try self.regexpMatch(Value.obj(re_obj), s);
        }
        if (eq(name, "matchAll")) {
            // String.prototype.matchAll(regexp): dispatch to regexp[@@matchAll]
            // when the argument supplies one, after the global-flag invariant.
            const regexp = arg0(args);
            const skey = self.wellKnownSymbolKey("matchAll");
            if (!regexp.isUndefined() and !regexp.isNull()) {
                if (try self.isRegExp(regexp)) {
                    const flags_v = try self.getProperty(regexp, "flags");
                    if (flags_v.isUndefined() or flags_v.isNull())
                        return self.throwError("TypeError", "String.prototype.matchAll called with a RegExp whose flags is undefined or null");
                    const flags_s = try self.toStringV(flags_v);
                    if (std.mem.indexOfScalar(u8, flags_s, 'g') == null)
                        return self.throwError("TypeError", "String.prototype.matchAll called with a non-global RegExp argument");
                }
                // GetMethod(regexp, @@matchAll) — only an object can carry one; a
                // primitive argument (string/number, and the object-boxed
                // BigInt/Symbol) is left to the RegExpCreate fallback below.
                if (isRegExpObjectValue(regexp)) if (skey) |k| {
                    const m = try self.getProperty(regexp, k);
                    if (!m.isUndefined() and !m.isNull()) {
                        if (!m.isCallable()) return self.throwError("TypeError", "regexp[Symbol.matchAll] is not callable");
                        return try self.callValueWithThis(m, &.{Value.str(s)}, regexp);
                    }
                };
            }
            // RegExpCreate(regexp, "g"), then Invoke(rx, @@matchAll, « S ») so a
            // replaced/deleted RegExp.prototype[@@matchAll] is honoured.
            const src = if (regexp.isObject() and regexp.asObj().is_regex)
                regexp.asObj().regex_source
            else if (regexp.isUndefined())
                ""
            else
                try self.toStringV(regexp);
            const rx = try self.makeRegex(src, "g");
            if (skey) |k| {
                const m = try self.getProperty(rx, k);
                return try self.callValueWithThis(m, &.{Value.str(s)}, rx);
            }
            return try self.regexpMatchAll(rx, s);
        }
        return null;
    }

    /// Coerce a value to a RegExp object: a regex stays as-is; anything else
    /// becomes `new RegExp(String(v))`.
    fn toRegexObject(self: *Interpreter, v: Value) EvalError!*value.Object {
        if (v.isObject() and v.asObj().is_regex) return v.asObj();
        const pat = if (v.isUndefined()) "" else try self.toStringV(v);
        return (try self.makeRegex(pat, "")).asObj();
    }

    /// A capture group's value: `undefined` when the group did not participate
    /// in the match (an unmatched optional), else its matched substring.
    fn captureVal(self: *Interpreter, m: regex.Match, i: usize) EvalError!Value {
        if (i < m.captures_present.len and !m.captures_present[i]) return Value.undef();
        return Value.str(try self.arena.dupe(u8, m.captures[i]));
    }

    /// The `groups` object for a match — `{ name: capture }` for each named
    /// group — or null when the pattern has no named groups (then `groups` is
    /// `undefined`).
    fn regexGroups(self: *Interpreter, re: *regex.Regex, m: regex.Match) EvalError!?*value.Object {
        if (re.named_capture_list.len == 0) return null;
        const o = (try self.newObject()).asObj();
        o.proto = null; // RegExpBuiltinExec: the groups object is ObjectCreate(null)
        for (re.named_capture_list) |entry| {
            const v: Value = if (re.getNamedCapture(&m, entry.name)) |capture|
                Value.str(try self.arena.dupe(u8, capture))
            else
                Value.undef();
            try self.setProp(o, entry.name, v);
        }
        return o;
    }

    fn namedCaptureSpan(re: *regex.Regex, m: regex.Match, name: []const u8) ?[2]usize {
        for (re.named_capture_list) |entry| {
            if (!std.mem.eql(u8, entry.name, name)) continue;
            if (entry.index == 0) continue;
            const i = entry.index - 1;
            if (i >= m.captures_present.len or i >= m.capture_spans.len) continue;
            if (!m.captures_present[i]) continue;
            return m.capture_spans[i];
        }
        return null;
    }

    /// A two-element `[start, end]` array, as used by the match-indices array.
    fn indexPair(self: *Interpreter, lo: usize, hi: usize) EvalError!Value {
        const p = (try self.newArray()).asObj();
        try p.elements.append(p.elementsAllocator(self.arena), Value.num(@floatFromInt(lo)));
        try p.elements.append(p.elementsAllocator(self.arena), Value.num(@floatFromInt(hi)));
        return Value.obj(p);
    }

    /// MakeIndicesArray: the `.indices` property an `exec` result carries when the
    /// regexp has the `d` (hasIndices) flag — element 0 is `[start, end]` of the
    /// whole match, element i+1 is the i-th capture's `[start, end]` (or undefined
    /// if it did not participate), and `.groups` maps each named group likewise.
    /// `base` is the byte offset of the search window within the original input.
    fn makeIndicesArray(self: *Interpreter, re: *regex.Regex, m: regex.Match, input: []const u8, base: usize) EvalError!*value.Object {
        const idx = (try self.newArray()).asObj();
        try idx.elements.append(idx.elementsAllocator(self.arena), try self.indexPair(
            utf16IndexForByteOffset(input, base + m.start),
            utf16IndexForByteOffset(input, base + m.end),
        ));
        for (0..m.captures.len) |i| {
            const present = i < m.captures_present.len and m.captures_present[i];
            if (present and i < m.capture_spans.len) {
                try idx.elements.append(idx.elementsAllocator(self.arena), try self.indexPair(
                    utf16IndexForByteOffset(input, base + m.capture_spans[i][0]),
                    utf16IndexForByteOffset(input, base + m.capture_spans[i][1]),
                ));
            } else {
                try idx.elements.append(idx.elementsAllocator(self.arena), Value.undef());
            }
        }
        if (re.named_capture_list.len > 0) {
            const g = (try self.newObject()).asObj();
            g.proto = null; // MakeIndicesArray: groups is ObjectCreate(null)
            for (re.named_capture_list) |entry| {
                const v: Value = if (namedCaptureSpan(re, m, entry.name)) |span|
                    try self.indexPair(
                        utf16IndexForByteOffset(input, base + span[0]),
                        utf16IndexForByteOffset(input, base + span[1]),
                    )
                else
                    Value.undef();
                try self.setProp(g, entry.name, v);
            }
            try self.setProp(idx, "groups", Value.obj(g));
        } else {
            try self.setProp(idx, "groups", Value.undef());
        }
        return idx;
    }

    /// GetSubstitution: append `template` to `buf`, expanding the `$` forms —
    /// `$$`, `$&` (matched), `` $` `` (prefix), `$'` (suffix), `$n`/`$nn`
    /// (capture groups, 1-based), and `$<name>` (named groups).
    fn getSubstitution(
        self: *Interpreter,
        buf: *std.ArrayListUnmanaged(u8),
        template: []const u8,
        matched: []const u8,
        str: []const u8,
        position: usize,
        captures: []const []const u8,
        groups: ?*value.Object,
    ) EvalError!void {
        const a = self.arena;
        var i: usize = 0;
        while (i < template.len) : (i += 1) {
            if (template[i] != '$' or i + 1 >= template.len) {
                try buf.append(a, template[i]);
                continue;
            }
            switch (template[i + 1]) {
                '$' => {
                    try buf.append(a, '$');
                    i += 1;
                },
                '&' => {
                    try buf.appendSlice(a, matched);
                    i += 1;
                },
                '`' => {
                    try buf.appendSlice(a, str[0..position]);
                    i += 1;
                },
                '\'' => {
                    const end = position + matched.len;
                    try buf.appendSlice(a, if (end <= str.len) str[end..] else "");
                    i += 1;
                },
                '<' => {
                    // `$<name>` — only when the pattern had named groups.
                    if (groups == null) {
                        try buf.append(a, '$');
                        continue;
                    }
                    const close = std.mem.indexOfScalarPos(u8, template, i + 2, '>') orelse {
                        try buf.append(a, '$');
                        continue;
                    };
                    const gv = groups.?.getOwn(template[i + 2 .. close]) orelse Value.undef();
                    if (gv.isString()) try buf.appendSlice(a, gv.asStr());
                    i = close;
                },
                '0'...'9' => {
                    var idx: usize = template[i + 1] - '0';
                    var consumed: usize = 1;
                    if (i + 2 < template.len and template[i + 2] >= '0' and template[i + 2] <= '9') {
                        const two = idx * 10 + (template[i + 2] - '0');
                        if (two >= 1 and two <= captures.len) {
                            idx = two;
                            consumed = 2;
                        }
                    }
                    if (idx >= 1 and idx <= captures.len) {
                        try buf.appendSlice(a, captures[idx - 1]);
                        i += consumed;
                    } else {
                        try buf.append(a, '$'); // not a valid group reference → literal `$`
                    }
                },
                else => try buf.append(a, '$'),
            }
        }
    }

    fn getSubstitutionValues(
        self: *Interpreter,
        buf: *std.ArrayListUnmanaged(u8),
        template: []const u8,
        matched: []const u8,
        str: []const u8,
        position: usize,
        captures: []const Value,
        groups: Value,
    ) EvalError!void {
        const a = self.arena;
        var i: usize = 0;
        while (i < template.len) : (i += 1) {
            if (template[i] != '$' or i + 1 >= template.len) {
                try buf.append(a, template[i]);
                continue;
            }
            switch (template[i + 1]) {
                '$' => {
                    try buf.append(a, '$');
                    i += 1;
                },
                '&' => {
                    try buf.appendSlice(a, matched);
                    i += 1;
                },
                '`' => {
                    try appendUtf16Slice(buf, a, str, 0, position);
                    i += 1;
                },
                '\'' => {
                    const end = position + utf16LenOfString(matched);
                    try appendUtf16Slice(buf, a, str, @min(end, utf16LenOfString(str)), utf16LenOfString(str));
                    i += 1;
                },
                '<' => {
                    if (groups.isUndefined()) {
                        try buf.append(a, '$');
                        continue;
                    }
                    const close = std.mem.indexOfScalarPos(u8, template, i + 2, '>') orelse {
                        try buf.append(a, '$');
                        continue;
                    };
                    const gv = try self.getProperty(groups, template[i + 2 .. close]);
                    if (!gv.isUndefined()) try buf.appendSlice(a, try self.toStringV(gv));
                    i = close;
                },
                '0'...'9' => {
                    var idx: usize = template[i + 1] - '0';
                    var consumed: usize = 1;
                    if (i + 2 < template.len and template[i + 2] >= '0' and template[i + 2] <= '9') {
                        const two = idx * 10 + (template[i + 2] - '0');
                        if (two >= 1 and two <= captures.len) {
                            idx = two;
                            consumed = 2;
                        }
                    }
                    if (idx >= 1 and idx <= captures.len) {
                        if (!captures[idx - 1].isUndefined()) try buf.appendSlice(a, captures[idx - 1].asStr());
                        i += consumed;
                    } else {
                        try buf.append(a, '$');
                    }
                },
                else => try buf.append(a, '$'),
            }
        }
    }

    // ---- try / catch / finally --------------------------------------------

    fn evalTry(self: *Interpreter, t: *ast.TryNode) EvalError!Value {
        var result: Value = Value.undef();
        if (self.eval(t.block)) |v| {
            result = v;
        } else |err| {
            if (err == error.Throw and t.catch_block != null) {
                const exc = self.exception;
                self.exception = Value.undef();
                const catch_env = try gc_mod.allocEnv(self.arena);
                self.initEnvironment(catch_env, self.env, false);
                const saved = self.env;
                self.env = catch_env;
                // Bind the catch target (identifier or destructuring pattern)
                // into the catch scope.
                if (t.catch_param) |p| try self.bindPattern(p, exc, true);
                const catch_result = self.eval(t.catch_block.?);
                self.env = saved;
                if (catch_result) |v| {
                    result = v;
                } else |cerr| {
                    if (t.finally_block) |fb| _ = try self.eval(fb);
                    return cerr;
                }
            } else {
                // No catch (or a non-JS host error): run finally, then rethrow.
                if (t.finally_block) |fb| _ = try self.eval(fb);
                return err;
            }
        }
        if (t.finally_block) |fb| _ = try self.eval(fb);
        return result;
    }

    fn evalUnary(self: *Interpreter, op: ast.UnaryOp, operand: *Node) EvalError!Value {
        // `typeof <unresolved identifier>` is "undefined" rather than a thrown
        // ReferenceError — the one context where an unbound name doesn't throw.
        if (op == .typeof and operand.* == .identifier and self.env.get(operand.identifier) == null and self.globalProp(operand.identifier) == null)
            return Value.str("undefined");
        const v = try self.eval(operand);
        // BigInt unary: `-`/`~` stay BigInt; unary `+` is a TypeError; `typeof`/
        // `!`/`void` work as for any value.
        if (v.isObject() and v.asObj().is_bigint and (op == .neg or op == .pos or op == .bit_not)) {
            return switch (op) {
                .neg => try negateBigIntObject(self, v.asObj()),
                .bit_not => try bitNotBigIntObject(self, v.asObj()),
                .pos => self.throwError("TypeError", "Cannot convert a BigInt value to a number"),
                else => unreachable,
            };
        }
        return switch (op) {
            .neg => Value.num(-(try self.toNumberV(v))),
            .pos => Value.num(try self.toNumberV(v)),
            .not => Value.boolVal(!v.toBoolean()),
            .typeof => Value.str(v.typeOf()),
            .bit_not => Value.num(@floatFromInt(~v.toInt32())),
            .void_op => Value.undef(),
            .to_string => Value.str(try self.toStringV(v)), // template-substitution ToString
        };
    }

    fn evalLogical(self: *Interpreter, op: ast.LogicalOp, left: *Node, right: *Node) EvalError!Value {
        const l = try self.eval(left);
        return switch (op) {
            .@"and" => if (l.toBoolean()) try self.eval(right) else l,
            .@"or" => if (l.toBoolean()) l else try self.eval(right),
            .nullish => if (l.isNull() or l.isUndefined()) try self.eval(right) else l,
        };
    }

    fn evalBinary(self: *Interpreter, op: ast.BinaryOp, left_node: *Node, right_node: *Node) EvalError!Value {
        // `#field in obj` — a private-name brand check. The LHS is a private-name
        // reference (an identifier whose text starts with `#`), which can't be
        // evaluated as an ordinary value.
        if (op == .in_op and left_node.* == .identifier and value.isPrivateKey(left_node.identifier)) {
            const robj = try self.eval(right_node);
            if (!robj.isObject())
                return self.throwError("TypeError", "Cannot use 'in' to search for a private name in a non-object");
            // Private elements are hidden from ordinary reflection, so look them
            // up directly. A field is an own data slot; a method/accessor lives on
            // the class prototype, so walk the prototype chain too.
            const key = left_node.identifier;
            var cur: ?*value.Object = robj.asObj();
            var has = false;
            while (cur) |c| {
                if (c.getOwn(key) != null or c.getAccessor(key) != null) {
                    has = true;
                    break;
                }
                cur = c.proto;
            }
            return Value.boolVal(has);
        }
        const l = try self.eval(left_node);
        const r = try self.eval(right_node);
        return self.applyBinary(op, l, r);
    }

    /// Apply a binary operator to two already-evaluated operands. Shared by the
    /// tree-walker and the bytecode VM.
    /// ToPrimitive: coerce a value to a primitive. Non-objects pass through; a
    /// Symbol is returned as-is. For an object, try `valueOf` then `toString`
    /// (order flipped for a string hint) via `callMethod` — so the universal
    /// `valueOf`/`toString` apply even to proto-less plain objects — and the
    /// first primitive result wins.
    pub fn toPrimitive(self: *Interpreter, v: Value, hint: enum { default, number, string }) EvalError!Value {
        if (!v.isObject() or v.asObj().is_symbol or v.asObj().is_bigint) return v;
        const o = v.asObj();
        // GetMethod(v, @@toPrimitive): if present, it alone decides — it is called
        // with the hint string and must return a non-object (an object result is
        // the "Cannot convert" TypeError); a non-callable @@toPrimitive throws.
        if (self.wellKnownSymbolKey("toPrimitive")) |tpkey| {
            const exotic = try self.getProperty(v, tpkey);
            if (!exotic.isUndefined() and !exotic.isNull()) {
                if (!exotic.isCallable()) return self.throwError("TypeError", "@@toPrimitive value is not callable");
                const hint_str: []const u8 = switch (hint) {
                    .string => "string",
                    .number => "number",
                    .default => "default",
                };
                const res = try self.callValueWithThis(exotic, &.{Value.str(hint_str)}, v);
                if (!res.isObject() or res.asObj().is_symbol or res.asObj().is_bigint) return res;
                return self.throwError("TypeError", "Cannot convert object to primitive value");
            }
        }
        // Honor a *user-defined* valueOf/toString (a JS function found on the
        // object or its prototype chain — e.g. `{ valueOf() {…} }` or a class
        // method) in the hint's order; the first primitive result wins. The
        // engine's built-in `valueOf`/`toString` (native prototype thunks) are
        // skipped here — falling through to the built-in coercion below — which
        // also avoids looping back through method dispatch.
        const names: [2][]const u8 = if (hint == .string) .{ "toString", "valueOf" } else .{ "valueOf", "toString" };
        var user_tried: u8 = 0;
        var builtin_wrapper_value_of = false;
        var builtin_to_string = false;
        var builtin_to_string_method: ?Value = null;
        outer: for (names) |m| {
            // OrdinaryToPrimitive resolves each method via `Get(O, name)`, so an
            // *accessor* `valueOf`/`toString` getter is run (and its abrupt
            // completion must propagate — `{ get valueOf() { throw } }`). A data
            // property that is a JS function is the method directly; the engine's
            // native prototype thunks / non-callable shadows are left to the
            // built-in coercion below (calling them would loop through dispatch).
            var method: ?Value = null;
            var cur: ?*value.Object = o;
            while (cur) |c| : (cur = c.proto) {
                if (c.getAccessor(m)) |acc| {
                    if (acc.get) |g| {
                        if (!g.isUndefined()) method = try self.callValueWithThis(g, &.{}, v);
                    }
                    break;
                }
                if (c.getOwn(m)) |fv| {
                    if (fv.isObject() and (fv.asObj().js_func != null or (c == o and fv.asObj().native != null) or (o.temporal != null and std.mem.eql(u8, m, "valueOf") and fv.asObj().native != null))) method = fv
                        // Primitive wrappers' native valueOf is a spec builtin that
                        // produces the boxed primitive at this position in the
                        // OrdinaryToPrimitive order, so do not continue to a later
                        // user toString accessor for default/number hints.
                    else if (std.mem.eql(u8, m, "valueOf") and o.prim != null and fv.isCallable()) builtin_wrapper_value_of = true
                        // A callable native `toString` thunk yields a primitive string
                        // (the built-in coercion below); it must run at *this* position
                        // in the hint order — so stop here rather than trying a later
                        // user `valueOf` (e.g. String({ valueOf() {…} }) is
                        // "[object Object]", not the valueOf result).
                    else if (std.mem.eql(u8, m, "toString") and fv.isCallable()) {
                        builtin_to_string = true;
                        builtin_to_string_method = fv;
                    }
                    break; // native thunk or non-callable shadow → built-in coercion
                }
            }
            if (builtin_wrapper_value_of or builtin_to_string) break :outer;
            if (method) |fnv| {
                if (fnv.isCallable()) {
                    user_tried += 1;
                    const res = try self.callValueWithThis(fnv, &.{}, v);
                    // A BigInt or Symbol result is a primitive (it is represented
                    // as an object internally), so it ends ToPrimitive too.
                    if (!res.isObject() or res.asObj().is_bigint or res.asObj().is_symbol) return res;
                }
            }
        }
        // Both `toString` and `valueOf` were user-defined and each returned an
        // object — there's no built-in to fall back to, so this is the spec's
        // "Cannot convert object to primitive value" TypeError.
        if (user_tried == 2) return self.throwError("TypeError", "Cannot convert object to primitive value");
        // A callable object with no user-defined valueOf/toString stringifies via
        // Function.prototype.toString (its source text / native syntax). `valueOf`
        // returns the object itself, so `toString` always wins regardless of hint.
        if (o.isCallableObject()) return try self.functionToString(o);
        // A primitive-wrapper object (`new Number/String/Boolean`) with no user
        // override unwraps to its boxed primitive — except for a string hint,
        // where it stringifies (so `new Number(5) + 1 === 6` but `String hint`
        // gives "5").
        if (o.prim) |p| {
            if (builtin_wrapper_value_of) return p;
            if (builtin_to_string) {
                if (p.isObject() and p.asObj().is_symbol) {
                    const ds = p.asObj().sym_desc orelse "";
                    return Value.str(try std.mem.concat(self.arena, u8, &.{ "Symbol(", ds, ")" }));
                }
                return Value.str(try p.toString(self.arena));
            }
            return self.throwError("TypeError", "Cannot convert object to primitive value");
        }
        // A Date with the built-in coercion: a number hint (`Number(date)`,
        // `+date`, `date - date`) yields its time value; string/default hints
        // (Date's default hint is "string": `\`${date}\``, `date + ""`) yield the
        // built-in Date toString, which OrdinaryToPrimitive above skipped as a
        // native thunk.
        if (o.is_date) {
            if (hint == .number) return Value.num(o.date_ms);
            return (try self.dateMethod(o, "toString", &.{})) orelse Value.str("Invalid Date");
        }
        // The built-in "[object …]" / array-join / Date / error fallback is the
        // result of the *built-in* `toString`; it is only reachable when
        // `toString` still resolves to that built-in. If it is shadowed — by a
        // non-callable own value (`toString: undefined`) or by a user method
        // (which, having been tried in the loop above, must have returned an
        // object, since we're at the fallback) — there is no primitive and no
        // built-in to fall back to: the spec's "Cannot convert object to
        // primitive value" TypeError.
        const own_ts = o.getOwn("toString");
        const ts_shadowed = (own_ts != null and !own_ts.?.isCallable()) or userMethodOf(o, "toString") != null;
        if (ts_shadowed) return self.throwError("TypeError", "Cannot convert object to primitive value");
        if (!builtin_to_string) return self.throwError("TypeError", "Cannot convert object to primitive value");
        if (builtin_to_string_method) |m| {
            const res = try self.callValueWithThis(m, &.{}, v);
            if (!res.isObject() or res.asObj().is_symbol or res.asObj().is_bigint) return res;
        }
        return self.throwError("TypeError", "Cannot convert object to primitive value");
    }

    /// A *user-defined* `name` method on `o`'s own properties or prototype chain
    /// — a JS function (`js_func`), not one of the engine's native built-in
    /// prototype thunks (calling those would loop back through dispatch). The
    /// nearest definition shadows: if it's a native thunk we stop and report
    /// none, so ToPrimitive uses the built-in coercion instead.
    fn userMethodOf(o: *value.Object, name: []const u8) ?Value {
        var cur: ?*value.Object = o;
        while (cur) |c| : (cur = c.proto) {
            if (c.getOwn(name)) |fv| {
                return if (fv.isObject() and fv.asObj().js_func != null) fv else null;
            }
        }
        return null;
    }

    pub fn applyBinary(self: *Interpreter, op_in: ast.BinaryOp, l_in: Value, r_in: Value) EvalError!Value {
        const op = op_in;
        var l = l_in;
        var r = r_in;
        // Coerce object operands to primitives first (ToPrimitive). `+` uses the
        // "default" hint; the other arithmetic / relational / bitwise ops use
        // "number". Equality and instanceof/in handle objects themselves.
        switch (op) {
            .add => {
                l = try self.toPrimitive(l, .default);
                r = try self.toPrimitive(r, .default);
            },
            .sub, .mul, .div, .mod, .pow, .lt, .le, .gt, .ge, .bit_and, .bit_or, .bit_xor, .shl, .shr, .ushr => {
                l = try self.toPrimitive(l, .number);
                r = try self.toPrimitive(r, .number);
            },
            .eq, .neq => {
                // Abstract equality (IsLooselyEqual): when one operand is an
                // ordinary object and the other is a primitive, the object is
                // ToPrimitive'd (default hint) and the comparison retried — so
                // `Object("1") == "1"` and `{valueOf(){return 1}} == 1` hold. Two
                // objects compare by identity, and an object vs null/undefined is
                // always unequal, so neither is coerced. A BigInt/Symbol value is
                // boxed as an object here but counts as a primitive operand.
                const l_obj = l.isObject() and !l.asObj().is_bigint and !l.asObj().is_symbol;
                const r_obj = r.isObject() and !r.asObj().is_bigint and !r.asObj().is_symbol;
                if (l_obj and !r_obj and !r.isUndefined() and !r.isNull()) l = try self.toPrimitive(l, .default);
                if (r_obj and !l_obj and !l.isUndefined() and !l.isNull()) r = try self.toPrimitive(r, .default);
            },
            else => {},
        }
        // BigInt operands. Arithmetic/bitwise require both to be BigInt (mixing
        // with a Number is a TypeError); relational ops compare mathematically;
        // `+` with a string still concatenates.
        const l_big = l.isObject() and l.asObj().is_bigint;
        const r_big = r.isObject() and r.asObj().is_bigint;
        if (l_big or r_big) {
            switch (op) {
                .add => if (l.isString() or r.isString()) {} else return self.bigIntBinary(op, l, r, l_big, r_big),
                .sub, .mul, .div, .mod, .pow, .bit_and, .bit_or, .bit_xor, .shl, .shr => return self.bigIntBinary(op, l, r, l_big, r_big),
                .ushr => return self.throwError("TypeError", "BigInts have no unsigned right shift, use >> instead"),
                .lt => return Value.boolVal(bigCmp(l, r) < 0),
                .le => return Value.boolVal(bigCmp(l, r) <= 0),
                .gt => return Value.boolVal(bigCmp(l, r) > 0),
                .ge => return Value.boolVal(bigCmp(l, r) >= 0),
                else => {},
            }
        }
        return switch (op) {
            .add => blk: {
                // String concatenation if either operand is a string.
                if (l.isString() or r.isString()) {
                    const ls = try self.toStringV(l);
                    const rs = try self.toStringV(r);
                    break :blk Value.str(try std.mem.concat(self.arena, u8, &.{ ls, rs }));
                }
                break :blk Value.num(l.toNumber() + r.toNumber());
            },
            .sub => Value.num(l.toNumber() - r.toNumber()),
            .mul => Value.num(l.toNumber() * r.toNumber()),
            .div => Value.num(l.toNumber() / r.toNumber()),
            .mod => Value.num(@mod(l.toNumber(), r.toNumber())),
            .pow => Value.num(std.math.pow(f64, l.toNumber(), r.toNumber())),
            .lt => Value.boolVal(try lessThan(self, l, r)),
            .le => Value.boolVal(!(try lessThan(self, r, l)) and !relationalNaN(l, r)),
            .gt => Value.boolVal(try lessThan(self, r, l)),
            .ge => Value.boolVal(!(try lessThan(self, l, r)) and !relationalNaN(l, r)),
            .eq => Value.boolVal(value.looseEquals(l, r)),
            .neq => Value.boolVal(!value.looseEquals(l, r)),
            .eq_strict => Value.boolVal(value.strictEquals(l, r)),
            .neq_strict => Value.boolVal(!value.strictEquals(l, r)),
            .instanceof => Value.boolVal(try self.instanceOf(l, r)),
            .in_op => Value.boolVal(try self.inOperator(l, r)),
            .bit_and => Value.num(@floatFromInt(l.toInt32() & r.toInt32())),
            .bit_or => Value.num(@floatFromInt(l.toInt32() | r.toInt32())),
            .bit_xor => Value.num(@floatFromInt(l.toInt32() ^ r.toInt32())),
            .shl => blk: {
                const sh: u5 = @intCast(r.toUint32() & 31);
                break :blk Value.num(@floatFromInt(@as(i32, @bitCast(l.toUint32() << sh))));
            },
            .shr => blk: {
                const sh: u5 = @intCast(r.toUint32() & 31);
                break :blk Value.num(@floatFromInt(l.toInt32() >> sh));
            },
            .ushr => blk: {
                const sh: u5 = @intCast(r.toUint32() & 31);
                break :blk Value.num(@floatFromInt(l.toUint32() >> sh));
            },
        };
    }

    /// A BigInt binary op (both operands must be BigInt — mixing is a TypeError).
    fn bigIntBinary(self: *Interpreter, op: ast.BinaryOp, l: Value, r: Value, l_big: bool, r_big: bool) EvalError!Value {
        if (!l_big or !r_big) return self.throwError("TypeError", "Cannot mix BigInt and other types, use explicit conversions");
        const a = l.asObj().bigint;
        const b = r.asObj().bigint;
        const res: i128 = switch (op) {
            .add => a +% b,
            .sub => a -% b,
            .mul => a *% b,
            .div => if (b == 0) return self.throwError("RangeError", "Division by zero") else @divTrunc(a, b),
            .mod => if (b == 0) return self.throwError("RangeError", "Division by zero") else @rem(a, b),
            .pow => blk: {
                if (b < 0) return self.throwError("RangeError", "Exponent must be non-negative");
                var acc: i128 = 1;
                var e = b;
                while (e > 0) : (e -= 1) acc *%= a;
                break :blk acc;
            },
            .bit_and => a & b,
            .bit_or => a | b,
            .bit_xor => a ^ b,
            .shl => if (b >= 128 or b <= -128) 0 else if (b >= 0) a << @intCast(b) else a >> @intCast(-b),
            .shr => if (b >= 128 or b <= -128) (if (a < 0) -1 else 0) else if (b >= 0) a >> @intCast(b) else a << @intCast(-b),
            else => 0,
        };
        return self.makeBigInt(res);
    }

    /// Mathematical comparison of two BigInt/Number operands (for `< <= > >=`),
    /// returning negative/zero/positive. (Lossy for BigInts beyond 2^53.)
    fn bigCmp(l: Value, r: Value) f64 {
        // BigInt vs BigInt: compare the i128 values exactly (an f64 round-trip
        // loses precision past 2^53, e.g. 9007199254740992000n vs ...991999n).
        const l_big = l.isObject() and l.asObj().is_bigint;
        const r_big = r.isObject() and r.asObj().is_bigint;
        if (l_big and r_big) {
            const a = l.asObj().bigint;
            const b = r.asObj().bigint;
            return if (a < b) -1 else if (a > b) 1 else 0;
        }
        const lf: f64 = if (l_big) @floatFromInt(l.asObj().bigint) else l.toNumber();
        const rf: f64 = if (r_big) @floatFromInt(r.asObj().bigint) else r.toNumber();
        return lf - rf;
    }

    /// `x instanceof C`: OrdinaryHasInstance walks the live prototype chain.
    /// Spec [[HasProperty]]: own property first, then prototype chain, invoking
    /// Proxy `has` traps at whichever object in the chain provides them.
    fn hasPropertyResult(self: *Interpreter, o: *value.Object, key: []const u8) EvalError!bool {
        // Integer-Indexed Exotic [[HasProperty]]: a canonical numeric key resolves
        // purely to index validity — it never consults the prototype chain.
        if (o.typed_array) |ta| {
            if (canonicalNumericIndexString(key)) |n| return isValidIntegerIndex(ta, n);
        }
        var cur: ?*value.Object = o;
        while (cur) |c| {
            if (c.proxy_handler != null or c.proxy_revoked) return self.proxyHas(c, key);
            if (moduleNsOf(c)) |ns| return moduleNsHas(ns, key);
            if (objectHasOwn(c, key)) return true;
            cur = self.effectiveProto(c);
        }
        return false;
    }

    pub fn inOperator(self: *Interpreter, l: Value, r: Value) EvalError!bool {
        if (r.isObject()) try self.checkRestricted(r.asObj());
        if (!r.isObject()) return self.throwError("TypeError", "cannot use 'in' on a non-object");
        const o = r.asObj();
        const key = try self.keyOf(l);
        if (try self.hasPropertyResult(o, key)) return true;
        // The global object carries the installed globals as properties.
        if (self.global_object != null and o == self.global_object.? and rootEnv(self.env).get(key) != null) return true;
        return false;
    }

    pub fn instanceOf(self: *Interpreter, l: Value, r: Value) EvalError!bool {
        if (!r.isObject() or !r.asObj().isCallableObject())
            return self.throwError("TypeError", "Right-hand side of 'instanceof' is not callable");
        return self.ordinaryHasInstance(r.asObj(), l);
    }

    /// OrdinaryHasInstance(C=`rc`, O=`l`): is `rc.prototype` in `l`'s prototype
    /// chain? Assumes `rc` is already known callable (false otherwise).
    /// An object's effective [[Prototype]]: its `proto`, or — for a callable
    /// (native/bound) function that was never given one — %Function.prototype%,
    /// which every function inherits.
    pub fn effectiveProto(self: *Interpreter, o: *value.Object) ?*value.Object {
        if (o.proto) |p| return p;
        if (o.native != null or o.js_func != null or o.bound != null) return self.functionProto();
        return null;
    }

    fn objectGetPrototypeValue(self: *Interpreter, o: *value.Object) EvalError!Value {
        if (o.proxy_handler != null or o.proxy_revoked) return self.proxyGetProto(o);
        return if (self.effectiveProto(o)) |p| Value.obj(p) else Value.nul();
    }

    pub fn ordinaryHasInstance(self: *Interpreter, rc: *value.Object, l: Value) EvalError!bool {
        if (!rc.isCallableObject()) return false;
        if (rc.bound) |erased| {
            const bf: *BoundFn = @ptrCast(@alignCast(erased));
            return self.instanceOf(l, bf.target);
        }
        if (!builtins.isRealObject(l)) return false;
        const lo = l.asObj();
        const p = try self.getProperty(Value.obj(rc), "prototype");
        if (!builtins.isRealObject(p)) return self.throwError("TypeError", "Function has non-object prototype in instanceof check");
        var cur = try self.objectGetPrototypeValue(lo);
        while (cur.isObject()) {
            if (cur.asObj() == p.asObj()) return true;
            cur = try self.objectGetPrototypeValue(cur.asObj());
        }
        if (rc.error_ctor) |name| {
            if (lo.is_error and (std.mem.eql(u8, lo.error_name, name) or std.mem.eql(u8, name, "Error")))
                return true;
        }
        return false;
    }
};

/// `Function.prototype[Symbol.hasInstance](O)` — OrdinaryHasInstance with the
/// bound function `this` as the constructor (false when `this` isn't callable).
fn functionHasInstanceFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject()) return Value.boolVal(false);
    return Value.boolVal(try self.ordinaryHasInstance(this.asObj(), if (args.len > 0) args[0] else Value.undef()));
}

/// The global `eval`. Direct eval runs in the caller's lexical environment;
/// member/indirect eval runs as global eval in the realm captured by the eval
/// function object.
fn evalFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (args.len == 0) return Value.undef();
    if (!args[0].isString()) return args[0]; // eval of a non-string is the identity
    const src = args[0].asStr();
    var parser = Parser.init(self.arena, src) catch return self.throwError("SyntaxError", "eval: invalid source");
    // Direct eval inherits the caller's strictness for early errors; indirect
    // eval is global code in the eval function's realm and only becomes strict
    // from its own directive prologue.
    if (self.direct_eval_call and self.strict) parser.strict = true;
    const prog = parser.parseProgram() catch return self.throwError("SyntaxError", "eval: parse error");

    const saved_env = self.env;
    const saved_this = self.this_value;
    const saved_glob = self.global_object;
    if (!self.direct_eval_call) {
        const fnobj = self.active_native orelse return Value.undef();
        const genv: *Environment = @ptrCast(@alignCast(fnobj.private_data orelse return Value.undef()));
        self.env = genv;
        if (genv.get("globalThis")) |gt| if (gt.isObject()) {
            self.this_value = Value.obj(gt.asObj());
            self.global_object = gt.asObj();
        };
    }

    const eval_env = try gc_mod.allocEnv(self.arena);
    // Eval's lexical environment holds the eval'd code's let/const/class. In
    // *sloppy* eval its top-level function/var declarations target the
    // surrounding variable scope (EvalDeclarationInstantiation) — `fn_body`
    // marks it as a function-top scope so those functions hoist var-scoped (to
    // the caller / realm global) and the Annex B B.3.3 analysis runs. *Strict*
    // eval has its OWN variable environment (declarations stay local), so it is
    // a real variable scope (`fn_scope`).
    self.initEnvironment(eval_env, self.env, parser.strict);
    eval_env.fn_body = !parser.strict;
    self.env = eval_env;
    // Non-strict eval's var/function declarations target the surrounding
    // variable scope and, when that is the global object, must be deletable.
    // (Strict eval keeps them local in `eval_env`, so the flag is moot there.)
    const saved_deletable = self.eval_decl_deletable;
    self.eval_decl_deletable = !parser.strict;
    defer {
        self.env = saved_env;
        self.this_value = saved_this;
        self.global_object = saved_glob;
        self.eval_decl_deletable = saved_deletable;
    }

    // Eval creates a fresh lexical environment for let/const/class declarations,
    // while var/function declarations target the surrounding variable
    // environment (the caller for direct eval, the realm global for indirect).
    if (prog.* == .program) try self.hoistVarNames(prog.program);
    return self.eval(prog);
}

fn promiseRejectAbrupt(self: *Interpreter, err: value.HostError) value.HostError!Value {
    if (err != error.Throw) return err;
    const reason = self.exception;
    self.exception = Value.undef();
    return promiseRejectValue(self, reason);
}

fn asyncFromSyncUnderlying(self: *Interpreter, this: Value) value.HostError!Value {
    if (!this.isObject()) return self.throwError("TypeError", "Async-from-Sync iterator method called on a non-object");
    return this.asObj().getOwn("__sync") orelse self.throwError("TypeError", "Async-from-Sync iterator missing underlying iterator");
}

fn asyncFromSyncContinuation(self: *Interpreter, sync_iter: Value, result: Value, close_on_rejection: bool) value.HostError!Value {
    if (!result.isObject())
        return promiseRejectValue(self, try self.makeError("TypeError", "iterator result is not an object"));
    const done = (self.getProperty(result, "done") catch |err| return promiseRejectAbrupt(self, err)).toBoolean();
    const value_v = self.getProperty(result, "value") catch |err| return promiseRejectAbrupt(self, err);
    const wrapped = promiseResolveValue(self, value_v) catch |err| {
        if (err != error.Throw) return err;
        const reason = self.exception;
        if (close_on_rejection and !done) {
            self.iteratorCloseKeepingThrow(sync_iter);
        }
        self.exception = Value.undef();
        return promiseRejectValue(self, reason);
    };
    const unwrapped = self.awaitValue(wrapped) catch |err| {
        if (err != error.Throw) return err;
        const reason = self.exception;
        if (close_on_rejection and !done) {
            self.iteratorCloseKeepingThrow(sync_iter);
        }
        self.exception = Value.undef();
        return promiseRejectValue(self, reason);
    };
    return promiseResolveValue(self, try self.iterResultObj(unwrapped, done));
}

fn asyncFromSyncNextFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const sync_iter = try asyncFromSyncUnderlying(self, this);
    const call_args = if (args.len > 0) args[0..1] else args[0..0];
    const result = self.callMethod(sync_iter, "next", call_args) catch |err| return promiseRejectAbrupt(self, err);
    return asyncFromSyncContinuation(self, sync_iter, result, true);
}

fn asyncFromSyncReturnFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const sync_iter = try asyncFromSyncUnderlying(self, this);
    const sent = if (args.len > 0) args[0] else Value.undef();
    const ret = self.getProperty(sync_iter, "return") catch |err| return promiseRejectAbrupt(self, err);
    if (ret.isUndefined() or ret.isNull()) {
        const resolved = self.awaitValue(sent) catch |err| return promiseRejectAbrupt(self, err);
        return promiseResolveValue(self, try self.iterResultObj(resolved, true));
    }
    if (!ret.isCallable()) return promiseRejectValue(self, try self.makeError("TypeError", "iterator return is not callable"));
    const call_args = if (args.len > 0) args[0..1] else args[0..0];
    const result = self.callValueWithThis(ret, call_args, sync_iter) catch |err| return promiseRejectAbrupt(self, err);
    return asyncFromSyncContinuation(self, sync_iter, result, false);
}

fn asyncFromSyncThrowFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const sync_iter = try asyncFromSyncUnderlying(self, this);
    const throw_m = self.getProperty(sync_iter, "throw") catch |err| return promiseRejectAbrupt(self, err);
    if (throw_m.isUndefined() or throw_m.isNull()) {
        self.iteratorClose(sync_iter) catch |err| return promiseRejectAbrupt(self, err);
        return promiseRejectValue(self, try self.makeError("TypeError", "iterator throw is not callable"));
    }
    if (!throw_m.isCallable()) return promiseRejectValue(self, try self.makeError("TypeError", "iterator throw is not callable"));
    const call_args = if (args.len > 0) args[0..1] else args[0..0];
    const result = self.callValueWithThis(throw_m, call_args, sync_iter) catch |err| return promiseRejectAbrupt(self, err);
    return asyncFromSyncContinuation(self, sync_iter, result, true);
}

// --- Promise built-ins ----------------------------------------------------

/// `new Promise(executor)` — create a pending promise and synchronously call
/// `executor(resolve, reject)`. The resolve/reject closures carry the promise
/// in their `private_data`; an executor that throws rejects the promise.
fn promiseConstructorFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    // `Promise(...)` without `new` is a TypeError (only [[Construct]] sets new.target).
    if (self.new_target.isUndefined()) return self.throwError("TypeError", "Promise constructor cannot be invoked without 'new'");
    const executor = if (args.len > 0) args[0] else Value.undef();
    if (!executor.isCallable()) return self.throwError("TypeError", "Promise resolver is not a function");
    const pobj = try promise.newPromise(self);
    if (self.new_target.isObject()) pobj.proto = try self.ctorRealmIntrinsicProto(self.new_target.asObj(), "Promise");
    const pp = pobj.promise.?;
    const resolving = try self.arena.create(promise.Resolving);
    resolving.* = .{ .promise = @ptrCast(@alignCast(pp)) };
    const res_fn = try gc_mod.allocObj(self.arena);
    res_fn.* = .{ .native = promiseResolveClosure, .private_data = @ptrCast(resolving) };
    const rej_fn = try gc_mod.allocObj(self.arena);
    rej_fn.* = .{ .native = promiseRejectClosure, .private_data = @ptrCast(resolving) };
    // The resolve/reject functions are anonymous, length 1 (spec).
    try installNativeProps(self.arena, self.root_shape, res_fn, "", 1);
    try installNativeProps(self.arena, self.root_shape, rej_fn, "", 1);
    if (self.callValueWithThis(executor, &.{ Value.obj(res_fn), Value.obj(rej_fn) }, Value.undef())) |_| {} else |err| {
        if (err == error.Throw) {
            const reason = self.exception;
            self.exception = Value.undef();
            if (!resolving.already) {
                resolving.already = true;
                try promise.reject(self, resolving.promise, reason);
            }
        } else return err;
    }
    return Value.obj(pobj);
}

fn promiseResolveClosure(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const fnobj = self.active_native orelse return Value.undef();
    const resolving: *promise.Resolving = @ptrCast(@alignCast(fnobj.private_data.?));
    if (resolving.already) return Value.undef();
    resolving.already = true;
    try promise.resolve(self, resolving.promise, if (args.len > 0) args[0] else Value.undef());
    return Value.undef();
}

fn promiseRejectClosure(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const fnobj = self.active_native orelse return Value.undef();
    const resolving: *promise.Resolving = @ptrCast(@alignCast(fnobj.private_data.?));
    if (resolving.already) return Value.undef();
    resolving.already = true;
    try promise.reject(self, resolving.promise, if (args.len > 0) args[0] else Value.undef());
    return Value.undef();
}

/// `Promise.prototype.then` — the result promise is built from
/// `SpeciesConstructor(this, %Promise%)`, so a subclass's `.then` yields a
/// subclass instance. The fast path (intrinsic species) skips the capability.
fn promiseThenImpl(self: *Interpreter, this: Value, on_f: Value, on_r: Value) value.HostError!Value {
    const p = promise.promiseOf(this) orelse return self.throwError("TypeError", "Promise.prototype.then called on a non-Promise");
    const default_ctor = self.env.get("Promise") orelse Value.undef();
    const c = try self.speciesConstructor(this, default_ctor);
    // Intrinsic Promise → cheap native capability; a subclass/custom → its own.
    if (c.isObject() and default_ctor.isObject() and c.asObj() == default_ctor.asObj())
        return promise.then(self, p, on_f, on_r);
    const cap = try newPromiseCapability(self, c);
    try promise.performThen(self, p, on_f, on_r, cap.resolve, cap.reject);
    return cap.promise;
}

/// A getter (or method) that simply returns its receiver — `get [@@species]() {
/// return this; }`.
fn returnThisFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = ctx;
    _ = args;
    return this;
}

fn promiseThenFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    return promiseThenImpl(self, this, if (args.len > 0) args[0] else Value.undef(), if (args.len > 1) args[1] else Value.undef());
}

fn promiseCatchFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    // `catch(f)` is `? Invoke(this, "then", «undefined, f»)` — a generic call to
    // this value's own `then`, so it works on any thenable, not just a Promise.
    return self.callMethod(this, "then", &.{ Value.undef(), if (args.len > 0) args[0] else Value.undef() });
}

/// Captured state for a `finally` reaction (`then`/`catch` side) and its inner
/// value-restoring thunk.
const FinallyData = struct { on_finally: Value, ctor: Value = Value.undef(), captured: Value = Value.undef(), is_catch: bool };

/// `thenFinally`/`catchFinally`: run `onFinally()`, then — once its result
/// settles — re-yield the original value (or re-throw the original reason),
/// so `finally` is transparent to the settled completion.
fn finallyReactionFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const fnobj = self.active_native orelse return Value.undef();
    const d: *FinallyData = @ptrCast(@alignCast(fnobj.private_data.?));
    const incoming = if (args.len > 0) args[0] else Value.undef();
    const result = try self.callValue(d.on_finally, &.{}); // may throw → propagates (rejects)
    const wrapped = try promiseResolveForConstructor(self, d.ctor, result);
    // After onFinally's result settles, a thunk that ignores its argument and
    // reinstates the original completion.
    const thunk = try gc_mod.allocObj(self.arena);
    const td = try self.arena.create(FinallyData);
    td.* = .{ .on_finally = Value.undef(), .captured = incoming, .is_catch = d.is_catch };
    thunk.* = .{ .native = finallyThunkFn, .private_data = @ptrCast(td) };
    try installNativeProps(self.arena, self.root_shape, thunk, "", 0);
    return self.callMethod(wrapped, "then", &.{Value.obj(thunk)});
}

fn finallyThunkFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const fnobj = self.active_native orelse return Value.undef();
    const d: *FinallyData = @ptrCast(@alignCast(fnobj.private_data.?));
    if (d.is_catch) {
        self.exception = d.captured; // re-throw the original rejection reason
        return error.Throw;
    }
    return d.captured; // re-yield the original fulfillment value
}

fn promiseFinallyFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    // `finally` requires an Object `this` (not necessarily a Promise) and ends in
    // `Invoke(this, "then", …)`, so it composes over any thenable.
    if (!this.isObject()) return self.throwError("TypeError", "Promise.prototype.finally called on a non-object");
    const default_ctor = self.env.get("Promise") orelse Value.undef();
    const c = try self.speciesConstructor(this, default_ctor);
    const cb = if (args.len > 0) args[0] else Value.undef();
    // A non-callable `onFinally` is used directly for both reactions (spec).
    if (!cb.isCallable()) return self.callMethod(this, "then", &.{ cb, cb });
    const onf = try gc_mod.allocObj(self.arena);
    const ond = try self.arena.create(FinallyData);
    ond.* = .{ .on_finally = cb, .ctor = c, .is_catch = false };
    onf.* = .{ .native = finallyReactionFn, .private_data = @ptrCast(ond) };
    try installNativeProps(self.arena, self.root_shape, onf, "", 1);
    const onr = try gc_mod.allocObj(self.arena);
    const ord = try self.arena.create(FinallyData);
    ord.* = .{ .on_finally = cb, .ctor = c, .is_catch = true };
    onr.* = .{ .native = finallyReactionFn, .private_data = @ptrCast(ord) };
    try installNativeProps(self.arena, self.root_shape, onr, "", 1);
    return self.callMethod(this, "then", &.{ Value.obj(onf), Value.obj(onr) });
}

fn promiseResolveForConstructor(self: *Interpreter, c: Value, v: Value) EvalError!Value {
    if (promise.promiseOf(v) != null) {
        const ctor = try self.getProperty(v, "constructor");
        if (ctor.isObject() and c.isObject() and ctor.asObj() == c.asObj()) return v;
    }
    const cap = try newPromiseCapability(self, c);
    _ = try self.callValue(cap.resolve, &.{v});
    return cap.promise;
}

/// Internal `PromiseResolve(%Promise%, v)`: `v` itself only when it is a native
/// promise whose observable `constructor` is the intrinsic Promise, else a fresh
/// native promise fulfilled with `v` (adopting a thenable).
pub fn promiseResolveValue(self: *Interpreter, v: Value) EvalError!Value {
    if (promise.promiseOf(v) != null) {
        if (self.env.get("Promise")) |pc| if (pc.isObject()) {
            const ctor = try self.getProperty(v, "constructor");
            if (ctor.isObject() and ctor.asObj() == pc.asObj()) return v;
        };
    }
    const pobj = try promise.newPromise(self);
    try promise.resolve(self, @ptrCast(@alignCast(pobj.promise.?)), v);
    return Value.obj(pobj);
}

fn promiseResolveAfterTick(self: *Interpreter, v: Value) EvalError!Value {
    const result = try promise.newPromise(self);
    const rp: *promise.Promise = @ptrCast(@alignCast(result.promise.?));
    const tick = try promise.newPromise(self);
    const tp: *promise.Promise = @ptrCast(@alignCast(tick.promise.?));
    const nr = try promise.nativeResolveReject(self, rp);
    try promise.performThen(self, tp, Value.undef(), Value.undef(), nr.resolve, nr.reject);
    try promise.resolve(self, tp, v);
    return Value.obj(result);
}

/// A fresh promise already rejected with `reason`.
fn promiseRejectValue(self: *Interpreter, reason: Value) EvalError!Value {
    const pobj = try promise.newPromise(self);
    try promise.reject(self, @ptrCast(@alignCast(pobj.promise.?)), reason);
    return Value.obj(pobj);
}

/// `Promise.resolve(v)` — uses `this` as the constructor `C`: returns `v`
/// unchanged when it is a promise whose `constructor` is `C`, otherwise builds
/// `C`'s capability and resolves it with `v` (so a subclass's `resolve` yields a
/// subclass instance).
fn promiseResolveStaticFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject() or this.asObj().is_symbol or this.asObj().is_bigint)
        return self.throwError("TypeError", "Promise.resolve called on a non-object");
    const v = if (args.len > 0) args[0] else Value.undef();
    return promiseResolveForConstructor(self, this, v);
}

/// `Promise.reject(e)` — builds `this`'s capability and rejects it with `e`.
fn promiseRejectStaticFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const cap = try newPromiseCapability(self, this);
    _ = try self.callValue(cap.reject, &.{if (args.len > 0) args[0] else Value.undef()});
    return cap.promise;
}

/// `Object.groupBy(items, callback)` — group `items` into a null-prototype
/// object keyed by `callback(value, index)` (coerced to a property key), each
/// bucket an array of the values in iteration order.
fn objectGroupByFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const cb = if (args.len > 1) args[1] else Value.undef();
    if (!cb.isCallable()) return self.throwError("TypeError", "Object.groupBy: callback is not a function");
    const elems = try collectIterable(self, if (args.len > 0) args[0] else Value.undef());
    const obj = (try self.newObject()).asObj();
    obj.proto = null; // groupBy result has a null prototype
    for (elems, 0..) |el, i| {
        const kv = try self.callValue(cb, &.{ el, Value.num(@floatFromInt(i)) });
        const key = try self.keyOf(kv);
        if (obj.getOwn(key)) |bucket| {
            try bucket.asObj().elements.append(bucket.asObj().elementsAllocator(self.arena), el);
        } else {
            const arr = try self.newArray();
            try arr.asObj().elements.append(arr.asObj().elementsAllocator(self.arena), el);
            try self.setProp(obj, key, arr);
        }
    }
    return Value.obj(obj);
}

/// `Map.groupBy(items, callback)` — like Object.groupBy but the result is a Map
/// keyed by the (SameValueZero) callback result, each value an array.
fn mapGroupByFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const cb = if (args.len > 1) args[1] else Value.undef();
    if (!cb.isCallable()) return self.throwError("TypeError", "Map.groupBy: callback is not a function");
    const elems = try collectIterable(self, if (args.len > 0) args[0] else Value.undef());
    const map = (try self.makeMap(Value.undef())).asObj();
    for (elems, 0..) |el, i| {
        const key = try self.callValue(cb, &.{ el, Value.num(@floatFromInt(i)) });
        if ((try self.mapMethod(map, "has", &.{key})).?.asBool()) {
            const bucket = (try self.mapMethod(map, "get", &.{key})).?;
            try bucket.asObj().elements.append(bucket.asObj().elementsAllocator(self.arena), el);
        } else {
            const arr = try self.newArray();
            try arr.asObj().elements.append(arr.asObj().elementsAllocator(self.arena), el);
            _ = try self.mapMethod(map, "set", &.{ key, arr });
        }
    }
    return Value.obj(map);
}

/// Collect an iterable's elements into a slice: arrays use their dense store
/// directly; anything else is driven through the iterator protocol.
fn collectIterable(self: *Interpreter, v: Value) EvalError![]Value {
    if (v.isObject() and v.asObj().is_array) return v.asObj().elements.items;
    const iter = try self.iteratorOf(v);
    var list: std.ArrayListUnmanaged(Value) = .empty;
    while (true) {
        const r = try self.callMethod(iter, "next", &.{});
        if (!r.isObject()) return self.throwError("TypeError", "iterator.next() did not return an object");
        if ((try self.getProperty(r, "done")).toBoolean()) break;
        try list.append(self.arena, try self.getProperty(r, "value"));
    }
    return list.items;
}

/// One element's settle reaction for `Promise.all`/`allSettled`/`any`: record
/// the outcome at its index and, when the last input settles, settle the
/// combined promise.
fn combineElemFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const fnobj = self.active_native orelse return Value.undef();
    const e: *promise.Elem = @ptrCast(@alignCast(fnobj.private_data.?));
    // [[AlreadyCalled]]: a resolve/reject element function settles its element at
    // most once; subsequent calls are no-ops.
    if (e.already.*) return Value.undef();
    e.already.* = true;
    const c = e.combine;
    const val = if (args.len > 0) args[0] else Value.undef();
    switch (c.kind) {
        .all => {
            if (e.is_reject) {
                _ = try self.callValue(c.reject, &.{val}); // first rejection wins
                return Value.undef();
            }
            c.values.elements.items[e.index] = val;
        },
        .all_settled => {
            const o = (try self.newObject()).asObj();
            if (e.is_reject) {
                try self.setProp(o, "status", Value.str("rejected"));
                try self.setProp(o, "reason", val);
            } else {
                try self.setProp(o, "status", Value.str("fulfilled"));
                try self.setProp(o, "value", val);
            }
            c.values.elements.items[e.index] = Value.obj(o);
        },
        .all_keyed => {
            if (e.is_reject) {
                _ = try self.callValue(c.reject, &.{val}); // first rejection wins
                return Value.undef();
            }
            c.values.elements.items[e.index] = val;
        },
        .all_settled_keyed => {
            const o = (try self.newObject()).asObj();
            if (e.is_reject) {
                try self.setProp(o, "status", Value.str("rejected"));
                try self.setProp(o, "reason", val);
            } else {
                try self.setProp(o, "status", Value.str("fulfilled"));
                try self.setProp(o, "value", val);
            }
            c.values.elements.items[e.index] = Value.obj(o);
        },
        .any => {
            if (!e.is_reject) {
                _ = try self.callValue(c.resolve, &.{val}); // first fulfillment wins
                return Value.undef();
            }
            c.values.elements.items[e.index] = val; // collect the error
        },
    }
    c.remaining -= 1;
    if (c.remaining == 0) try combineSettle(self, c);
    return Value.undef();
}

/// Settle a combinator once its `remaining` count reaches zero: `all`/
/// `allSettled` fulfill with the values array; `any` rejects with an
/// AggregateError carrying the collected rejection reasons.
fn combineSettle(self: *Interpreter, c: *promise.Combine) value.HostError!void {
    if (c.kind == .any) {
        const agg = try self.makeErrorWithArgs("AggregateError", &.{Value.obj(c.values)});
        _ = try self.callValue(c.reject, &.{agg});
    } else if (c.keys) |keys| {
        const result = (try self.newObject()).asObj();
        result.proto = null;
        for (keys, 0..) |key, i| {
            try self.setProp(result, key, c.values.elements.items[i]);
        }
        try callCapabilityResolve(self, c, Value.obj(result));
    } else try callCapabilityResolve(self, c, Value.obj(c.values));
}

fn callCapabilityResolve(self: *Interpreter, c: *promise.Combine, value_arg: Value) value.HostError!void {
    if (self.callValue(c.resolve, &.{value_arg})) |_| return else |err| {
        if (err != error.Throw) return err;
        const reason = self.exception;
        self.exception = Value.undef();
        _ = try self.callValue(c.reject, &.{reason});
    }
}

inline fn tracePrivateValue(v: anytype, val: Value) void {
    if (val.isObject()) v.mark(val.asObj());
}

/// Trace engine-owned `private_data` carried by native closures allocated in
/// this file. The Object tracer already marks the closure object itself; this
/// hook keeps type-erased side records from hiding GC-managed Values/Objects.
pub fn traceNativePrivateData(o: *value.Object, v: anytype) void {
    const nf = o.native orelse return;
    const pd = o.private_data orelse return;

    if (nf == promiseResolveClosure or nf == promiseRejectClosure) {
        const data: *promise.Resolving = @ptrCast(@alignCast(pd));
        v.mark(data.promise);
        return;
    }

    if (nf == finallyReactionFn or nf == finallyThunkFn) {
        const data: *FinallyData = @ptrCast(@alignCast(pd));
        tracePrivateValue(v, data.on_finally);
        tracePrivateValue(v, data.captured);
        return;
    }

    if (nf == combineElemFn) {
        const elem: *promise.Elem = @ptrCast(@alignCast(pd));
        const c = elem.combine;
        tracePrivateValue(v, c.resolve);
        tracePrivateValue(v, c.reject);
        v.mark(c.values);
        return;
    }

    if (nf == capabilityExecutorFn) {
        const cap: *CapCapture = @ptrCast(@alignCast(pd));
        tracePrivateValue(v, cap.resolve);
        tracePrivateValue(v, cap.reject);
    }
}

/// IteratorStep + IteratorValue: advance `iter`, returning the next value or
/// null when exhausted. A protocol violation (non-object result) throws.
fn iterStep(self: *Interpreter, iter: Value) EvalError!?Value {
    const r = try self.callMethod(iter, "next", &.{});
    if (!r.isObject()) return self.throwError("TypeError", "iterator.next() did not return an object");
    if ((try self.getProperty(r, "done")).toBoolean()) return null;
    return try self.getProperty(r, "value");
}

/// Shared setup for `Promise.all`/`allSettled`/`any`: build the combined promise
/// and wire a per-element reaction onto each input (coerced via the source's
/// `then`). An empty input settles immediately.
/// A `PromiseCapability` record: the constructed promise plus the resolve/reject
/// functions its executor handed out. Settling the combined promise goes through
/// these functions, so a subclass constructor's promise is the actual result.
const Capability = struct { promise: Value, resolve: Value, reject: Value };

/// Captures the (resolve, reject) pair the executor is invoked with.
const CapCapture = struct { resolve: Value = Value.undef(), reject: Value = Value.undef() };

fn capabilityExecutorFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const fnobj = self.active_native orelse return Value.undef();
    const cap: *CapCapture = @ptrCast(@alignCast(fnobj.private_data.?));
    // GetCapabilitiesExecutor: the executor may be invoked only once — if
    // [[Resolve]] or [[Reject]] is already set, a second call throws.
    if (!cap.resolve.isUndefined() or !cap.reject.isUndefined())
        return self.throwError("TypeError", "Promise capability executor already invoked");
    cap.resolve = if (args.len > 0) args[0] else Value.undef();
    cap.reject = if (args.len > 1) args[1] else Value.undef();
    return Value.undef();
}

/// `NewPromiseCapability(C)`: construct `new C(executor)`, capturing the resolve
/// and reject functions. Both must be callable. Works for the native `Promise`
/// and for any subclass/custom constructor that forwards to a Promise executor.
/// `Promise.withResolvers()` — `{ promise, resolve, reject }` built from a fresh
/// capability of `this` constructor (so a subclass's promise/functions are used).
fn promiseWithResolversFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const cap = try newPromiseCapability(self, this);
    const obj = (try self.newObject()).asObj();
    try self.setProp(obj, "promise", cap.promise);
    try self.setProp(obj, "resolve", cap.resolve);
    try self.setProp(obj, "reject", cap.reject);
    return Value.obj(obj);
}

/// `Promise.try(callback, ...args)` — run `callback(...args)` now, settling a
/// fresh capability of `this` constructor with its result or thrown reason.
fn promiseTryFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const cap = try newPromiseCapability(self, this);
    const cb = if (args.len > 0) args[0] else Value.undef();
    const extra = if (args.len > 1) args[1..] else &[_]Value{};
    const result = self.callValue(cb, extra) catch |e| {
        if (e != error.Throw) return e;
        _ = try self.callValue(cap.reject, &.{self.exception});
        return cap.promise;
    };
    _ = try self.callValue(cap.resolve, &.{result});
    return cap.promise;
}

fn newPromiseCapability(self: *Interpreter, c: Value) EvalError!Capability {
    if (!isConstructorValue(c)) return self.throwError("TypeError", "NewPromiseCapability called on a non-constructor");
    const capture = try self.arena.create(CapCapture);
    capture.* = .{};
    const executor = try gc_mod.allocObj(self.arena);
    executor.* = .{ .native = capabilityExecutorFn, .private_data = @ptrCast(capture) };
    try installNativeProps(self.arena, self.root_shape, executor, "", 2);
    const p = try self.construct(c, &.{Value.obj(executor)});
    if (!capture.resolve.isCallable() or !capture.reject.isCallable())
        return self.throwError("TypeError", "Promise capability resolve/reject is not callable");
    return .{ .promise = p, .resolve = capture.resolve, .reject = capture.reject };
}

/// `GetPromiseResolve(C)` — `Get(C, "resolve")`, which must be callable. The
/// combinators call this once per element (observably, so a replaced
/// `Promise.resolve` is honored), passing `C` as the receiver.
fn getPromiseResolve(self: *Interpreter, c: Value) EvalError!Value {
    const r = try self.getProperty(c, "resolve");
    if (!r.isCallable()) return self.throwError("TypeError", "Promise resolve is not a function");
    return r;
}

/// Resolve one combinator element through the constructor's `resolve` (spec:
/// `Call(promiseResolve, C, « nextValue »)`), yielding a promise to attach to.
fn elementPromise(self: *Interpreter, promise_resolve: Value, c: Value, el: Value) EvalError!*promise.Promise {
    const p = try self.callValueWithThis(promise_resolve, &.{el}, c);
    if (promise.promiseOf(p)) |pp| return pp;
    // A non-promise `resolve` result is adopted into a fresh native promise.
    const wrapped = try promiseResolveValue(self, p);
    return promise.promiseOf(wrapped).?;
}

fn setupCombinator(self: *Interpreter, this: Value, iterable: Value, kind: @TypeOf(@as(promise.Combine, undefined).kind)) value.HostError!Value {
    // NewPromiseCapability(C): C (the `this` value) must be a constructor. This
    // throws synchronously (it is before the IfAbruptRejectPromise region).
    const cap = try newPromiseCapability(self, this);
    // GetPromiseResolve + GetIterator are abrupt-rejected: a failure rejects the
    // returned promise (IfAbruptRejectPromise) rather than throwing out of the call.
    const promise_resolve = getPromiseResolve(self, this) catch |err| return rejectAbrupt(self, cap, err);
    const iter = self.iteratorOf(iterable) catch |err| return rejectAbrupt(self, cap, err);

    const values = (try self.newArray()).asObj();
    const combine = try self.arena.create(promise.Combine);
    // `remaining` starts at 1 for the loop itself, so a synchronously-settling
    // input can't fire the final settle before the iteration completes; it is
    // decremented once the iterator is exhausted (PerformPromiseAll pattern).
    combine.* = .{ .resolve = cap.resolve, .reject = cap.reject, .values = values, .remaining = 1, .kind = kind };
    var index: usize = 0;
    while (true) {
        // IteratorStep/IteratorValue errors leave the iterator done → reject
        // without closing it.
        const maybe = iterStep(self, iter) catch |err| return rejectAbrupt(self, cap, err);
        const el = maybe orelse break;
        try values.elements.append(values.elementsAllocator(self.arena), Value.undef());
        combine.remaining += 1;
        // `nextPromise = Call(promiseResolve, C, «el»)` — an abrupt completion
        // here closes the (still-open) iterator before rejecting.
        const next = self.callValueWithThis(promise_resolve, &.{el}, this) catch |err| return closeAndReject(self, cap, iter, err);
        // One [[AlreadyCalled]] record shared by this element's resolve & reject
        // functions — the element settles at most once.
        const already = try self.arena.create(bool);
        already.* = false;
        const f = try gc_mod.allocObj(self.arena);
        const fe = try self.arena.create(promise.Elem);
        fe.* = .{ .combine = combine, .index = index, .is_reject = false, .already = already };
        f.* = .{ .native = combineElemFn, .private_data = @ptrCast(fe) };
        try installNativeProps(self.arena, self.root_shape, f, "", 1); // anonymous, length 1
        const r = try gc_mod.allocObj(self.arena);
        const re = try self.arena.create(promise.Elem);
        re.* = .{ .combine = combine, .index = index, .is_reject = true, .already = already };
        r.* = .{ .native = combineElemFn, .private_data = @ptrCast(re) };
        try installNativeProps(self.arena, self.root_shape, r, "", 1);
        // Invoke(nextPromise, "then", «resolveElement, rejectElement»): for a
        // native promise this is the native `then`; for a thenable it runs its
        // own `then` (which may settle synchronously).
        const fulfill_element = if (kind == .any) cap.resolve else Value.obj(f);
        const reject_element = if (kind == .all) cap.reject else Value.obj(r);
        _ = self.callMethod(next, "then", &.{ fulfill_element, reject_element }) catch |err| return closeAndReject(self, cap, iter, err);
        index += 1;
    }
    combine.remaining -= 1; // the loop's own count
    if (combine.remaining == 0) try combineSettle(self, combine);
    return cap.promise;
}

fn addCombineElement(
    self: *Interpreter,
    cap: Capability,
    combine: *promise.Combine,
    promise_resolve: Value,
    c: Value,
    next_value: Value,
    index: usize,
) value.HostError!bool {
    try combine.values.appendElement(self.arena, Value.undef());
    combine.remaining += 1;
    const next = self.callValueWithThis(promise_resolve, &.{next_value}, c) catch |err| {
        _ = try rejectAbrupt(self, cap, err);
        return false;
    };
    const already = try self.arena.create(bool);
    already.* = false;
    const f = try gc_mod.allocObj(self.arena);
    const fe = try self.arena.create(promise.Elem);
    fe.* = .{ .combine = combine, .index = index, .is_reject = false, .already = already };
    f.* = .{ .native = combineElemFn, .private_data = @ptrCast(fe) };
    try installNativeProps(self.arena, self.root_shape, f, "", 1);
    const r = try gc_mod.allocObj(self.arena);
    const re = try self.arena.create(promise.Elem);
    re.* = .{ .combine = combine, .index = index, .is_reject = true, .already = already };
    r.* = .{ .native = combineElemFn, .private_data = @ptrCast(re) };
    try installNativeProps(self.arena, self.root_shape, r, "", 1);
    const reject_element = if (combine.kind == .all_keyed) cap.reject else Value.obj(r);
    _ = self.callMethod(next, "then", &.{ Value.obj(f), reject_element }) catch |err| {
        _ = try rejectAbrupt(self, cap, err);
        return false;
    };
    return true;
}

fn setupKeyedCombinator(self: *Interpreter, this: Value, promises: Value, kind: @TypeOf(@as(promise.Combine, undefined).kind)) value.HostError!Value {
    const cap = try newPromiseCapability(self, this);
    const promise_resolve = getPromiseResolve(self, this) catch |err| return rejectAbrupt(self, cap, err);
    if (!promises.isObject() or promises.asObj().is_symbol or promises.asObj().is_bigint) {
        _ = try self.callValue(cap.reject, &.{try self.makeError("TypeError", "Promise keyed combinator argument is not an object")});
        return cap.promise;
    }
    const source = promises.asObj();
    const all_keys = self.objectOwnKeysList(source) catch |err| return rejectAbrupt(self, cap, err);
    var kept_keys: std.ArrayListUnmanaged([]const u8) = .empty;
    const values = (try self.newArray()).asObj();
    const combine = try self.arena.create(promise.Combine);
    combine.* = .{ .resolve = cap.resolve, .reject = cap.reject, .values = values, .remaining = 1, .kind = kind };
    for (all_keys) |key| {
        const desc = builtins.objectGetOwnPropertyDescriptor(@ptrCast(self), Value.undef(), &.{ Value.obj(source), self.keyToValue(key) }) catch |err| return rejectAbrupt(self, cap, err);
        if (desc.isUndefined()) continue;
        const enumerable = self.getProperty(desc, "enumerable") catch |err| return rejectAbrupt(self, cap, err);
        if (!enumerable.toBoolean()) continue;
        try kept_keys.append(self.arena, key);
        const next_value = self.getProperty(promises, key) catch |err| return rejectAbrupt(self, cap, err);
        if (!try addCombineElement(self, cap, combine, promise_resolve, this, next_value, kept_keys.items.len - 1))
            return cap.promise;
    }
    combine.keys = kept_keys.items;
    combine.remaining -= 1;
    if (combine.remaining == 0) try combineSettle(self, combine);
    return cap.promise;
}

/// IfAbruptRejectPromise: a thrown completion rejects the capability and returns
/// its promise; any non-throw (host) error propagates unchanged.
fn rejectAbrupt(self: *Interpreter, cap: Capability, err: value.HostError) value.HostError!Value {
    if (err != error.Throw) return err;
    const reason = self.exception;
    self.exception = Value.undef();
    _ = try self.callValue(cap.reject, &.{reason});
    return cap.promise;
}

/// Abrupt completion mid-iteration: close the still-open iterator (its own
/// errors are swallowed — the original completion wins) and reject the result.
fn closeAndReject(self: *Interpreter, cap: Capability, iter: Value, err: value.HostError) value.HostError!Value {
    if (err != error.Throw) return err;
    const reason = self.exception;
    self.exception = Value.undef();
    self.iteratorClose(iter) catch {};
    self.exception = Value.undef();
    _ = try self.callValue(cap.reject, &.{reason});
    return cap.promise;
}

fn promiseAllFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    return setupCombinator(self, this, if (args.len > 0) args[0] else Value.undef(), .all);
}

fn promiseAllSettledFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    return setupCombinator(self, this, if (args.len > 0) args[0] else Value.undef(), .all_settled);
}

fn promiseAllKeyedFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    return setupKeyedCombinator(self, this, if (args.len > 0) args[0] else Value.undef(), .all_keyed);
}

fn promiseAllSettledKeyedFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    return setupKeyedCombinator(self, this, if (args.len > 0) args[0] else Value.undef(), .all_settled_keyed);
}

fn promiseAnyFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    return setupCombinator(self, this, if (args.len > 0) args[0] else Value.undef(), .any);
}

/// `Promise.race(iterable)` — settle with the first input to settle.
fn promiseRaceFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const cap = try newPromiseCapability(self, this);
    const promise_resolve = getPromiseResolve(self, this) catch |err| return rejectAbrupt(self, cap, err);
    const iter = self.iteratorOf(if (args.len > 0) args[0] else Value.undef()) catch |err| return rejectAbrupt(self, cap, err);
    while (true) {
        const maybe = iterStep(self, iter) catch |err| return rejectAbrupt(self, cap, err);
        const el = maybe orelse break;
        const next = self.callValueWithThis(promise_resolve, &.{el}, this) catch |err| return closeAndReject(self, cap, iter, err);
        // The capability's resolve/reject settle the result; the first input to
        // fire wins (later settlements are no-ops on an already-settled promise).
        _ = self.callMethod(next, "then", &.{ cap.resolve, cap.reject }) catch |err| return closeAndReject(self, cap, iter, err);
    }
    return cap.promise;
}

/// `print(...)` — appends a space-joined line to the Context's print buffer
/// (used by the test262 async harness's `$DONE`).
fn printFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const buf = self.print_buffer orelse return Value.undef();
    for (args, 0..) |a, i| {
        if (i != 0) try buf.append(self.arena, ' ');
        try buf.appendSlice(self.arena, try a.toString(self.arena));
    }
    try buf.append(self.arena, '\n');
    return Value.undef();
}

/// Test-shell compatibility: JSC's `noInline(fn)` affects tiering only. This
/// engine's tiering is not JIT-driven, so the observable behavior is identity.
fn noInlineFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = ctx;
    _ = this;
    return if (args.len > 0) args[0] else Value.undef();
}

/// Test-shell compatibility for PR-249 object-model/GC stress files. The M1
/// collector is precise and only sound at quiescent points, so in GC-enabled
/// contexts this requests collection for the next safe entry instead of tracing
/// while live JS values still sit in Zig locals/registers.
fn gcFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (self.gc != null) {
        if (self.gc_requested) |requested| requested.* = true;
    }
    return Value.undef();
}

fn quitFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    self.exception = Value.str("__zigjs_threads_quit__");
    return error.Throw;
}

fn vmUseThreadGILFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    return Value.boolVal(self.gil != null and self.use_thread_gil);
}

fn vmIndexingModeFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = ctx;
    _ = this;
    const v = if (args.len > 0) args[0] else Value.undef();
    if (v.isObject() and v.asObj().is_array) {
        if (v.asObj().forced_array_storage) return Value.str("Array ArrayStorage");
        return Value.str("Array CopyOnWrite");
    }
    if (v.isObject()) {
        if (v.asObj().typed_array) |ta| return Value.str(ta.kind.ctorName());
    }
    return Value.str("Object");
}

fn vmEnsureArrayStorageFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const v = if (args.len > 0) args[0] else Value.undef();
    if (!v.isObject() or !v.asObj().is_array)
        return self.throwError("TypeError", "$vm.ensureArrayStorage expects an Array");
    v.asObj().forced_array_storage = true;
    return v;
}

fn installDollarVM(env: *Environment, rs: *Shape, object_proto: *value.Object) EvalError!void {
    const a = env.arena;
    const vm_obj = try gc_mod.allocObj(a);
    vm_obj.* = .{ .proto = object_proto };
    try setNative(a, rs, vm_obj, "gc", 0, gcFn);
    try setNative(a, rs, vm_obj, "edenGC", 0, gcFn);
    try setNative(a, rs, vm_obj, "ensureArrayStorage", 1, vmEnsureArrayStorageFn);
    try setNative(a, rs, vm_obj, "indexingMode", 1, vmIndexingModeFn);
    try setNative(a, rs, vm_obj, "noInline", 1, noInlineFn);
    try setNative(a, rs, vm_obj, "useThreadGIL", 0, vmUseThreadGILFn);
    try env.put("$vm", Value.obj(vm_obj));
}

/// Host timer used by test262's Atomics helper. This intentionally blocks the
/// current agent for the delay, services finite waitAsync tickets, then queues
/// the callback; the engine has no browser event loop yet.
fn setTimeoutFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const cb = if (args.len > 0) args[0] else Value.undef();
    if (!cb.isCallable()) return Value.num(0);
    const ms = if (args.len > 1) try self.toNumberV(args[1]) else 0;
    if (!std.math.isNan(ms) and ms > 0) agent.sleepMs(ms);
    if (self.async_waiters) |waiters| {
        if (waiters.items.len > 0) self.settleAsyncWaiters();
    }
    const tick = try promise.newPromise(self);
    const pp: *promise.Promise = @ptrCast(@alignCast(tick.promise.?));
    try promise.resolve(self, pp, Value.undef());
    _ = try promise.then(self, pp, cb, Value.undef());
    return Value.num(0);
}

/// Test-shell helper used by the PR-249 corpus. This is a microtask checkpoint
/// only: threaded run-loop tasks such as `Lock.asyncHold` grants are still
/// delivered by the evaluate tail / park pump, not by this hook.
fn drainMicrotasksFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    try self.drainMicrotasks();
    return Value.undef();
}

/// Internal shell run-loop tick used by `conformance/threads_test.zig` while it
/// waits for `asyncTestPassed()` counters. Kept separate from drainMicrotasks()
/// because corpus tests assert that async lock grants do not settle merely by
/// draining the Promise queue inside the same script turn.
fn drainRunLoopFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    var rounds: usize = 0;
    while (rounds < 8) : (rounds += 1) {
        const before = if (self.microtasks) |q| q.items.len else 0;
        jsthread.pumpTasks(self);
        jsthread.pollPropAsync(self);
        try self.drainMicrotasks();
        try self.drainFinalizationCleanupJobs();
        try self.drainMicrotasks();
        const after = if (self.microtasks) |q| q.items.len else 0;
        if (before == 0 and after == 0) break;
    }
    return Value.undef();
}

/// `Object.prototype.toString` → `"[object Tag]"`. The tag comes from the
/// object's kind (Array/Function/Error/Date/RegExp/Boolean/Number/String, else
/// "Object"), but an own/inherited `Symbol.toStringTag` *string* overrides it
/// (per spec). Distinct from the kind-specific `toString`s (e.g.
/// `[1,2].toString()` still joins) — this is the one on `Object.prototype`.
/// `Object.prototype.toLocaleString()` — by default just invokes `this.toString()`.
fn objectProtoToLocaleStringFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    return self.callMethod(this, "toString", &.{});
}

/// Getter for `Object.prototype.__proto__` — `[[GetPrototypeOf]]` of ToObject(this).
fn protoGetterFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const o = try self.toObject(this);
    if (o.proxy_handler != null or o.proxy_revoked) return self.proxyGetProto(o);
    if (self.effectiveProto(o)) |p| return Value.obj(p);
    return Value.nul();
}

/// Setter for `Object.prototype.__proto__` — sets the prototype to an object or
/// null; any other value is silently ignored (per spec).
fn protoSetterFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    // RequireObjectCoercible(this).
    if (this.isUndefined() or this.isNull())
        return self.throwError("TypeError", "Object.prototype.__proto__ setter called on null or undefined");
    const v = if (args.len > 0) args[0] else Value.undef();
    // Only an Object or null is a candidate prototype; anything else is a no-op.
    if (!v.isNull() and !builtins.isRealObject(v)) return Value.undef();
    if (!this.isObject()) return Value.undef(); // a primitive `this` has no own [[Prototype]]
    const o = this.asObj();
    const new_proto: ?*value.Object = if (v.isObject()) v.asObj() else null;
    // OrdinarySetPrototypeOf rejects setting the prototype of a non-extensible
    // object, or any change that would form a [[Prototype]] cycle. The
    // `__proto__` setter turns that false result into a TypeError.
    if (!try self.setPrototypeOfObject(o, new_proto))
        return self.throwError("TypeError", "Cannot set object prototype");
    return Value.undef();
}

fn objectProtoToStringFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const tag_obj: ?*value.Object = switch (this.kind()) {
        .undefined => return Value.str("[object Undefined]"),
        .null => return Value.str("[object Null]"),
        .object => this.asObj(),
        else => try self.toObject(this),
    };
    const builtin_tag: []const u8 = switch (this.kind()) {
        .number => "Number",
        .boolean => "Boolean",
        .string => "String",
        .object => blk: {
            const o = this.asObj();
            break :blk if (o.is_arguments) "Arguments" else if (try objectToStringIsArray(self, o)) "Array" else if (o.is_error) "Error" else if (o.is_date) "Date" else if (o.is_regex) "RegExp" else if (o.prim) |p| (switch (p.kind()) {
                .number => "Number",
                .string => "String",
                .boolean => "Boolean",
                else => "Object",
            }) else if (o.isCallableObject()) "Function" else "Object";
        },
        else => "Object",
    };
    // `Symbol.toStringTag` (a string) wins over the builtin tag.
    var tag = builtin_tag;
    if (tag_obj) |o| {
        if (symbolToStringTagKey(self)) |tk| {
            const tv = try self.getProperty(Value.obj(o), tk);
            if (tv.isString()) tag = tv.asStr();
        }
    }
    return Value.str(try std.mem.concat(self.arena, u8, &.{ "[object ", tag, "]" }));
}

pub fn objectToStringIsArray(self: *Interpreter, o: *value.Object) EvalError!bool {
    if (o.proxy_handler != null or o.proxy_revoked) {
        const target = o.proxy_target orelse return self.throwError("TypeError", "Cannot perform IsArray on a revoked proxy");
        return objectToStringIsArray(self, target);
    }
    return o.is_array;
}

/// Internal key of the well-known `Symbol.toStringTag`, for `@@toStringTag`.
fn symbolToStringTagKey(self: *Interpreter) ?[]const u8 {
    const sym = self.env.get("Symbol") orelse return null;
    if (!sym.isObject()) return null;
    const tt = sym.asObj().getOwn("toStringTag") orelse return null;
    if (!tt.isObject() or !tt.asObj().is_symbol) return null;
    return tt.asObj().sym_key;
}

/// `Error.isError(v)` — true iff `v` is an object with [[ErrorData]], looking
/// through a Proxy to its target (and false for a revoked proxy).
fn errorIsErrorFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = ctx;
    _ = this;
    const v = if (args.len > 0) args[0] else Value.undef();
    if (!v.isObject()) return Value.boolVal(false);
    var o = v.asObj();
    while (o.proxy_handler != null) {
        if (o.proxy_target) |t| o = t else break;
    }
    return Value.boolVal(o.is_error);
}

/// `Error.prototype.toString`: `"name: message"`, or just one when the other is
/// empty. Generic — reads `name`/`message` off `this` (so the prototype chain and
/// `.call(errorLike)` both work).
/// `Date.prototype[Symbol.toPrimitive](hint)`: OrdinaryToPrimitive over a string
/// hint — "string"/"default" try toString then valueOf, "number" the reverse;
/// any other hint (or a non-string) is a TypeError.
fn dateSymbolToPrimitiveFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject() or this.asObj().is_symbol or this.asObj().is_bigint)
        return self.throwError("TypeError", "Date.prototype[Symbol.toPrimitive] called on a non-object");
    const hint = if (args.len > 0) args[0] else Value.undef();
    if (!hint.isString()) return self.throwError("TypeError", "hint must be a string");
    const string_first = std.mem.eql(u8, hint.asStr(), "string") or std.mem.eql(u8, hint.asStr(), "default");
    if (!string_first and !std.mem.eql(u8, hint.asStr(), "number"))
        return self.throwError("TypeError", "invalid hint for Symbol.toPrimitive");
    const names: [2][]const u8 = if (string_first) .{ "toString", "valueOf" } else .{ "valueOf", "toString" };
    for (names) |m| {
        const method = try self.getProperty(this, m);
        if (method.isCallable()) {
            const res = try self.callValueWithThis(method, &.{}, this);
            if (!res.isObject() or res.asObj().is_symbol or res.asObj().is_bigint) return res;
        }
    }
    return self.throwError("TypeError", "Cannot convert object to primitive value");
}

fn errorToStringFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject() or this.asObj().is_symbol or this.asObj().is_bigint)
        return self.throwError("TypeError", "Error.prototype.toString called on a non-object");
    // ToString(name)/ToString(message) run ToPrimitive (throwing for a Symbol and
    // propagating an abrupt valueOf/toString).
    const name_v = try self.getProperty(this, "name");
    const name = if (name_v.isUndefined()) "Error" else try self.toStringV(name_v);
    const msg_v = try self.getProperty(this, "message");
    const msg = if (msg_v.isUndefined()) "" else try self.toStringV(msg_v);
    if (name.len == 0) return Value.str(msg);
    if (msg.len == 0) return Value.str(name);
    return Value.str(try std.mem.concat(self.arena, u8, &.{ name, ": ", msg }));
}

/// `Error.prototype.stack` getter (V8-style): a string for a receiver that has
/// `[[ErrorData]]` (an Error instance), otherwise undefined. The trace content
/// is implementation-defined; we return `"name: message"`.
fn errorStackGet(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject() or this.asObj().is_symbol or this.asObj().is_bigint)
        return self.throwError("TypeError", "Error.prototype.stack getter called on a non-object");
    // No [[ErrorData]] → undefined (e.g. Error.prototype, a plain object). For an
    // error, an implementation-defined trace string. Read the class name directly
    // off `[[ErrorData]]` rather than via [[Get]], so a hostile/recursive receiver
    // (proxy traps, getters) can't re-enter and blow the stack.
    if (!this.asObj().is_error) return Value.undef();
    const name = this.asObj().error_name;
    return Value.str(if (name.len == 0) "Error" else name);
}

/// SetterThatIgnoresPrototypeProperties(this, home, p, v): reject a non-object
/// receiver or the `home` object (which emulates a non-writable data property),
/// then — per the receiver's OWN descriptor — CreateDataPropertyOrThrow when the
/// property is absent (bypassing this inherited accessor) or Set(this, p, v,
/// true) when present (honoring an own accessor/writability).
fn setterIgnoringProto(self: *Interpreter, this: Value, home: ?*value.Object, key: []const u8, v: Value) EvalError!Value {
    if (!this.isObject() or this.asObj().is_symbol or this.asObj().is_bigint)
        return self.throwError("TypeError", "setter requires an object receiver");
    if (home) |h| if (this.asObj() == h) {
        const proto: ?*value.Object = if (h.getOwn("constructor")) |ctor|
            (if (ctor.isObject()) try self.functionRealmIntrinsicProto(ctor.asObj(), "TypeError") else null)
        else
            null;
        self.exception = try self.makeErrorWithProto("TypeError", "Cannot assign to the read-only property of the home object", proto);
        return error.Throw;
    };
    const o = this.asObj();
    // [[GetOwnProperty]](this, key): own data slot, own accessor, or proxy trap.
    const has_own = if (o.proxy_handler != null or o.proxy_revoked) blk: {
        const d = try builtins.objectGetOwnPropertyDescriptor(@ptrCast(self), Value.undef(), &.{ Value.obj(o), self.keyToValue(key) });
        break :blk d.isObject();
    } else (o.getOwn(key) != null or o.getAccessor(key) != null);
    if (!has_own) {
        // CreateDataPropertyOrThrow(this, key, v) — own {w,e,c}=true data property;
        // fails (TypeError) on a non-extensible receiver.
        const desc = (try self.newObject()).asObj();
        try desc.setOwn(self.arena, self.root_shape, "value", v);
        try desc.setOwn(self.arena, self.root_shape, "writable", Value.boolVal(true));
        try desc.setOwn(self.arena, self.root_shape, "enumerable", Value.boolVal(true));
        try desc.setOwn(self.arena, self.root_shape, "configurable", Value.boolVal(true));
        if (!try builtins.defineOneResult(self, o, key, desc))
            return self.throwError("TypeError", "Cannot create property");
        return Value.undef();
    }
    // Set(this, key, v, true) — honors an own accessor or writability.
    if (!try self.setMemberResult(Value.obj(o), key, v, Value.obj(o)))
        return self.throwError("TypeError", "Cannot set property");
    return Value.undef();
}

/// `Error.prototype.stack` setter. The home pointer (%Error.prototype%) is the
/// setter's `private_data`.
fn errorStackSet(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    // Step 1: a non-object receiver throws (handled in setterIgnoringProto).
    if (!this.isObject() or this.asObj().is_symbol or this.asObj().is_bigint)
        return self.throwError("TypeError", "Error.prototype.stack setter called on a non-object");
    // Step 2: v must already be a String (no coercion of an object/wrapper).
    const v = if (args.len > 0) args[0] else Value.undef();
    if (!v.isString())
        return self.throwError("TypeError", "Error.prototype.stack setter requires a string value");
    const home: ?*value.Object = if (self.active_native) |nat|
        (if (nat.private_data) |hd| @as(*value.Object, @ptrCast(@alignCast(hd))) else null)
    else
        null;
    return setterIgnoringProto(self, this, home, "stack", v);
}

/// Give `proto` a `constructor` own property pointing back to `ctor`
/// (non-enumerable, writable, configurable — the spec default for built-ins).
pub fn setConstructor(a: std.mem.Allocator, rs: *Shape, proto: *value.Object, ctor: *value.Object) EvalError!void {
    try proto.setOwn(a, rs, "constructor", Value.obj(ctor));
    try proto.setAttr(a, "constructor", .{ .enumerable = false, .configurable = true, .writable = true });
}

/// `Boolean.prototype.toString` / `valueOf` for a primitive boolean `this`.
fn booleanProtoFn(comptime to_string: bool) value.NativeFn {
    return struct {
        fn call(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
            _ = args;
            const self: *Interpreter = @ptrCast(@alignCast(ctx));
            const b: bool = switch (this.kind()) {
                .boolean => this.asBool(),
                // A Boolean wrapper object (`new Boolean(x)`) unwraps to its boxed value.
                .object => if (this.asObj().prim != null and this.asObj().prim.?.isBoolean()) this.asObj().prim.?.asBool() else return self.throwError("TypeError", "Boolean.prototype method requires that 'this' be a Boolean"),
                else => return self.throwError("TypeError", "Boolean.prototype method requires that 'this' be a Boolean"),
            };
            return if (to_string) Value.str(if (b) "true" else "false") else Value.boolVal(b);
        }
    }.call;
}

/// `Symbol.prototype.toString` → `"Symbol(description)"`. Requires a Symbol `this`.
fn symbolToStringFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const sym = try thisSymbol(self, this, "Symbol.prototype.toString");
    const ds = sym.sym_desc orelse "";
    return Value.str(try std.mem.concat(self.arena, u8, &.{ "Symbol(", ds, ")" }));
}

/// `Symbol.prototype.valueOf` → the Symbol itself. Requires a Symbol `this`.
fn symbolValueOfFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    _ = try thisSymbol(self, this, "Symbol.prototype.valueOf");
    return symbolThisValue(this);
}

/// `get Symbol.prototype.description` → the symbol's `[[Description]]` (a string
/// or `undefined`). Accepts a Symbol or a boxed Symbol wrapper as `this`.
fn symbolDescriptionGetFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const sym = try thisSymbol(self, this, "Symbol.prototype.description");
    return if (sym.sym_desc) |d| Value.str(d) else Value.undef();
}

/// `Symbol.prototype[@@toPrimitive]` → the symbol itself (any hint). Lets
/// `String(sym)`/`` `${sym}` `` route through it (and still throw on string
/// coercion via the normal ToString path, not here).
fn symbolToPrimitiveFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    _ = try thisSymbol(self, this, "Symbol.prototype[Symbol.toPrimitive]");
    return symbolThisValue(this);
}

/// The underlying Symbol value of `this` — the symbol itself, or the boxed
/// symbol of an `Object(sym)` wrapper.
fn symbolThisValue(this: Value) Value {
    if (this.isObject()) {
        if (this.asObj().is_symbol) return this;
        if (this.asObj().prim) |p| return p;
    }
    return this;
}

/// Brand-check helper: returns the Symbol object backing `this` (unwrapping an
/// `Object(sym)` wrapper), else throws a TypeError naming `method`.
fn thisSymbol(self: *Interpreter, this: Value, method: []const u8) EvalError!*value.Object {
    if (this.isObject()) {
        if (this.asObj().is_symbol) return this.asObj();
        if (this.asObj().prim) |p| {
            if (p.isObject() and p.asObj().is_symbol) return p.asObj();
        }
    }
    return self.throwError("TypeError", try std.fmt.allocPrint(self.arena, "{s} requires that 'this' be a Symbol", .{method}));
}

// ---- Proxy / Reflect natives ----------------------------------------------

fn proxyConstructorFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (self.new_target.isUndefined())
        return self.throwError("TypeError", "Constructor Proxy requires 'new'");
    const target = if (args.len > 0) args[0] else Value.undef();
    const handler = if (args.len > 1) args[1] else Value.undef();
    if (!builtins.isRealObject(target) or !builtins.isRealObject(handler))
        return self.throwError("TypeError", "Cannot create proxy with a non-object as target or handler");
    const o = try gc_mod.allocObj(self.arena);
    o.* = .{ .proxy_target = target.asObj(), .proxy_handler = handler.asObj(), .proxy_callable = target.asObj().isCallableObject() };
    return Value.obj(o);
}

/// `Proxy.revocable(target, handler)` → `{ proxy, revoke }`.
fn proxyRevocableFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const saved_nt = self.new_target;
    self.new_target = Value.undef(); // proxyConstructorFn requires new; emulate it
    defer self.new_target = saved_nt;
    const target = if (args.len > 0) args[0] else Value.undef();
    const handler = if (args.len > 1) args[1] else Value.undef();
    if (!builtins.isRealObject(target) or !builtins.isRealObject(handler))
        return self.throwError("TypeError", "Cannot create proxy with a non-object as target or handler");
    const p = try gc_mod.allocObj(self.arena);
    p.* = .{ .proxy_target = target.asObj(), .proxy_handler = handler.asObj(), .proxy_callable = target.asObj().isCallableObject() };
    const revoke = try gc_mod.allocObj(self.arena);
    revoke.* = .{ .native = proxyRevokeFn, .private_data = @ptrCast(p) };
    try installNativeProps(self.arena, self.root_shape, revoke, "", 0);
    const result = (try self.newObject()).asObj();
    try self.setProp(result, "proxy", Value.obj(p));
    try self.setProp(result, "revoke", Value.obj(revoke));
    return Value.obj(result);
}

fn proxyRevokeFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (self.active_native) |nf| {
        if (nf.private_data) |pd| {
            const p: *value.Object = @ptrCast(@alignCast(pd));
            p.proxy_revoked = true;
            p.proxy_target = null;
            p.proxy_handler = null;
        }
    }
    return Value.undef();
}

fn reflectGetFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const target = if (args.len > 0) args[0] else Value.undef();
    if (!builtins.isRealObject(target)) return self.throwError("TypeError", "Reflect.get called on non-object");
    const receiver = if (args.len > 2) args[2] else target;
    return self.getPropertyWithReceiver(target, try self.keyOf(if (args.len > 1) args[1] else Value.undef()), receiver);
}

fn reflectSetFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const target = if (args.len > 0) args[0] else Value.undef();
    if (!builtins.isRealObject(target)) return self.throwError("TypeError", "Reflect.set called on non-object");
    // A module namespace's [[Set]] returns false (Reflect.set reports it without
    // throwing, unlike a strict assignment).
    if (target.isObject() and isModuleNs(target.asObj())) return Value.boolVal(false);
    const receiver = if (args.len > 3) args[3] else target;
    return Value.boolVal(try self.setMemberResult(target, try self.keyOf(if (args.len > 1) args[1] else Value.undef()), if (args.len > 2) args[2] else Value.undef(), receiver));
}

fn reflectHasFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const target = if (args.len > 0) args[0] else Value.undef();
    if (!builtins.isRealObject(target)) return self.throwError("TypeError", "Reflect.has called on non-object");
    return Value.boolVal(try self.inOperator(if (args.len > 1) args[1] else Value.undef(), target));
}

fn reflectDeleteFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const target = if (args.len > 0) args[0] else Value.undef();
    if (!builtins.isRealObject(target)) return self.throwError("TypeError", "Reflect.deleteProperty called on non-object");
    return Value.boolVal(try self.deleteOwn(target.asObj(), try self.keyOf(if (args.len > 1) args[1] else Value.undef())));
}

fn reflectOwnKeysFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (args.len > 0 and args[0].isObject()) try self.checkRestricted(args[0].asObj());
    const target = if (args.len > 0) args[0] else Value.undef();
    if (!builtins.isRealObject(target)) return self.throwError("TypeError", "Reflect.ownKeys called on non-object");
    // objectOwnKeysList is proxy- and module-namespace-aware (sorted exotic keys).
    const keys = try self.objectOwnKeysList(target.asObj());
    const arr = try self.newArray();
    for (keys) |k| try arr.asObj().elements.append(arr.asObj().elementsAllocator(self.arena), self.keyToValue(k));
    return arr;
}

fn reflectGetProtoFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const target = if (args.len > 0) args[0] else Value.undef();
    if (!builtins.isRealObject(target)) return self.throwError("TypeError", "Reflect.getPrototypeOf called on non-object");
    if (target.asObj().proxy_handler != null or target.asObj().proxy_revoked) return self.proxyGetProto(target.asObj());
    return if (target.asObj().proto) |p| Value.obj(p) else Value.nul();
}

/// CreateListFromArrayLike: a non-Array argumentsList is still read via its
/// `length` + indexed properties (a throwing `length`/index getter propagates);
/// a non-object is a TypeError. Real arrays take the dense fast path.
fn createListFromArrayLike(self: *Interpreter, v: Value) EvalError![]const Value {
    if (!builtins.isRealObject(v)) return self.throwError("TypeError", "Reflect: arguments list is not an object");
    if (v.asObj().is_array) return v.asObj().elements.items;
    const len = toLen((try self.toPrimitive(try self.getProperty(v, "length"), .number)).toNumber());
    if (len > (1 << 22)) return self.throwError("RangeError", "arguments list is too large");
    const buf = try self.arena.alloc(Value, len);
    for (buf, 0..) |*slot, i| slot.* = try self.getProperty(v, try std.fmt.allocPrint(self.arena, "{d}", .{i}));
    return buf;
}

fn reflectApplyFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const target = if (args.len > 0) args[0] else Value.undef();
    if (!target.isCallable()) return self.throwError("TypeError", "Reflect.apply target is not a function");
    const this_arg = if (args.len > 1) args[1] else Value.undef();
    const list = try createListFromArrayLike(self, if (args.len > 2) args[2] else Value.undef());
    return self.callValueWithThis(target, list, this_arg);
}

fn reflectConstructFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const target = if (args.len > 0) args[0] else Value.undef();
    if (!isConstructorValue(target)) return self.throwError("TypeError", "Reflect.construct target is not a constructor");
    // A new.target (3rd arg) must itself be a constructor — this is what the
    // `isConstructor` harness probes via `Reflect.construct(fn, [], target)`.
    if (args.len > 2 and !isConstructorValue(args[2]))
        return self.throwError("TypeError", "Reflect.construct newTarget is not a constructor");
    const list = try createListFromArrayLike(self, if (args.len > 1) args[1] else Value.undef());
    const new_target = if (args.len > 2) args[2] else target;
    return self.constructNT(target, list, new_target);
}

/// `Reflect.getOwnPropertyDescriptor(target, key)` — like the Object.* form but
/// a non-Object target is a TypeError (Object.* coerces / returns undefined).
fn reflectGetOwnDescFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!builtins.isRealObject(if (args.len > 0) args[0] else Value.undef()))
        return self.throwError("TypeError", "Reflect.getOwnPropertyDescriptor called on non-object");
    return builtins.objectGetOwnPropertyDescriptor(ctx, this, args);
}

/// `Reflect.isExtensible(target)` — TypeError on a non-Object (Object.* returns false).
fn reflectIsExtensibleFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (args.len > 0 and args[0].isObject()) try self.checkRestricted(args[0].asObj());
    if (!builtins.isRealObject(if (args.len > 0) args[0] else Value.undef()))
        return self.throwError("TypeError", "Reflect.isExtensible called on non-object");
    return builtins.objectIsExtensible(ctx, this, args);
}

/// `Reflect.preventExtensions(target)` — TypeError on a non-Object, returns a
/// boolean (Object.preventExtensions returns the target / no-ops a primitive).
fn reflectPreventExtFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (args.len > 0 and args[0].isObject()) try self.checkRestricted(args[0].asObj());
    const target = if (args.len > 0) args[0] else Value.undef();
    if (!builtins.isRealObject(target))
        return self.throwError("TypeError", "Reflect.preventExtensions called on non-object");
    if (target.asObj().proxy_handler != null or target.asObj().proxy_revoked)
        return Value.boolVal(try self.proxyPreventExt(target.asObj()));
    target.asObj().extensible = false;
    return Value.boolVal(true);
}

/// `Reflect.setPrototypeOf(target, proto)` — OrdinarySetPrototypeOf returning a
/// boolean: TypeError if target is not an Object or proto is not Object|null;
/// otherwise true on success and false (NOT a throw) when the object is
/// non-extensible or the new prototype would form a cycle.
fn reflectSetProtoFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const target = if (args.len > 0) args[0] else Value.undef();
    if (!builtins.isRealObject(target))
        return self.throwError("TypeError", "Reflect.setPrototypeOf called on non-object");
    const p = if (args.len > 1) args[1] else Value.undef();
    if (!p.isNull() and !builtins.isRealObject(p))
        return self.throwError("TypeError", "Object prototype may only be an Object or null");
    const new_proto: ?*value.Object = if (p.isObject()) p.asObj() else null;
    return Value.boolVal(try self.setPrototypeOfObject(target.asObj(), new_proto));
}

/// Best-effort [[Construct]]-ability test: a native flagged `native_ctor`, an
/// error constructor, a non-arrow/non-generator/non-async JS function, a bound
/// function over a constructor, or a proxy whose target is a constructor.
pub fn isConstructorValue(v: Value) bool {
    if (!v.isObject()) return false;
    const o = v.asObj();
    if (o.proxy_handler != null) return if (o.proxy_target) |t| isConstructorValue(Value.obj(t)) else false;
    if (o.bound) |erased| {
        const bf: *Interpreter.BoundFn = @ptrCast(@alignCast(erased));
        return isConstructorValue(bf.target);
    }
    if (o.error_ctor != null) return true;
    if (o.native != null) return o.native_ctor;
    if (o.js_func) |erased| {
        const f: *Function = @ptrCast(@alignCast(erased));
        return !f.is_arrow and !f.is_async and !f.is_generator and !f.is_method;
    }
    return false;
}

/// Install the engine's global bindings into `env`: the `Error`-family
/// constructors, `NaN`/`Infinity`/`undefined`, the `Math` and `Object`/`Array`
/// namespaces, and the common global functions. `root_shape` backs the property
/// stores of the namespace objects. Called once per Context, before user code.
fn eq(a: []const u8, b: []const u8) bool {
    return std.mem.eql(u8, a, b);
}

/// Mirror a global environment's bindings onto its global object as own
/// properties (matching `Context.create`), so `globalThis.X` / reflection work.
pub fn mirrorGlobalsOnto(env: *Environment, gobj: *value.Object, rs: *Shape) EvalError!void {
    var it = env.vars.iterator();
    while (it.next()) |e| {
        const name = e.key_ptr.*;
        if (name.len > 0 and name[0] == 0) continue;
        if (gobj.getOwn(name) != null) continue;
        try gobj.setOwn(env.arena, rs, name, e.value_ptr.*);
        const frozen = eq(name, "undefined") or eq(name, "NaN") or eq(name, "Infinity");
        try gobj.setAttr(env.arena, name, if (frozen)
            .{ .writable = false, .enumerable = false, .configurable = false }
        else
            .{ .writable = true, .enumerable = false, .configurable = true });
    }
}

/// `$262.gc()` — a no-op (the engine uses an arena, no explicit GC).
fn host262GcFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = ctx;
    _ = this;
    _ = args;
    return Value.undef();
}

/// `$262.IsHTMLDDA()` — the [[Call]] of an [[IsHTMLDDA]] object (legacy
/// `document.all`): returns null when called with no arguments or a first
/// argument that is undefined or the empty string, else undefined.
fn host262IsHTMLDDACallFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = ctx;
    _ = this;
    if (args.len == 0) return Value.nul();
    if (args[0].isUndefined()) return Value.nul();
    if (args[0].isString() and args[0].asStr().len == 0) return Value.nul();
    return Value.undef();
}

/// `$262.detachArrayBuffer(buffer)` — detach an ArrayBuffer's backing store.
fn host262DetachFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    _ = ctx;
    const v = if (args.len > 0) args[0] else Value.undef();
    if (v.isObject()) if (v.asObj().array_buffer) |ab| {
        ab.detached = true;
    };
    return Value.undef();
}

/// `$262.evalScript(src)` / a realm's evalScript — parse + evaluate `src` as a
/// global script in the realm captured in this native's `private_data`.
fn host262EvalScriptFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const fnobj = self.active_native orelse return Value.undef();
    const genv: *Environment = @ptrCast(@alignCast(fnobj.private_data orelse return Value.undef()));
    if (args.len == 0 or !args[0].isString()) return if (args.len > 0) args[0] else Value.undef();
    var parser = Parser.init(self.arena, args[0].asStr()) catch return self.throwError("SyntaxError", "evalScript: invalid source");
    const prog = parser.parseProgram() catch return self.throwError("SyntaxError", "evalScript: parse error");
    const gobj: ?*value.Object = if (genv.get("globalThis")) |g| (if (g.isObject()) g.asObj() else null) else null;
    const s_env = self.env;
    const s_this = self.this_value;
    const s_glob = self.global_object;
    self.env = genv;
    if (gobj) |go| {
        self.this_value = Value.obj(go);
        self.global_object = go;
    }
    defer {
        self.env = s_env;
        self.this_value = s_this;
        self.global_object = s_glob;
    }
    return self.eval(prog);
}

/// `$262.createRealm()` — a fresh realm (its own global environment, intrinsics,
/// and global object), returned as `{ global, evalScript }`.
fn host262CreateRealmFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const a = self.arena;
    const genv = try gc_mod.allocEnv(a);
    self.initEnvironment(genv, null, true);
    const gobj = try gc_mod.allocObj(a);
    gobj.* = .{};
    // Share the creating realm's well-known symbols with the new realm.
    const parent_symbol: ?*value.Object = if (self.env.get("Symbol")) |sv| (if (sv.isObject()) sv.asObj() else null) else null;
    try installGlobalsInner(genv, self.root_shape, parent_symbol);
    try genv.put("globalThis", Value.obj(gobj));
    try mirrorGlobalsOnto(genv, gobj, self.root_shape);
    // Point the new realm's own `$262.global` at its global object.
    if (genv.get("$262")) |d| {
        if (d.isObject()) try self.setProp(d.asObj(), "global", Value.obj(gobj));
    }
    // The realm record handed back to the caller (in the caller's realm).
    const realm = (try self.newObject()).asObj();
    try self.setProp(realm, "global", Value.obj(gobj));
    const es = try gc_mod.allocObj(a);
    es.* = .{ .native = host262EvalScriptFn, .private_data = @ptrCast(genv) };
    try installNativeProps(a, self.root_shape, es, "evalScript", 1);
    try self.setProp(realm, "evalScript", Value.obj(es));
    return Value.obj(realm);
}

fn host262AbstractModuleSourceFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    return self.throwError("TypeError", "AbstractModuleSource is not constructible");
}

fn host262AbstractModuleSourceTagGetter(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = ctx;
    _ = this;
    _ = args;
    // Real module source objects will carry [[ModuleSourceClassName]] later.
    return Value.undef();
}

fn install262AbstractModuleSource(env: *Environment, rs: *Shape, host: *value.Object, object_proto: *value.Object) EvalError!void {
    const a = env.arena;
    const proto = try gc_mod.allocObj(a);
    proto.* = .{ .proto = object_proto };

    const ctor = try gc_mod.allocObj(a);
    const function_proto: ?*value.Object = blk: {
        if (env.get("Function")) |fv| if (fv.isObject()) {
            if (fv.asObj().getOwn("prototype")) |pv| if (pv.isObject()) break :blk pv.asObj();
        };
        break :blk null;
    };
    ctor.* = .{ .native = host262AbstractModuleSourceFn, .native_ctor = true, .proto = function_proto };
    try installNativeProps(a, rs, ctor, "AbstractModuleSource", 0);
    try ctor.setOwn(a, rs, "prototype", Value.obj(proto));
    try ctor.setAttr(a, "prototype", .{ .writable = false, .enumerable = false, .configurable = false });
    try setConstructor(a, rs, proto, ctor);

    if (env.get("Symbol")) |sym| if (sym.isObject()) {
        if (sym.asObj().getOwn("toStringTag")) |tag| if (tag.isObject() and tag.asObj().is_symbol) {
            const getter = try gc_mod.allocObj(a);
            getter.* = .{ .native = host262AbstractModuleSourceTagGetter };
            try installNativeProps(a, rs, getter, "get [Symbol.toStringTag]", 0);
            try proto.setAccessor(a, tag.asObj().sym_key, Value.obj(getter), null);
            try proto.setAttr(a, tag.asObj().sym_key, .{ .enumerable = false, .configurable = true });
        };
    };

    try host.setOwn(a, rs, "AbstractModuleSource", Value.obj(ctor));
    try host.setAttr(a, "AbstractModuleSource", .{ .writable = true, .enumerable = false, .configurable = true });
}

/// Build a fresh realm (own global env + global object + intrinsics), sharing
/// the creating realm's well-known symbols. Returns the new Environment.
fn makeChildRealm(self: *Interpreter) EvalError!*Environment {
    const a = self.arena;
    const genv = try gc_mod.allocEnv(a);
    self.initEnvironment(genv, null, true);
    const gobj = try gc_mod.allocObj(a);
    gobj.* = .{};
    const parent_symbol: ?*value.Object = if (self.env.get("Symbol")) |sv| (if (sv.isObject()) sv.asObj() else null) else null;
    const parent_symbol_registry = try symbolRegistry(self);
    try installGlobalsInner(genv, self.root_shape, parent_symbol);
    if (parent_symbol_registry) |reg| {
        if (genv.get("Symbol")) |sv| if (sv.isObject())
            try sv.asObj().setOwn(a, self.root_shape, "\x00registry", Value.obj(reg));
    }
    if (genv.get("Object")) |ov| if (ov.isObject()) {
        if (ov.asObj().getOwn("prototype")) |pv| {
            if (pv.isObject()) gobj.proto = pv.asObj();
        }
    };
    try genv.put("globalThis", Value.obj(gobj));
    try mirrorGlobalsOnto(genv, gobj, self.root_shape);
    if (genv.get("$262")) |d| {
        if (d.isObject()) try self.setProp(d.asObj(), "global", Value.obj(gobj));
    }
    return genv;
}

fn shadowRealmNativeRealm(self: *Interpreter) ?*Environment {
    const native = self.active_native orelse return null;
    return @ptrCast(@alignCast(native.private_data orelse return null));
}

fn throwErrorInRealm(self: *Interpreter, realm: *Environment, name: []const u8, message: []const u8) EvalError {
    const saved_env = self.env;
    self.env = realm;
    defer self.env = saved_env;
    return self.throwError(name, message);
}

fn objectFunctionRealm(o: *value.Object) ?*Environment {
    if (o.js_func) |erased| {
        const func: *Function = @ptrCast(@alignCast(erased));
        return func.closure;
    }
    return null;
}

fn symbolProtoInRealm(realm: *Environment) ?*value.Object {
    const sym = realm.get("Symbol") orelse return null;
    if (!sym.isObject()) return null;
    const p = sym.asObj().getOwn("prototype") orelse return null;
    return if (p.isObject()) p.asObj() else null;
}

const SrWrappedData = struct {
    target: *value.Object,
    caller_env: *Environment,
    target_env: *Environment,
};

/// GetWrappedValue across a ShadowRealm boundary: a primitive (incl. Symbol /
/// BigInt) passes through; a callable becomes a forwarding wrapper function; any
/// other object is a TypeError.
fn srWrapValue(self: *Interpreter, wrap_env: *Environment, error_env: *Environment, v: Value) EvalError!Value {
    if (!v.isObject()) return v;
    const o = v.asObj();
    if (o.is_symbol) {
        if (symbolProtoInRealm(wrap_env)) |p| o.proto = p;
        return v;
    }
    if (o.is_bigint) return v;
    if (o.isCallableObject()) {
        const saved_env = self.env;
        self.env = wrap_env;
        defer self.env = saved_env;
        const w = (try self.newObject()).asObj();
        w.native = srWrappedCallFn;
        const data = try self.arena.create(SrWrappedData);
        data.* = .{
            .target = o,
            .caller_env = wrap_env,
            .target_env = objectFunctionRealm(o) orelse wrap_env,
        };
        w.private_data = @ptrCast(data);
        // The wrapper's [[Prototype]] is the realm receiving the wrapped value.
        if (wrap_env.get("Function")) |fc| if (fc.isObject()) {
            if (fc.asObj().getOwn("prototype")) |fp| if (fp.isObject()) {
                w.proto = fp.asObj();
            };
        };
        // CopyNameAndLength(wrapped, target): a read that throws (a poisoned
        // length/name getter) aborts the wrap with a TypeError in error_env.
        const ro_attr: value.PropAttr = .{ .writable = false, .enumerable = false, .configurable = true };
        const len_desc = builtins.objectGetOwnPropertyDescriptor(self, Value.undef(), &.{ Value.obj(o), Value.str("length") }) catch
            return throwErrorInRealm(self, error_env, "TypeError", "ShadowRealm: wrapped function length is not accessible");
        const len_v = if (len_desc.isUndefined())
            Value.undef()
        else
            self.getProperty(Value.obj(o), "length") catch
                return throwErrorInRealm(self, error_env, "TypeError", "ShadowRealm: wrapped function length is not accessible");
        // ToIntegerOrInfinity(targetLen): +∞ is preserved; otherwise clamp to ≥ 0.
        const len: f64 = if (len_v.isNumber() and !std.math.isNan(len_v.asNum()))
            (if (std.math.isInf(len_v.asNum())) (if (len_v.asNum() > 0) len_v.asNum() else 0) else @max(0, @trunc(len_v.asNum())))
        else
            0;
        try w.setOwn(self.arena, self.root_shape, "length", Value.num(len));
        try w.setAttr(self.arena, "length", ro_attr);
        const name_v = self.getProperty(Value.obj(o), "name") catch
            return throwErrorInRealm(self, error_env, "TypeError", "ShadowRealm: wrapped function name is not accessible");
        try w.setOwn(self.arena, self.root_shape, "name", Value.str(if (name_v.isString()) name_v.asStr() else ""));
        try w.setAttr(self.arena, "name", ro_attr);
        return Value.obj(w);
    }
    return throwErrorInRealm(self, error_env, "TypeError", "ShadowRealm: a non-callable object cannot cross the realm boundary");
}

/// A wrapped ShadowRealm callable: wrap each argument inward, call the target,
/// and wrap the result outward.
fn srWrappedCallFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const fnobj = self.active_native orelse return Value.undef();
    const data: *SrWrappedData = @ptrCast(@alignCast(fnobj.private_data orelse return Value.undef()));
    const wargs = try self.arena.alloc(Value, args.len);
    for (args, 0..) |arg_v, i| wargs[i] = try srWrapValue(self, data.target_env, data.caller_env, arg_v);
    // WrappedFunction [[Call]]: a normal completion is wrapped outward; an abrupt
    // one is re-thrown as a TypeError in the *calling* realm.
    const r = self.callValueWithThis(Value.obj(data.target), wargs, Value.undef()) catch |e| {
        if (e == error.Throw) return throwErrorInRealm(self, data.caller_env, "TypeError", "WrappedFunction: the wrapped target threw");
        return e;
    };
    return srWrapValue(self, data.caller_env, data.caller_env, r);
}

fn shadowRealmConstructorFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const ctor_env = shadowRealmNativeRealm(self) orelse self.env;
    if (self.new_target.isUndefined()) return throwErrorInRealm(self, ctor_env, "TypeError", "Constructor ShadowRealm requires 'new'");
    const saved_env = self.env;
    self.env = ctor_env;
    defer self.env = saved_env;
    const genv = try makeChildRealm(self);
    const o = (try self.newObject()).asObj();
    o.is_shadow_realm = true;
    o.private_data = @ptrCast(genv);
    if (self.new_target.isObject()) o.proto = try self.protoObject(self.new_target.asObj());
    return Value.obj(o);
}

/// `ShadowRealm.prototype.importValue(specifier, exportName)` — validates the
/// receiver and arguments synchronously (ToString(specifier); exportName must be
/// a String), then returns a Promise. Module loading inside a ShadowRealm is not
/// wired up, so the returned promise rejects.
fn shadowRealmImportValueFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject() or !this.asObj().is_shadow_realm) return self.throwError("TypeError", "ShadowRealm.prototype.importValue called on a non-ShadowRealm");
    _ = try self.toStringV(if (args.len > 0) args[0] else Value.undef()); // ToString(specifier) — may throw
    const export_name = if (args.len > 1) args[1] else Value.undef();
    if (!export_name.isString()) return self.throwError("TypeError", "ShadowRealm.prototype.importValue: exportName must be a string");
    const reason = try self.makeError("TypeError", "ShadowRealm module import is not supported");
    return promiseRejectValue(self, reason);
}

fn shadowRealmEvaluateFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const caller_env = shadowRealmNativeRealm(self) orelse self.env;
    if (!this.isObject() or !this.asObj().is_shadow_realm) return throwErrorInRealm(self, caller_env, "TypeError", "ShadowRealm.prototype.evaluate called on a non-ShadowRealm");
    const src = if (args.len > 0) args[0] else Value.undef();
    if (!src.isString()) return throwErrorInRealm(self, caller_env, "TypeError", "ShadowRealm.prototype.evaluate expects a string");
    const genv: *Environment = @ptrCast(@alignCast(this.asObj().private_data orelse return throwErrorInRealm(self, caller_env, "TypeError", "ShadowRealm has no realm")));
    var parser = Parser.init(self.arena, src.asStr()) catch return throwErrorInRealm(self, caller_env, "SyntaxError", "evaluate: invalid source");
    const prog = parser.parseProgram() catch return throwErrorInRealm(self, caller_env, "SyntaxError", "evaluate: parse error");
    const prog_strict = parser.strict;
    const gobj: ?*value.Object = if (genv.get("globalThis")) |g| (if (g.isObject()) g.asObj() else null) else null;
    const s_env = self.env;
    const s_this = self.this_value;
    const s_glob = self.global_object;
    const s_strict = self.strict;
    self.env = genv;
    self.strict = prog_strict;
    if (gobj) |go| {
        self.this_value = Value.obj(go);
        self.global_object = go;
    }
    const eval_result = self.eval(prog);
    // Restore the CALLER realm before converting an abrupt completion / wrapping
    // the result, so a boundary TypeError is created with the caller's %TypeError%
    // (and the result value is wrapped from the caller's perspective).
    self.env = s_env;
    self.this_value = s_this;
    self.global_object = s_glob;
    self.strict = s_strict;
    const result = eval_result catch |e| {
        // A throw inside the child realm surfaces as a TypeError in the caller
        // (the thrown value can't cross the boundary).
        if (e == error.Throw) {
            return throwErrorInRealm(self, caller_env, "TypeError", "ShadowRealm.prototype.evaluate: the evaluated code threw");
        }
        return e;
    };
    return srWrapValue(self, caller_env, caller_env, result);
}

/// Install the test262 `$262` host object into `env` (its `global` is wired up
/// by the caller once the realm's global object exists).
pub fn install262(env: *Environment, rs: *Shape, object_proto: *value.Object) EvalError!void {
    const a = env.arena;
    const d = try gc_mod.allocObj(a);
    d.* = .{ .proto = object_proto };
    try setNative(a, rs, d, "gc", 0, host262GcFn);
    try setNative(a, rs, d, "detachArrayBuffer", 1, host262DetachFn);
    try setNative(a, rs, d, "createRealm", 0, host262CreateRealmFn);
    // $262.IsHTMLDDA — an [[IsHTMLDDA]] exotic (typeof "undefined", falsy,
    // loosely-equal to null/undefined), callable per its legacy [[Call]].
    const htmldda = try gc_mod.allocObj(a);
    htmldda.* = .{ .proto = object_proto, .native = host262IsHTMLDDACallFn, .is_htmldda = true };
    try d.setOwn(a, rs, "IsHTMLDDA", Value.obj(htmldda));
    const es = try gc_mod.allocObj(a);
    es.* = .{ .native = host262EvalScriptFn, .private_data = @ptrCast(env) };
    try installNativeProps(a, rs, es, "evalScript", 1);
    try d.setOwn(a, rs, "evalScript", Value.obj(es));
    try install262AbstractModuleSource(env, rs, d, object_proto);
    try installAgent(a, rs, d);
    // On the main thread, each test gets a fresh Context → reset cross-test
    // agent coordination state. Agent threads must NOT reset it (the parent owns
    // the broadcast/report channels they're using).
    // A fresh *main* realm tears down the previous test's agent group (joins
    // agent threads, clears reports/broadcast, wakes stranded waiters). An
    // agent realm installing $262 must not reset the group it belongs to.
    if (agent.currentAgent() == null) agent.reset();
    try env.put("$262", Value.obj(d));
}

/// Render an `i128` in `radix` (2..36).
fn formatBigIntRadix(arena: std.mem.Allocator, val: i128, radix: u8) error{OutOfMemory}![]const u8 {
    if (val == 0) return "0";
    var buf: [200]u8 = undefined;
    var i: usize = buf.len;
    const neg = val < 0;
    // Magnitude in u128 (bitcast handles i128 minInt without overflow on negate).
    var v: u128 = if (neg) @as(u128, @bitCast(-%val)) else @intCast(val);
    const digits = "0123456789abcdefghijklmnopqrstuvwxyz";
    while (v > 0) {
        i -= 1;
        buf[i] = digits[@intCast(v % radix)];
        v /= radix;
    }
    if (neg) {
        i -= 1;
        buf[i] = '-';
    }
    return arena.dupe(u8, buf[i..]);
}

fn canonicalBigIntDecimalString(arena: std.mem.Allocator, raw: []const u8) error{OutOfMemory}!?[]const u8 {
    if (raw.len == 0) return null;
    var i: usize = 0;
    var neg = false;
    if (raw[i] == '+' or raw[i] == '-') {
        neg = raw[i] == '-';
        i += 1;
        if (i == raw.len) return null;
    }
    while (i < raw.len and raw[i] == '0') i += 1;
    if (i == raw.len) return "0";
    for (raw[i..]) |c| if (!std.ascii.isDigit(c)) return null;
    if (!neg) {
        const out = try arena.dupe(u8, raw[i..]);
        return out;
    }
    const out = try std.mem.concat(arena, u8, &.{ "-", raw[i..] });
    return out;
}

fn canonicalBigIntRadixString(arena: std.mem.Allocator, digits: []const u8, radix: u8) error{OutOfMemory}!?[]const u8 {
    if (digits.len == 0) return null;
    var non_zero = false;
    for (digits) |c| {
        const d = std.fmt.charToDigit(c, radix) catch return null;
        if (d != 0) non_zero = true;
    }
    if (!non_zero) return "0";
    if (std.fmt.parseInt(i128, digits, radix)) |n| {
        const out: []const u8 = try std.fmt.allocPrint(arena, "{d}", .{n});
        return out;
    } else |_| {}

    var decimal: std.ArrayListUnmanaged(u8) = .empty; // little-endian decimal digits
    try decimal.append(arena, 0);
    for (digits) |c| {
        const digit = std.fmt.charToDigit(c, radix) catch unreachable;
        var carry: u16 = digit;
        for (decimal.items) |*decimal_digit| {
            const value_ = @as(u16, decimal_digit.*) * radix + carry;
            decimal_digit.* = @intCast(value_ % 10);
            carry = value_ / 10;
        }
        while (carry > 0) {
            try decimal.append(arena, @intCast(carry % 10));
            carry /= 10;
        }
    }
    while (decimal.items.len > 1 and decimal.items[decimal.items.len - 1] == 0) decimal.items.len -= 1;
    var out = try arena.alloc(u8, decimal.items.len);
    for (decimal.items, 0..) |d, i| out[out.len - 1 - i] = '0' + d;
    return out;
}

/// `BigInt(value)` — NumberToBigInt for an integral Number, else ToBigInt.
/// It has [[Construct]] so IsConstructor(BigInt) is true, but `new BigInt`
/// throws before argument coercion.
fn bigIntFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const saved_env = self.env;
    var swapped_env = false;
    if (self.active_native) |callee| {
        if (callee.private_data) |pd| {
            self.env = @ptrCast(@alignCast(pd));
            swapped_env = true;
        }
    }
    defer if (swapped_env) {
        self.env = saved_env;
    };
    if (!self.new_target.isUndefined()) return self.throwError("TypeError", "BigInt is not a constructor");
    return self.toBigIntValueImpl(if (args.len > 0) args[0] else Value.undef(), true);
}

fn bigIntRoundSignificant(self: *Interpreter, digits_in: []const u8, max_sig: usize) EvalError![]const u8 {
    if (max_sig == 0 or digits_in.len <= max_sig) return digits_in;
    var kept = try self.arena.dupe(u8, digits_in[0..max_sig]);
    if (digits_in[max_sig] >= '5') {
        var i = kept.len;
        while (i > 0) {
            i -= 1;
            if (kept[i] < '9') {
                kept[i] += 1;
                break;
            }
            kept[i] = '0';
        } else {
            var carry: std.ArrayListUnmanaged(u8) = .empty;
            try carry.append(self.arena, '1');
            try carry.appendSlice(self.arena, kept);
            kept = try carry.toOwnedSlice(self.arena);
        }
    }
    var out: std.ArrayListUnmanaged(u8) = .empty;
    try out.appendSlice(self.arena, kept);
    var z = digits_in.len - max_sig;
    while (z > 0) : (z -= 1) try out.append(self.arena, '0');
    return out.toOwnedSlice(self.arena);
}

fn bigIntGroupedDecimal(self: *Interpreter, digits: []const u8, locale: []const u8, group: []const u8) EvalError![]const u8 {
    const indic = nfIndicGrouping(locale);
    var out: std.ArrayListUnmanaged(u8) = .empty;
    const n = digits.len;
    for (digits, 0..) |c, i| {
        const rem = n - i;
        const at_boundary = if (indic)
            (rem == 3 or (rem > 3 and (rem - 3) % 2 == 0))
        else
            (rem % 3 == 0);
        if (i != 0 and at_boundary) try out.appendSlice(self.arena, group);
        try out.append(self.arena, c);
    }
    return out.toOwnedSlice(self.arena);
}

fn bigIntFormatWithOptions(self: *Interpreter, big: *value.Object, loc: []const u8, ro: *value.Object) value.HostError![]const u8 {
    var s = try value.bigIntToString(big, self.arena);
    const neg = s.len > 0 and s[0] == '-';
    if (neg) s = s[1..];
    if (ro.getOwn("style")) |sv| if (sv.isString() and std.mem.eql(u8, sv.asStr(), "percent")) {
        s = try std.fmt.allocPrint(self.arena, "{s}00", .{s});
    };
    if (ro.getOwn("maximumSignificantDigits")) |msv| if (msv.isNumber()) {
        s = try bigIntRoundSignificant(self, s, @intFromFloat(msv.asNum()));
    };
    const syms = localeNumberSymbols(loc);
    const grouped = try bigIntGroupedDecimal(self, s, loc, syms.group);
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    if (neg) try buf.appendSlice(self.arena, syms.minus);
    try buf.appendSlice(self.arena, grouped);
    if (ro.getOwn("minimumFractionDigits")) |mfv| if (mfv.isNumber()) {
        const n: usize = @intFromFloat(mfv.asNum());
        if (n > 0) {
            try buf.appendSlice(self.arena, syms.decimal);
            for (0..n) |_| try buf.append(self.arena, '0');
        }
    };
    if (ro.getOwn("style")) |sv| if (sv.isString() and std.mem.eql(u8, sv.asStr(), "percent")) {
        if (loc.len >= 2 and loc[0] == 'd' and loc[1] == 'e') try buf.appendSlice(self.arena, "\xc2\xa0");
        try buf.appendSlice(self.arena, syms.percent);
    };
    return buf.toOwnedSlice(self.arena);
}

fn bigIntToLocaleStringFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const big = if (this.isObject() and this.asObj().is_bigint) this.asObj() else if (this.isObject() and this.asObj().prim != null and this.asObj().prim.?.isObject() and this.asObj().prim.?.asObj().is_bigint) this.asObj().prim.?.asObj() else return self.throwError("TypeError", "BigInt.prototype.toLocaleString requires that 'this' be a BigInt");
    const locs = try canonicalizeLocaleList(self, if (args.len > 0) args[0] else Value.undef());
    const loc = if (locs.elements.items.len > 0) locs.elements.items[0].asStr() else "en";
    const ro = try nfProcessOptions(self, if (args.len > 1) args[1] else Value.undef());
    return Value.str(try bigIntFormatWithOptions(self, big, loc, ro));
}

/// `BigInt.prototype.toString(radix)` — the BigInt rendered in `radix` (2..36).
fn bigIntToStringFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const big = if (this.isObject() and this.asObj().is_bigint) this.asObj() else if (this.isObject() and this.asObj().prim != null and this.asObj().prim.?.isObject() and this.asObj().prim.?.asObj().is_bigint) this.asObj().prim.?.asObj() else return self.throwError("TypeError", "BigInt.prototype.toString requires that 'this' be a BigInt");
    const radix: u8 = if (args.len > 0 and !args[0].isUndefined()) @intFromFloat(@trunc(try self.toNumberV(args[0]))) else 10;
    if (radix < 2 or radix > 36) return self.throwError("RangeError", "toString() radix must be between 2 and 36");
    if (big.bigint_text != null and radix == 10) return Value.str(big.bigint_text.?);
    if (big.bigint_text != null) return self.throwError("RangeError", "BigInt value is too large for non-decimal radix conversion");
    return Value.str(try formatBigIntRadix(self.arena, big.bigint, radix));
}

fn bigIntValueOfFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (this.isObject() and this.asObj().is_bigint) return this;
    // A BigInt wrapper object (`Object(1n)`) unwraps to its boxed BigInt.
    if (this.isObject() and this.asObj().prim != null and this.asObj().prim.?.isObject() and this.asObj().prim.?.asObj().is_bigint) return this.asObj().prim.?;
    return self.throwError("TypeError", "BigInt.prototype.valueOf requires that 'this' be a BigInt");
}

fn managedBigIntFromObject(arena: std.mem.Allocator, big: *value.Object) error{OutOfMemory}!std.math.big.int.Managed {
    var out = try std.math.big.int.Managed.init(arena);
    if (big.bigint_text) |s| {
        out.setString(10, s) catch |err| switch (err) {
            error.OutOfMemory => return error.OutOfMemory,
            else => unreachable,
        };
    } else {
        try out.set(big.bigint);
    }
    return out;
}

fn makeBigIntFromManaged(self: *Interpreter, managed: *const std.math.big.int.Managed) EvalError!Value {
    if (managed.toInt(i128)) |small| {
        return self.makeBigInt(small);
    } else |_| {}
    const text = managed.toString(self.arena, 10, .lower) catch |err| switch (err) {
        error.OutOfMemory => return error.OutOfMemory,
        else => unreachable,
    };
    return self.makeBigIntText(text);
}

pub fn negateBigIntObject(self: *Interpreter, big: *value.Object) EvalError!Value {
    if (big.bigint_text == null) return self.makeBigInt(-%big.bigint);
    var input = try managedBigIntFromObject(self.arena, big);
    input.negate();
    return makeBigIntFromManaged(self, &input);
}

pub fn bitNotBigIntObject(self: *Interpreter, big: *value.Object) EvalError!Value {
    if (big.bigint_text == null) return self.makeBigInt(~big.bigint);
    var input = try managedBigIntFromObject(self.arena, big);
    input.negate();
    var out = try std.math.big.int.Managed.init(self.arena);
    try out.addScalar(&input, -1);
    return makeBigIntFromManaged(self, &out);
}

/// `BigInt.asIntN(bits, x)` / `asUintN(bits, x)` — wrap into a 2's-complement
/// signed / unsigned `bits`-bit integer.
fn bigIntAsIntNFn(comptime signed: bool) value.NativeFn {
    return struct {
        fn call(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
            _ = this;
            const self: *Interpreter = @ptrCast(@alignCast(ctx));
            // ToIndex(bits) first (the Number coercion runs valueOf and rejects a
            // Symbol/BigInt), then ToBigInt(x) (which rejects a Number) — matching
            // the spec's step order.
            const bits_f = if (args.len > 0) try self.toNumberV(args[0]) else 0;
            const bits_int = if (std.math.isNan(bits_f)) 0 else @trunc(bits_f);
            if (bits_int < 0 or bits_int > 9007199254740991.0) return self.throwError("RangeError", "BigInt.asIntN bit count is out of range");
            const bits_count: u64 = @intFromFloat(bits_int);
            const xv = try self.toBigIntValueImpl(if (args.len > 1) args[1] else Value.undef(), false);
            if (bits_count == 0) return self.makeBigInt(if (signed) 0 else 0);
            const bit_count: usize = std.math.cast(usize, bits_count) orelse
                return self.throwError("RangeError", "BigInt.asIntN bit count is out of range");
            var input = try managedBigIntFromObject(self.arena, xv.asObj());
            var truncated = try std.math.big.int.Managed.init(self.arena);
            try truncated.truncate(&input, if (signed) .signed else .unsigned, bit_count);
            return makeBigIntFromManaged(self, &truncated);
        }
    }.call;
}

// ===== DataView =====================================================

/// ToIndex(v): ToIntegerOrInfinity, then RangeError outside [0, 2^53-1]. The
/// Number coercion runs valueOf/toString (so a Symbol/BigInt throws), matching
/// the spec's argument-coercion order.
fn toIndexArg(self: *Interpreter, v: Value) EvalError!u64 {
    if (v.isUndefined()) return 0;
    const n = try self.toNumberV(v);
    const i = if (std.math.isNan(n)) 0 else @trunc(n);
    if (i < 0 or i > 9007199254740991.0) return self.throwError("RangeError", "index out of range");
    return @intFromFloat(i);
}

const DVType = struct { name: []const u8, bytes: u8, signed: bool, float: bool, big: bool };
const dv_types = [_]DVType{
    .{ .name = "Int8", .bytes = 1, .signed = true, .float = false, .big = false },
    .{ .name = "Uint8", .bytes = 1, .signed = false, .float = false, .big = false },
    .{ .name = "Int16", .bytes = 2, .signed = true, .float = false, .big = false },
    .{ .name = "Uint16", .bytes = 2, .signed = false, .float = false, .big = false },
    .{ .name = "Int32", .bytes = 4, .signed = true, .float = false, .big = false },
    .{ .name = "Uint32", .bytes = 4, .signed = false, .float = false, .big = false },
    .{ .name = "Float16", .bytes = 2, .signed = true, .float = true, .big = false },
    .{ .name = "Float32", .bytes = 4, .signed = true, .float = true, .big = false },
    .{ .name = "Float64", .bytes = 8, .signed = true, .float = true, .big = false },
    .{ .name = "BigInt64", .bytes = 8, .signed = true, .float = false, .big = true },
    .{ .name = "BigUint64", .bytes = 8, .signed = false, .float = false, .big = true },
};

/// `new DataView(buffer, byteOffset?, byteLength?)`.
fn dataViewConstructorFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (self.new_target.isUndefined()) return self.throwError("TypeError", "Constructor DataView requires 'new'");
    const buf_v = if (args.len > 0) args[0] else Value.undef();
    if (!buf_v.isObject() or buf_v.asObj().array_buffer == null) return self.throwError("TypeError", "First argument to DataView must be an ArrayBuffer");
    const ab = buf_v.asObj().array_buffer.?;
    const offset = try toIndexArg(self, if (args.len > 1) args[1] else Value.undef());
    if (ab.detached) return self.throwError("TypeError", "ArrayBuffer is detached");
    const buf_len = ab.bytes().len;
    if (offset > buf_len) return self.throwError("RangeError", "Start offset is outside the bounds of the buffer");
    var view_len: usize = buf_len - @as(usize, @intCast(offset));
    // Omitting byteLength on a resizable buffer makes the view length-tracking.
    const track = (args.len <= 2 or args[2].isUndefined()) and ab.max_byte_length != null;
    if (args.len > 2 and !args[2].isUndefined()) {
        const vl = try toIndexArg(self, args[2]);
        if (ab.detached) return self.throwError("TypeError", "ArrayBuffer is detached");
        if (offset + vl > @as(u64, @intCast(ab.bytes().len))) return self.throwError("RangeError", "Invalid DataView length");
        view_len = @intCast(vl);
    }
    const o = (try self.newObject()).asObj();
    if (self.new_target.isObject()) o.proto = try self.ctorRealmIntrinsicProto(self.new_target.asObj(), "DataView");
    // The detached/out-of-bounds re-check after OrdinaryCreateFromConstructor is
    // spec'd: reading newTarget.prototype can run user code that detaches or
    // resizes the buffer.
    if (ab.detached) return self.throwError("TypeError", "ArrayBuffer is detached");
    const live_len = ab.bytes().len;
    if (offset > live_len) return self.throwError("RangeError", "Start offset is outside the bounds of the buffer");
    if (!track and offset + @as(u64, @intCast(view_len)) > @as(u64, @intCast(live_len)))
        return self.throwError("RangeError", "Invalid DataView length");
    const dv = try o.dataViewAllocator(self.arena).create(value.DataViewData);
    dv.* = .{ .buffer = buf_v.asObj(), .byte_offset = @intCast(offset), .byte_length = view_len, .track_length = track };
    o.data_view = dv;
    return Value.obj(o);
}

/// A `DataView.prototype.get<Type>(byteOffset, littleEndian)` accessor.
fn dataViewGetFn(comptime t: DVType) value.NativeFn {
    return struct {
        fn call(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
            const self: *Interpreter = @ptrCast(@alignCast(ctx));
            if (!this.isObject() or this.asObj().data_view == null) return self.throwError("TypeError", "DataView.prototype.get" ++ t.name ++ " requires a DataView receiver");
            const dv = this.asObj().data_view.?;
            const get_index = try toIndexArg(self, if (args.len > 0) args[0] else Value.undef());
            const little = if (args.len > 1) args[1].toBoolean() else false;
            const ab = dv.buffer.array_buffer.?;
            const view_len = dv.currentByteLength() orelse return self.throwError("TypeError", "DataView is detached or out of bounds");
            if (get_index + t.bytes > view_len) return self.throwError("RangeError", "Offset is outside the bounds of the DataView");
            const off = dv.byte_offset + @as(usize, @intCast(get_index));
            const endian: std.builtin.Endian = if (little) .little else .big;
            const UInt = switch (t.bytes) {
                1 => u8,
                2 => u16,
                4 => u32,
                else => u64,
            };
            const raw = std.mem.readInt(UInt, ab.bytes()[off..][0..t.bytes], endian);
            if (t.big) {
                if (t.signed) return self.makeBigInt(@as(i64, @bitCast(@as(u64, raw))));
                return self.makeBigInt(@as(i128, @as(u64, raw)));
            }
            if (t.float) {
                if (t.bytes == 2) return Value.num(@floatCast(@as(f16, @bitCast(@as(u16, raw)))));
                if (t.bytes == 4) return Value.num(@floatCast(@as(f32, @bitCast(@as(u32, raw)))));
                return Value.num(@bitCast(@as(u64, raw)));
            }
            if (t.signed) {
                const SInt = switch (t.bytes) {
                    1 => i8,
                    2 => i16,
                    4 => i32,
                    else => i64,
                };
                return Value.num(@floatFromInt(@as(SInt, @bitCast(raw))));
            }
            return Value.num(@floatFromInt(raw));
        }
    }.call;
}

/// A `DataView.prototype.set<Type>(byteOffset, value, littleEndian)` mutator.
fn dataViewSetFn(comptime t: DVType) value.NativeFn {
    return struct {
        fn call(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
            const self: *Interpreter = @ptrCast(@alignCast(ctx));
            if (!this.isObject() or this.asObj().data_view == null) return self.throwError("TypeError", "DataView.prototype.set" ++ t.name ++ " requires a DataView receiver");
            const dv = this.asObj().data_view.?;
            // SetViewValue checks IsImmutableBuffer before coercing the index/value.
            if (dv.buffer.array_buffer.?.immutable) return self.throwError("TypeError", "Cannot modify a DataView backed by an immutable ArrayBuffer");
            const get_index = try toIndexArg(self, if (args.len > 0) args[0] else Value.undef());
            const val = if (args.len > 1) args[1] else Value.undef();
            // Coerce the value (ToBigInt for the Big types, else ToNumber) before
            // the bounds/detach check, per SetViewValue.
            var num: f64 = 0;
            var big: i128 = 0;
            if (t.big) {
                const bv = try self.toBigIntValueImpl(val, false);
                big = bv.asObj().bigint;
            } else {
                num = try self.toNumberV(val);
            }
            const little = if (args.len > 2) args[2].toBoolean() else false;
            const ab = dv.buffer.array_buffer.?;
            const view_len = dv.currentByteLength() orelse return self.throwError("TypeError", "DataView is detached or out of bounds");
            if (get_index + t.bytes > view_len) return self.throwError("RangeError", "Offset is outside the bounds of the DataView");
            const off = dv.byte_offset + @as(usize, @intCast(get_index));
            const endian: std.builtin.Endian = if (little) .little else .big;
            const UInt = switch (t.bytes) {
                1 => u8,
                2 => u16,
                4 => u32,
                else => u64,
            };
            var raw: UInt = undefined;
            if (t.big) {
                raw = @truncate(@as(u128, @bitCast(big))); // low `bytes*8` bits (two's complement)
            } else if (t.float) {
                if (t.bytes == 2) {
                    raw = @bitCast(@as(f16, @floatCast(num)));
                } else if (t.bytes == 4) {
                    raw = @bitCast(@as(f32, @floatCast(num)));
                } else {
                    raw = @bitCast(num);
                }
            } else {
                raw = numToRaw(UInt, num);
            }
            std.mem.writeInt(UInt, ab.bytes()[off..][0..t.bytes], raw, endian);
            return Value.undef();
        }
    }.call;
}

/// ToIntXX/ToUintXX truncation for a DataView integer store (NaN/±Inf → 0, wrap
/// modulo 2^bits), returning the raw unsigned bit pattern.
fn numToRaw(comptime UInt: type, num: f64) UInt {
    if (std.math.isNan(num) or std.math.isInf(num)) return 0;
    const bits = @bitSizeOf(UInt);
    const two_pow: f64 = std.math.pow(f64, 2, @floatFromInt(bits));
    var m = @mod(@trunc(num), two_pow);
    if (m < 0) m += two_pow;
    return @intFromFloat(m);
}

fn dataViewBufferGetter(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject() or this.asObj().data_view == null) return self.throwError("TypeError", "DataView.prototype.buffer requires a DataView receiver");
    return Value.obj(this.asObj().data_view.?.buffer);
}

fn dataViewByteLengthGetter(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject() or this.asObj().data_view == null) return self.throwError("TypeError", "DataView.prototype.byteLength requires a DataView receiver");
    const dv = this.asObj().data_view.?;
    // get byteLength throws when the view is detached or out of bounds.
    const cur = dv.currentByteLength() orelse return self.throwError("TypeError", "DataView is detached or out of bounds");
    return Value.num(@floatFromInt(cur));
}

fn dataViewByteOffsetGetter(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject() or this.asObj().data_view == null) return self.throwError("TypeError", "DataView.prototype.byteOffset requires a DataView receiver");
    const dv = this.asObj().data_view.?;
    // get byteOffset throws when the view is detached or out of bounds.
    if (dv.currentByteLength() == null) return self.throwError("TypeError", "DataView is detached or out of bounds");
    return Value.num(@floatFromInt(dv.byte_offset));
}

/// Install `DataView` (constructor + prototype get/set accessors and methods).
// ===== Iterator + Iterator Helpers (ES2025) ==========================

/// Build a lazy iterator-helper object (`map`/`filter`/…) wrapping `src`.
fn makeIterHelper(self: *Interpreter, src: Value, kind: value.IterHelper.Kind, func: Value, limit: f64) EvalError!Value {
    const o = (try self.newObject()).asObj();
    const h = try gc_mod.allocIterHelper(self.arena);
    h.* = .{ .src = src, .kind = kind, .func = func, .limit = limit };
    // GetIteratorDirect: capture the source iterator's `next` method once at
    // creation (the concat/zip kinds hold an array of iterables, not a single
    // iterator, so they capture per-source instead).
    switch (kind) {
        .concat, .zip, .zip_keyed => {},
        else => if (src.isObject()) {
            h.next_method = try self.getProperty(src, "next");
        },
    }
    o.iter_helper = h;
    if (self.env.get("\x00IterHelperProto")) |p| if (p.isObject()) {
        o.proto = p.asObj();
    };
    return Value.obj(o);
}

/// `next` for a lazy iterator helper: pulls from the underlying iterator and
/// applies the helper's transform.
fn iterHelperNextFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject() or this.asObj().iter_helper == null) return self.throwError("TypeError", "Iterator Helper next called on an incompatible receiver");
    const h = this.asObj().iter_helper.?;
    // GeneratorValidate: re-entering an already-executing helper (e.g. its
    // mapper calls back into next()) is a TypeError, not a stack RangeError.
    if (h.running) return self.throwError("TypeError", "Iterator Helper is already running");
    if (h.done) return self.iterResultObj(Value.undef(), true);
    h.running = true;
    defer h.running = false;
    switch (h.kind) {
        .wrap => {
            const s = try self.iterStepM(h.src, h.next_method);
            if (s.done) {
                h.done = true;
                return self.iterResultObj(Value.undef(), true);
            }
            return self.iterResultObj(s.value, false);
        },
        .map => {
            const s = try self.iterStepM(h.src, h.next_method);
            if (s.done) {
                h.done = true;
                return self.iterResultObj(Value.undef(), true);
            }
            const mapped = self.callValueWithThis(h.func, &.{ s.value, Value.num(h.counter) }, Value.undef()) catch |e| {
                if (e == error.Throw) {
                    h.done = true;
                    self.iteratorCloseKeepingThrow(h.src);
                }
                return e;
            };
            h.counter += 1;
            return self.iterResultObj(mapped, false);
        },
        .filter => {
            while (true) {
                const s = try self.iterStepM(h.src, h.next_method);
                if (s.done) {
                    h.done = true;
                    return self.iterResultObj(Value.undef(), true);
                }
                const keep = (self.callValueWithThis(h.func, &.{ s.value, Value.num(h.counter) }, Value.undef()) catch |e| {
                    if (e == error.Throw) {
                        h.done = true;
                        self.iteratorCloseKeepingThrow(h.src);
                    }
                    return e;
                }).toBoolean();
                h.counter += 1;
                if (keep) return self.iterResultObj(s.value, false);
            }
        },
        .take => {
            if (h.counter >= h.limit) {
                h.done = true;
                // Reaching the limit closes the underlying iterator (IteratorClose).
                try self.iteratorClose(h.src);
                return self.iterResultObj(Value.undef(), true);
            }
            const s = try self.iterStepM(h.src, h.next_method);
            if (s.done) {
                h.done = true;
                return self.iterResultObj(Value.undef(), true);
            }
            h.counter += 1;
            return self.iterResultObj(s.value, false);
        },
        .drop => {
            if (!h.started) {
                h.started = true;
                while (h.counter < h.limit) : (h.counter += 1) {
                    const s = try self.iterStepM(h.src, h.next_method);
                    if (s.done) {
                        h.done = true;
                        return self.iterResultObj(Value.undef(), true);
                    }
                }
            }
            const s = try self.iterStepM(h.src, h.next_method);
            if (s.done) {
                h.done = true;
                return self.iterResultObj(Value.undef(), true);
            }
            return self.iterResultObj(s.value, false);
        },
        .flat_map => {
            while (true) {
                if (h.inner == null) {
                    const s = try self.iterStepM(h.src, h.next_method);
                    if (s.done) {
                        h.done = true;
                        return self.iterResultObj(Value.undef(), true);
                    }
                    const mapped = self.callValueWithThis(h.func, &.{ s.value, Value.num(h.counter) }, Value.undef()) catch |e| {
                        if (e == error.Throw) {
                            h.done = true;
                            self.iteratorCloseKeepingThrow(h.src);
                        }
                        return e;
                    };
                    h.counter += 1;
                    // GetIteratorFlattenable(mapped, reject-primitives): a primitive
                    // (including a primitive string) is a TypeError; an abrupt
                    // completion closes the source iterator.
                    h.inner = self.getIteratorFlattenableObj(mapped) catch |e| {
                        if (e == error.Throw) {
                            h.done = true;
                            self.iteratorCloseKeepingThrow(h.src);
                        }
                        return e;
                    };
                    h.inner_next = if (h.inner.?.isObject()) try self.getProperty(h.inner.?, "next") else Value.undef();
                }
                const is = try self.iterStepM(h.inner.?, h.inner_next);
                if (is.done) {
                    h.inner = null;
                    continue;
                }
                return self.iterResultObj(is.value, false);
            }
        },
        .concat => {
            // `h.src` is a JS array of the source iterables; `counter` is the next
            // source index and `inner` the iterator currently being drained.
            h.started = true; // the generator has run (→ "suspended-yield")
            const srcs = h.src.asObj();
            while (true) {
                if (h.inner == null) {
                    const idx: usize = @intFromFloat(h.counter);
                    if (idx >= srcs.elements.items.len) {
                        h.done = true;
                        return self.iterResultObj(Value.undef(), true);
                    }
                    h.counter += 1;
                    // Open the source with its pre-captured @@iterator method.
                    const it = try self.callValueWithThis(h.func.asObj().elements.items[idx], &.{}, srcs.elements.items[idx]);
                    if (!it.isObject()) return self.throwError("TypeError", "Iterator.concat: @@iterator did not return an object");
                    h.inner = it;
                }
                const is = try self.iterStep(h.inner.?);
                if (is.done) {
                    h.inner = null;
                    continue;
                }
                return self.iterResultObj(is.value, false);
            }
        },
        .zip, .zip_keyed => {
            // `src` = opened iterators; `inner` = per-source removed flags (true =
            // openIters[i] is null); `limit` = mode (0 shortest, 1 longest, 2
            // strict); `padding` = per-source padding (longest); `func` = key
            // array (zip_keyed). Implements the IteratorZip abstract closure.
            h.started = true; // the generator has run (→ "suspended-yield")
            const iters = h.src.asObj().elements.items;
            const flags = h.inner.?.asObj();
            const n = iters.len;
            if (n == 0) {
                h.done = true;
                return self.iterResultObj(Value.undef(), true);
            }
            const mode: u8 = @intFromFloat(h.limit);
            const results = (try self.newArray()).asObj();
            try results.elements.ensureTotalCapacity(results.elementsAllocator(self.arena), n);
            var i: usize = 0;
            while (i < n) : (i += 1) {
                if (flags.elements.items[i].toBoolean()) {
                    // openIters[i] is null — longest padding.
                    const pad = if (h.padding.isObject() and i < h.padding.asObj().elements.items.len) h.padding.asObj().elements.items[i] else Value.undef();
                    try results.elements.append(results.elementsAllocator(self.arena), pad);
                    continue;
                }
                // IteratorStepValue(openIters[i]); an abrupt completion closes the
                // remaining open iterators (reverse order) and propagates.
                const s = self.iterStep(iters[i]) catch {
                    flags.elements.items[i] = Value.boolVal(true);
                    h.done = true;
                    try zipCloseAll(self, iters, flags, true);
                    return error.Throw;
                };
                if (!s.done) {
                    try results.elements.append(results.elementsAllocator(self.arena), s.value);
                    continue;
                }
                // The source is done — remove it from openIters.
                flags.elements.items[i] = Value.boolVal(true);
                switch (mode) {
                    0 => { // shortest: close the rest and finish.
                        h.done = true;
                        try zipCloseAll(self, iters, flags, false);
                        return self.iterResultObj(Value.undef(), true);
                    },
                    2 => { // strict: every source must end together.
                        h.done = true;
                        if (i != 0) {
                            self.exception = try self.makeError("TypeError", "Iterator.zip: strict mode requires all iterators to have the same length");
                            try zipCloseAll(self, iters, flags, true);
                            return error.Throw;
                        }
                        // i == 0: each remaining source must also be done now.
                        var k: usize = 1;
                        while (k < n) : (k += 1) {
                            if (flags.elements.items[k].toBoolean()) continue;
                            const kdone = self.iterStepDoneOnly(iters[k]) catch {
                                flags.elements.items[k] = Value.boolVal(true);
                                try zipCloseAll(self, iters, flags, true);
                                return error.Throw;
                            };
                            if (!kdone) {
                                self.exception = try self.makeError("TypeError", "Iterator.zip: strict mode requires all iterators to have the same length");
                                try zipCloseAll(self, iters, flags, true);
                                return error.Throw;
                            }
                            flags.elements.items[k] = Value.boolVal(true);
                        }
                        return self.iterResultObj(Value.undef(), true);
                    },
                    else => { // longest: pad this slot and continue.
                        const pad = if (h.padding.isObject() and i < h.padding.asObj().elements.items.len) h.padding.asObj().elements.items[i] else Value.undef();
                        try results.elements.append(results.elementsAllocator(self.arena), pad);
                    },
                }
            }
            // Longest mode: finish once every source has been removed.
            var all_null = true;
            for (flags.elements.items[0..n]) |f| {
                if (!f.toBoolean()) {
                    all_null = false;
                    break;
                }
            }
            if (all_null) {
                h.done = true;
                return self.iterResultObj(Value.undef(), true);
            }
            if (h.kind == .zip) return self.iterResultObj(Value.obj(results), false);
            // zip_keyed: OrdinaryObjectCreate(null) with one data property per
            // key (CreateDataPropertyOrThrow → writable/enumerable/configurable).
            const keys = h.func.asObj().elements.items;
            const obj = (try self.newObject()).asObj();
            obj.proto = null;
            var k: usize = 0;
            while (k < keys.len and k < results.elements.items.len) : (k += 1) {
                try self.setProp(obj, keys[k].asStr(), results.elements.items[k]);
            }
            return self.iterResultObj(Value.obj(obj), false);
        },
    }
}

/// IteratorCloseAll(openIters, completion): close every non-removed iterator in
/// reverse list order. When `pending` is true a throw completion is already in
/// flight (its value in `self.exception`) — any error from a `return()` call is
/// swallowed and the original throw re-raised. When false the completion is
/// normal — the first close error becomes the completion and is raised.
fn zipCloseAll(self: *Interpreter, iters: []Value, flags: *value.Object, pending: bool) EvalError!void {
    var thrown = pending;
    var pending_val: Value = if (pending) self.exception else Value.undef();
    var i: usize = iters.len;
    while (i > 0) {
        i -= 1;
        if (i < flags.elements.items.len and flags.elements.items[i].toBoolean()) continue;
        if (thrown) {
            self.iteratorClose(iters[i]) catch {};
            self.exception = pending_val; // a throw completion discards close errors
        } else {
            self.iteratorClose(iters[i]) catch {
                thrown = true;
                pending_val = self.exception;
            };
        }
    }
    if (thrown) {
        self.exception = pending_val;
        return error.Throw;
    }
}

fn iterHelperReturnFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject() or this.asObj().iter_helper == null)
        return self.throwError("TypeError", "Iterator Helper return called on an incompatible receiver");
    const h = this.asObj().iter_helper.?;
    // GeneratorValidate: a re-entrant return() while the helper is mid-close
    // (state "executing") is a TypeError.
    if (h.running) return self.throwError("TypeError", "Iterator Helper is already running");
    const was_done = h.done;
    h.done = true;
    // A WrapForValidIterator forwards return() to its underlying iterator and
    // returns THAT result (or {undefined, done:true} when there is no return()).
    if (h.kind == .wrap) {
        if (was_done or !h.src.isObject()) return self.iterResultObj(Value.undef(), true);
        const ret = try self.getProperty(h.src, "return");
        if (ret.isUndefined() or ret.isNull()) return self.iterResultObj(Value.undef(), true);
        if (!ret.isCallable()) return self.throwError("TypeError", "iterator return is not callable");
        return try self.callValueWithThis(ret, &.{}, h.src);
    }
    // An IteratorHelper closes its source iterator(s) and yields {undefined, done}.
    if (!was_done) {
        switch (h.kind) {
            // zip closes every still-open source via IteratorCloseAll (reverse
            // order, normal completion → a return() error propagates). The
            // `running` guard makes a re-entrant next() from a source's return()
            // a TypeError (GeneratorValidate sees the "executing" state).
            .zip, .zip_keyed => {
                if (h.src.isObject() and h.inner != null and h.inner.?.isObject()) {
                    // "suspended-yield" (already started) → state is "executing"
                    // during the close, so a re-entrant call throws TypeError.
                    // "suspended-start" (never stepped) → state is "completed",
                    // so a re-entrant call just returns {undefined, done:true}.
                    h.running = h.started;
                    defer h.running = false;
                    try zipCloseAll(self, h.src.asObj().elements.items, h.inner.?.asObj(), false);
                }
                return self.iterResultObj(Value.undef(), true);
            },
            // concat closes the iterator it is currently draining; the running
            // guard makes a re-entrant return() from that close a TypeError.
            .concat => {
                if (h.inner) |inner| if (inner.isObject() and inner.asObj().iter_helper == null) {
                    h.running = h.started;
                    defer h.running = false;
                    try self.iteratorClose(inner);
                };
                return self.iterResultObj(Value.undef(), true);
            },
            else => if (h.src.isObject()) try self.iteratorClose(h.src),
        }
        if (h.inner) |inner| if (inner.isObject() and inner.asObj().iter_helper == null) try self.iteratorClose(inner);
    }
    return self.iterResultObj(Value.undef(), true);
}

// --- the lazy helper methods on %Iterator.prototype% -----------------

fn iterMapFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject()) return self.throwError("TypeError", "Iterator.prototype.map called on a non-object");
    const f = if (args.len > 0) args[0] else Value.undef();
    if (!f.isCallable()) {
        self.iteratorClose(this) catch {};
        return self.throwError("TypeError", "Iterator.prototype.map: mapper is not a function");
    }
    return makeIterHelper(self, this, .map, f, 0);
}
fn iterFilterFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject()) return self.throwError("TypeError", "Iterator.prototype.filter called on a non-object");
    const f = if (args.len > 0) args[0] else Value.undef();
    if (!f.isCallable()) {
        self.iteratorClose(this) catch {};
        return self.throwError("TypeError", "Iterator.prototype.filter: predicate is not a function");
    }
    return makeIterHelper(self, this, .filter, f, 0);
}
fn iterFlatMapFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject()) return self.throwError("TypeError", "Iterator.prototype.flatMap called on a non-object");
    const f = if (args.len > 0) args[0] else Value.undef();
    if (!f.isCallable()) {
        self.iteratorClose(this) catch {};
        return self.throwError("TypeError", "Iterator.prototype.flatMap: mapper is not a function");
    }
    return makeIterHelper(self, this, .flat_map, f, 0);
}
/// Validate the `limit`/`count` argument of take/drop: ToNumber (closing `this`
/// on an abrupt completion), then ToIntegerOrInfinity, requiring NaN→RangeError
/// and a non-negative result (the truncation happens before the `< 0` check, so
/// `-0.5` yields 0, not a RangeError). Closes `this` before any RangeError.
fn iterLimitArg(self: *Interpreter, this: Value, arg_v: Value, comptime who: []const u8) EvalError!f64 {
    const n = self.toNumberV(arg_v) catch |e| {
        if (e == error.Throw) self.iteratorCloseKeepingThrow(this);
        return e;
    };
    if (std.math.isNan(n)) {
        self.iteratorClose(this) catch {};
        return self.throwError("RangeError", who ++ ": invalid count");
    }
    const lim = @trunc(n); // ToIntegerOrInfinity (-0.5 → -0, which is not < 0)
    if (lim < 0) {
        self.iteratorClose(this) catch {};
        return self.throwError("RangeError", who ++ ": invalid count");
    }
    return lim;
}
fn iterTakeFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject()) return self.throwError("TypeError", "Iterator.prototype.take called on a non-object");
    const lim = try iterLimitArg(self, this, if (args.len > 0) args[0] else Value.undef(), "Iterator.prototype.take");
    return makeIterHelper(self, this, .take, Value.undef(), lim);
}
fn iterDropFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject()) return self.throwError("TypeError", "Iterator.prototype.drop called on a non-object");
    const lim = try iterLimitArg(self, this, if (args.len > 0) args[0] else Value.undef(), "Iterator.prototype.drop");
    return makeIterHelper(self, this, .drop, Value.undef(), lim);
}

// --- the eager helper methods (consume `this`) -----------------------

fn iterToArrayFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject()) return self.throwError("TypeError", "Iterator.prototype.toArray called on a non-object");
    // GetIteratorDirect captures `next` once (a `next` accessor runs a single time).
    const next_method = try self.getProperty(this, "next");
    const arr = (try self.newArray()).asObj();
    while (true) {
        const s = try self.iterStepM(this, next_method);
        if (s.done) break;
        try arr.elements.append(arr.elementsAllocator(self.arena), s.value);
    }
    return Value.obj(arr);
}
fn iterForEachFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject()) return self.throwError("TypeError", "Iterator.prototype.forEach called on a non-object");
    const f = if (args.len > 0) args[0] else Value.undef();
    if (!f.isCallable()) {
        self.iteratorClose(this) catch {};
        return self.throwError("TypeError", "Iterator.prototype.forEach: fn is not a function");
    }
    const next_method = try self.getProperty(this, "next");
    var i: f64 = 0;
    while (true) : (i += 1) {
        const s = try self.iterStepM(this, next_method);
        if (s.done) break;
        _ = self.callValueWithThis(f, &.{ s.value, Value.num(i) }, Value.undef()) catch |e| {
            if (e == error.Throw) self.iteratorCloseKeepingThrow(this);
            return e;
        };
    }
    return Value.undef();
}
fn iterReduceFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject()) return self.throwError("TypeError", "Iterator.prototype.reduce called on a non-object");
    const f = if (args.len > 0) args[0] else Value.undef();
    if (!f.isCallable()) {
        self.iteratorClose(this) catch {};
        return self.throwError("TypeError", "Iterator.prototype.reduce: reducer is not a function");
    }
    const next_method = try self.getProperty(this, "next");
    var acc: Value = undefined;
    var i: f64 = 0;
    if (args.len > 1) {
        acc = args[1];
    } else {
        const s = try self.iterStepM(this, next_method);
        if (s.done) return self.throwError("TypeError", "Reduce of empty iterator with no initial value");
        acc = s.value;
        i = 1;
    }
    while (true) : (i += 1) {
        const s = try self.iterStepM(this, next_method);
        if (s.done) break;
        acc = self.callValueWithThis(f, &.{ acc, s.value, Value.num(i) }, Value.undef()) catch |e| {
            if (e == error.Throw) self.iteratorCloseKeepingThrow(this);
            return e;
        };
    }
    return acc;
}
fn iterSomeEveryFindFn(comptime which: enum { some, every, find }) value.NativeFn {
    return struct {
        fn call(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
            const self: *Interpreter = @ptrCast(@alignCast(ctx));
            if (!this.isObject()) return self.throwError("TypeError", "Iterator.prototype method called on a non-object");
            const f = if (args.len > 0) args[0] else Value.undef();
            if (!f.isCallable()) {
                // IteratorClose(O, ThrowCompletion): a non-callable predicate
                // closes the underlying iterator before the TypeError propagates.
                self.iteratorClose(this) catch {};
                return self.throwError("TypeError", "Iterator.prototype method: fn is not a function");
            }
            const next_method = try self.getProperty(this, "next");
            var i: f64 = 0;
            while (true) : (i += 1) {
                const s = try self.iterStepM(this, next_method);
                if (s.done) break;
                const tv = self.callValueWithThis(f, &.{ s.value, Value.num(i) }, Value.undef()) catch |e| {
                    if (e == error.Throw) self.iteratorCloseKeepingThrow(this);
                    return e;
                };
                const t = tv.toBoolean();
                switch (which) {
                    .some => if (t) {
                        try self.iteratorClose(this);
                        return Value.boolVal(true);
                    },
                    .every => if (!t) {
                        try self.iteratorClose(this);
                        return Value.boolVal(false);
                    },
                    .find => if (t) {
                        try self.iteratorClose(this);
                        return s.value;
                    },
                }
            }
            return switch (which) {
                .some => Value.boolVal(false),
                .every => Value.boolVal(true),
                .find => Value.undef(),
            };
        }
    }.call;
}

fn iterProtoSymbolIteratorFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = ctx;
    _ = args;
    return this; // %IteratorPrototype%[@@iterator] returns the iterator itself
}

/// %IteratorPrototype%[@@dispose]: call `this.return()` (if present); undefined.
fn iterProtoDisposeFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const ret = try self.getProperty(this, "return");
    if (ret.isObject() and ret.asObj().isCallableObject()) _ = try self.callValueWithThis(ret, &.{}, this);
    return Value.undef();
}

/// %AsyncIteratorPrototype%[@@asyncDispose]: a promise that calls (and awaits)
/// `this.return()` if present, then fulfills with undefined.
fn asyncIterProtoDisposeFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const pobj = try promise.newPromise(self);
    const p = promise.promiseOf(Value.obj(pobj)).?;
    const ret = self.getProperty(this, "return") catch {
        promise.reject(self, p, self.exception) catch {};
        return Value.obj(pobj);
    };
    if (ret.isObject() and ret.asObj().isCallableObject()) {
        const r = self.callValueWithThis(ret, &.{}, this) catch {
            promise.reject(self, p, self.exception) catch {};
            return Value.obj(pobj);
        };
        _ = self.awaitValue(r) catch {
            promise.reject(self, p, self.exception) catch {};
            return Value.obj(pobj);
        };
    }
    promise.resolve(self, p, Value.undef()) catch {};
    return Value.obj(pobj);
}

/// Install a well-known-symbol-keyed method whose `name` is the spec display
/// form (e.g. "[Symbol.dispose]") rather than the encoded key.
fn installSymbolMethod(a: std.mem.Allocator, rs: *Shape, obj: *value.Object, key: []const u8, display: []const u8, len: usize, f: value.NativeFn) EvalError!void {
    try setNative(a, rs, obj, key, len, f);
    if (obj.getOwn(key)) |mv| if (mv.isObject()) {
        try mv.asObj().setOwn(a, rs, "name", Value.str(display));
        try mv.asObj().setAttr(a, "name", .{ .writable = false, .enumerable = false, .configurable = true });
    };
}

/// `Iterator.from(O)`: wrap an iterator/iterable so the helper methods apply.
fn iteratorFromFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const o = if (args.len > 0) args[0] else Value.undef();
    // GetIteratorFlattenable(O, iterate-string-primitives): among primitives only a
    // String is accepted (Symbol/BigInt are object-boxed here, so reject them too).
    if (!o.isObject()) {
        if (!o.isString()) return self.throwError("TypeError", "Iterator.from: argument is not iterable");
    } else if (o.asObj().is_symbol or o.asObj().is_bigint) {
        return self.throwError("TypeError", "Iterator.from: argument is not iterable");
    }
    // method = GetMethod(O, @@iterator): an undefined method means O is itself the
    // iterator; otherwise Call(method, O) yields the iterator. Reads run getters in
    // spec order (@@iterator before next).
    var iterator: Value = o;
    if (self.wellKnownSymbolKey("iterator")) |ikey| {
        const method = try self.getProperty(o, ikey);
        if (!method.isUndefined() and !method.isNull()) {
            if (!method.isCallable()) return self.throwError("TypeError", "Iterator.from: @@iterator is not callable");
            iterator = try self.callValueWithThis(method, &.{}, o);
        }
    }
    if (!iterator.isObject() or iterator.asObj().is_symbol or iterator.asObj().is_bigint)
        return self.throwError("TypeError", "Iterator.from: the iterator is not an object");
    // If the iterator already inherits from %Iterator.prototype%, return it as-is;
    // otherwise wrap it (WrapForValidIteratorPrototype).
    if (self.env.get("Iterator")) |ic| if (ic.isObject()) {
        if (ic.asObj().getOwn("prototype")) |ip| if (ip.isObject()) {
            var cur: ?*value.Object = iterator.asObj().proto;
            while (cur) |c| : (cur = c.proto) if (c == ip.asObj()) return iterator;
        };
    };
    return makeIterHelper(self, iterator, .wrap, Value.undef(), 0);
}

/// `Iterator.concat(...items)` — an iterator yielding all values of each
/// iterable argument in order. Each argument must be an iterable object.
fn iteratorConcatFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const srcs = (try self.newArray()).asObj();
    const methods = (try self.newArray()).asObj();
    const ikey = self.wellKnownSymbolKey("iterator") orelse "";
    // Validate every argument up front, in order: each must be an Object whose
    // @@iterator (GetMethod, read exactly once now) is callable.
    for (args) |arg_v| {
        if (!arg_v.isObject()) return self.throwError("TypeError", "Iterator.concat: each argument must be an object");
        const method = try self.getProperty(arg_v, ikey);
        if (method.isUndefined() or method.isNull() or !method.isCallable())
            return self.throwError("TypeError", "Iterator.concat: each argument must have a callable @@iterator");
        try srcs.elements.append(srcs.elementsAllocator(self.arena), arg_v);
        try methods.elements.append(methods.elementsAllocator(self.arena), method);
    }
    // The captured @@iterator methods ride in `func` for the .concat consumer.
    return makeIterHelper(self, Value.obj(srcs), .concat, Value.obj(methods), 0);
}

/// Read the shared `{ mode, padding }` options of `Iterator.zip`/`zipKeyed`.
/// Returns the mode (0 shortest, 1 longest, 2 strict). `padding_out` receives
/// the raw `padding` value (undefined if absent or mode != longest).
fn zipReadMode(self: *Interpreter, options: Value, padding_out: *Value) EvalError!u8 {
    padding_out.* = Value.undef();
    if (options.isUndefined()) return 0;
    if (!options.isObject() or options.asObj().is_bigint or options.asObj().is_symbol)
        return self.throwError("TypeError", "Iterator.zip: options must be an object");
    const mv = try self.getProperty(options, "mode");
    var mode: u8 = 0;
    if (!mv.isUndefined()) {
        // The mode is compared by value (no ToString): only the primitive
        // strings "shortest"/"longest"/"strict" are accepted.
        if (!mv.isString()) return self.throwError("TypeError", "Iterator.zip: mode must be 'shortest', 'longest', or 'strict'");
        const ms = mv.asStr();
        if (std.mem.eql(u8, ms, "shortest")) {
            mode = 0;
        } else if (std.mem.eql(u8, ms, "longest")) {
            mode = 1;
        } else if (std.mem.eql(u8, ms, "strict")) {
            mode = 2;
        } else return self.throwError("TypeError", "Iterator.zip: mode must be 'shortest', 'longest', or 'strict'");
    }
    if (mode == 1) padding_out.* = try self.getProperty(options, "padding");
    return mode;
}

/// `Iterator.zip(iterables[, options])` — yields arrays of one value pulled
/// from each input iterable per step. Modes: shortest (default), longest
/// (pad), strict (equal lengths required).
fn iteratorZipFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const iterables = if (args.len > 0) args[0] else Value.undef();
    if (!iterables.isObject() or iterables.asObj().is_bigint or iterables.asObj().is_symbol)
        return self.throwError("TypeError", "Iterator.zip: iterables must be an object");
    var padding: Value = Value.undef();
    const mode = try zipReadMode(self, if (args.len > 1) args[1] else Value.undef(), &padding);

    // GetIterator(iterables, sync): a strict `@@iterator` lookup (no array-like
    // fallback). Then drain it, flattening each yielded value into an iterator.
    const iters = (try self.newArray()).asObj();
    const ik = self.symbolIteratorKey();
    const method: Value = if (ik) |k| try self.getProperty(iterables, k) else Value.undef();
    if (method.isUndefined() or method.isNull() or !method.isObject() or !method.asObj().isCallableObject())
        return self.throwError("TypeError", "Iterator.zip: iterables is not iterable");
    const input_iter = try self.callValueWithThis(method, &.{}, iterables);
    if (!input_iter.isObject()) return self.throwError("TypeError", "Iterator.zip: iterator is not an object");
    const next_method = try self.getProperty(input_iter, "next");
    if (!next_method.isObject() or !next_method.asObj().isCallableObject())
        return self.throwError("TypeError", "Iterator.zip: iterator.next is not callable");
    while (true) {
        // IteratorStepValue(inputIter). An abrupt completion runs
        // IfAbruptCloseIterators(next, iters): close every opened input (reverse
        // order) but NOT inputIter, then re-raise.
        const r = self.callValueWithThis(next_method, &.{}, input_iter) catch {
            self.closeListKeepingThrow(iters.elements.items);
            return error.Throw;
        };
        if (!r.isObject()) {
            self.exception = try self.makeError("TypeError", "Iterator.zip: iterator result is not an object");
            self.closeListKeepingThrow(iters.elements.items);
            return error.Throw;
        }
        const dn = (self.getProperty(r, "done") catch {
            self.closeListKeepingThrow(iters.elements.items);
            return error.Throw;
        }).toBoolean();
        if (dn) break;
        const item = self.getProperty(r, "value") catch {
            self.closeListKeepingThrow(iters.elements.items);
            return error.Throw;
        };
        // GetIteratorFlattenable(item) abrupt → IfAbruptCloseIterators over the
        // list-concatenation « inputIter » ++ iters (reverse): iters then input.
        const sub = self.getIteratorFlattenableObj(item) catch {
            self.closeListKeepingThrow(iters.elements.items);
            self.iteratorCloseKeepingThrow(input_iter);
            return error.Throw;
        };
        try iters.elements.append(iters.elementsAllocator(self.arena), sub);
    }
    // Per-source padding aligned to iterator order (longest mode only): pull
    // exactly `iterCount` values from the padding iterable, padding short. Any
    // abrupt completion here closes the opened inputs (reverse) and re-raises.
    const pad_arr = buildZipPadding(self, mode, padding, iters.elements.items.len) catch {
        self.closeListKeepingThrow(iters.elements.items);
        return error.Throw;
    };
    return makeZipHelper(self, .zip, iters, Value.undef(), mode, pad_arr);
}

/// `Iterator.zipKeyed(iterables[, options])` — like zip but `iterables` is an
/// object whose own enumerable keys name the inputs; each step yields an object.
fn iteratorZipKeyedFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const iterables = if (args.len > 0) args[0] else Value.undef();
    if (!iterables.isObject() or iterables.asObj().is_bigint or iterables.asObj().is_symbol)
        return self.throwError("TypeError", "Iterator.zipKeyed: iterables must be an object");
    var padding: Value = Value.undef();
    const mode = try zipReadMode(self, if (args.len > 1) args[1] else Value.undef(), &padding);
    // Longest-mode padding must be undefined or an Object (validated up front,
    // independent of how many keys `iterables` has).
    if (mode == 1 and !padding.isUndefined() and (!padding.isObject() or padding.asObj().is_bigint or padding.asObj().is_symbol))
        return self.throwError("TypeError", "Iterator.zipKeyed: padding must be an object");

    const keys = (try self.newArray()).asObj();
    const iters = (try self.newArray()).asObj();
    // [[OwnPropertyKeys]] snapshot, then per key: [[GetOwnProperty]] (enumerable
    // check), [[Get]] (value), GetIteratorFlattenable. Both string and symbol
    // keys participate. An abrupt completion closes opened inputs (reverse).
    const all_keys = try self.objectOwnKeysList(iterables.asObj());
    for (all_keys) |key| {
        const en = self.objectProtoPropertyIsEnumerable(iterables.asObj(), key) catch {
            self.closeListKeepingThrow(iters.elements.items);
            return error.Throw;
        };
        if (!en) continue;
        const v = self.getProperty(iterables, key) catch {
            self.closeListKeepingThrow(iters.elements.items);
            return error.Throw;
        };
        // An `undefined` value excludes the key entirely (no result property).
        if (v.isUndefined()) continue;
        const sub = self.getIteratorFlattenableObj(v) catch {
            self.closeListKeepingThrow(iters.elements.items);
            return error.Throw;
        };
        try keys.elements.append(keys.elementsAllocator(self.arena), Value.str(key));
        try iters.elements.append(iters.elementsAllocator(self.arena), sub);
    }
    // Per-key padding (longest mode): Get(padding, key) for each key, or all
    // undefined when padding is absent.
    var pad_arr: Value = Value.undef();
    if (mode == 1) {
        const pads = (try self.newArray()).asObj();
        for (keys.elements.items) |kv| {
            if (padding.isObject()) {
                const pv = self.getProperty(padding, kv.asStr()) catch {
                    self.closeListKeepingThrow(iters.elements.items);
                    return error.Throw;
                };
                try pads.elements.append(pads.elementsAllocator(self.arena), pv);
            } else try pads.elements.append(pads.elementsAllocator(self.arena), Value.undef());
        }
        pad_arr = Value.obj(pads);
    }
    return makeZipHelper(self, .zip_keyed, iters, Value.obj(keys), mode, pad_arr);
}

/// Build the per-source padding list for `Iterator.zip` longest mode: pull
/// exactly `n` values from the padding iterable (`reject-primitives`), padding
/// any shortfall with undefined and closing the iterator if not exhausted.
/// Returns `Value.undef()` for non-longest modes or an n-length array otherwise.
fn buildZipPadding(self: *Interpreter, mode: u8, padding: Value, n: usize) EvalError!Value {
    if (mode != 1) return Value.undef();
    const pads = (try self.newArray()).asObj();
    if (padding.isUndefined()) {
        var i: usize = 0;
        while (i < n) : (i += 1) try pads.elements.append(pads.elementsAllocator(self.arena), Value.undef());
        return Value.obj(pads);
    }
    if (!padding.isObject() or padding.asObj().is_bigint or padding.asObj().is_symbol)
        return self.throwError("TypeError", "Iterator.zip: padding must be an object");
    // GetIterator(padding, sync): strict — a missing @@iterator is a TypeError.
    const ik = self.symbolIteratorKey();
    const method: Value = if (ik) |k| try self.getProperty(padding, k) else Value.undef();
    if (method.isUndefined() or method.isNull() or !method.isObject() or !method.asObj().isCallableObject())
        return self.throwError("TypeError", "Iterator.zip: padding is not iterable");
    const pit = try self.callValueWithThis(method, &.{}, padding);
    if (!pit.isObject()) return self.throwError("TypeError", "Iterator.zip: padding iterator is not an object");
    // GetIteratorDirect captures `next` once (so an accessor runs a single time).
    const pnext = try self.getProperty(pit, "next");
    var exhausted = false;
    var i: usize = 0;
    while (i < n) : (i += 1) {
        if (exhausted) {
            try pads.elements.append(pads.elementsAllocator(self.arena), Value.undef());
            continue;
        }
        const s = try self.iterStepM(pit, pnext);
        if (s.done) {
            exhausted = true;
            try pads.elements.append(pads.elementsAllocator(self.arena), Value.undef());
        } else try pads.elements.append(pads.elementsAllocator(self.arena), s.value);
    }
    // Close the padding iterator (normal completion) if it still has values.
    if (!exhausted) try self.iteratorClose(pit);
    return Value.obj(pads);
}

/// Build a zip/zipKeyed iterator-helper object with its per-source done flags.
fn makeZipHelper(self: *Interpreter, kind: value.IterHelper.Kind, iters: *value.Object, keys: Value, mode: u8, padding: Value) EvalError!Value {
    const flags = (try self.newArray()).asObj();
    for (iters.elements.items) |_| try flags.elements.append(flags.elementsAllocator(self.arena), Value.boolVal(false));
    const o = (try self.newObject()).asObj();
    const h = try gc_mod.allocIterHelper(self.arena);
    h.* = .{ .src = Value.obj(iters), .kind = kind, .func = keys, .limit = @floatFromInt(mode), .inner = Value.obj(flags), .padding = padding };
    o.iter_helper = h;
    if (self.env.get("\x00IterHelperProto")) |p| if (p.isObject()) {
        o.proto = p.asObj();
    };
    return Value.obj(o);
}

/// `Iterator` is abstract — `new Iterator()` directly throws.
fn iteratorConstructorFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (self.new_target.isUndefined()) return self.throwError("TypeError", "Constructor Iterator requires 'new'");
    // Abstract: cannot be constructed unless subclassed (new.target !== Iterator).
    if (self.new_target.isObject()) {
        if (self.env.get("Iterator")) |ic| if (ic.isObject() and self.new_target.asObj() == ic.asObj())
            return self.throwError("TypeError", "Abstract class Iterator not directly constructable");
    }
    const o = (try self.newObject()).asObj();
    o.proto = try self.ctorRealmIntrinsicProto(self.new_target.asObj(), "Iterator");
    return Value.obj(o);
}

/// Install `%IteratorPrototype%`, `%IteratorHelperPrototype%`, the `Iterator`
/// global, and `Iterator.from`.
/// `%GeneratorPrototype%`.next/return/throw (and the async variants): brand-check
/// a generator receiver and drive it. Normal `gen.next()` uses the callMethod
/// fast path; these exist as real own properties for reflection / `.call`.
fn genProtoMethod(comptime which: enum { next, ret, throw }) value.NativeFn {
    return struct {
        fn call(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
            const self: *Interpreter = @ptrCast(@alignCast(ctx));
            if (!this.isObject() or this.asObj().gen == null)
                return self.throwError("TypeError", "method called on an incompatible receiver");
            const v: Value = if (args.len > 0) args[0] else Value.undef();
            return switch (which) {
                .next => vm.genNext(self, this.asObj(), v),
                .ret => vm.genReturn(self, this.asObj(), v),
                .throw => vm.genThrow(self, this.asObj(), v),
            };
        }
    }.call;
}

/// Async-generator next/return/throw: unlike the sync forms, a bad receiver
/// (not an async generator) yields a *rejected promise* rather than a synchronous
/// throw.
fn asyncGenProtoMethod(comptime which: enum { next, ret, throw }) value.NativeFn {
    return struct {
        fn call(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
            const self: *Interpreter = @ptrCast(@alignCast(ctx));
            if (!this.isObject() or this.asObj().gen == null or !vm.asyncGenObj(this.asObj())) {
                const pobj = try promise.newPromise(self);
                const p = promise.promiseOf(Value.obj(pobj)).?;
                const err = try self.makeError("TypeError", "AsyncGenerator method called on an incompatible receiver");
                try promise.reject(self, p, err);
                return Value.obj(pobj);
            }
            const v: Value = if (args.len > 0) args[0] else Value.undef();
            return switch (which) {
                .next => vm.genNext(self, this.asObj(), v),
                .ret => vm.genReturn(self, this.asObj(), v),
                .throw => vm.genThrow(self, this.asObj(), v),
            };
        }
    }.call;
}

/// The shared setter for %Iterator.prototype%'s `constructor` and
/// `@@toStringTag` accessors: reject a non-object receiver or the home object
/// (%Iterator.prototype%, which emulates a non-writable data property), then
/// write an own property on the receiver — CreateDataPropertyOrThrow when absent
/// or Set when present (both bypass this inherited accessor).
fn iterProtoAccessorSet(self: *Interpreter, this: Value, key: []const u8, v: Value) EvalError!Value {
    const home: ?*value.Object = if (self.env.get("\x00IterProto")) |h|
        (if (h.isObject()) h.asObj() else null)
