fn iterProtoTagSetterFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const key = symbolToStringTagKey(self) orelse return Value.undef();
