/// `Temporal.<Type>.prototype.valueOf` is a poison pill: it always throws, so a
/// Temporal value can never be implicitly converted with `<`/`>`/`+` (callers
/// must use `compare`/`equals`).
fn temporalValueOfFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    return self.throwError("TypeError", "Called valueOf on a Temporal type; use compare() / equals() / a string conversion instead");
}

/// `Temporal.<Type>.prototype.toLocaleString(locales, options)` — without an Intl
/// Temporal data table this falls back to the default ISO `toString`. The
/// locale/options arguments are deliberately ignored (not forwarded to
/// `toString`, whose option set differs), and the receiver is brand-checked.
fn temporalToLocaleStringFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject() or this.asObj().temporal == null) return self.throwError("TypeError", "toLocaleString called on a non-Temporal value");
    const none: []const Value = &.{};
    return switch (this.asObj().temporal.?.kind) {
        .plain_date => temporalPlainDateToStringFn(ctx, this, none),
        .plain_time => temporalPlainTimeToStringFn(ctx, this, none),
        .plain_date_time => temporalPlainDateTimeToStringFn(ctx, this, none),
        .plain_year_month => temporalYearMonthToStringFn(ctx, this, none),
        .plain_month_day => temporalMonthDayToStringFn(ctx, this, none),
        .instant => temporalInstantToStringFn(ctx, this, none),
        .zoned_date_time => temporalZdtToStringFn(ctx, this, none),
        .duration => temporalDurationToStringFn(ctx, this, none),
    };
}

/// ToTemporalCalendarSlotValue, restricted to the only supported calendar
/// (iso8601): a Temporal instance contributes its own calendar; any other value
/// is `ToString`'d and must name `iso8601`, else a RangeError.
fn requireIsoCalendarArg(self: *Interpreter, v: Value) value.HostError!void {
    if (v.isObject() and v.asObj().temporal != null) return; // a Temporal instance is iso8601 here
    // ToTemporalCalendarIdentifier: a non-object non-String is a TypeError.
    if (!v.isString()) return self.throwError("TypeError", "calendar must be a string or a Temporal object");
    const s = v.asStr();
    if (asciiEqlIgnoreCase(s, "iso8601")) return; // a bare calendar id
    // Otherwise the string is a Temporal date/time string whose calendar
    // annotation (default iso8601) must resolve to iso8601.
    _ = stripTemporalAnnotations(self, s) catch return self.throwError("RangeError", "invalid calendar string");
}

fn temporalPlainDateWithCalendarFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!tIsTemporal(this, .plain_date)) return self.throwError("TypeError", "non-PlainDate");
    const cal = try toCalendarId(self, if (args.len > 0) args[0] else Value.undef());
    const t = this.asObj().temporal.?;
    const iso = calendarDateToIso(t.calendar, t.year, t.month, t.day);
    const cd = calendarDateFromIso(cal, iso.y, iso.m, iso.d);
    const o = try makeTemporal(self, .plain_date, "\x00T.PlainDate");
    o.temporal.?.year = @intCast(cd.y);
    o.temporal.?.month = cd.m;
    o.temporal.?.day = cd.d;
    o.temporal.?.calendar = cal;
    return Value.obj(o);
}

fn temporalDateTimeWithCalendarFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!tIsTemporal(this, .plain_date_time)) return self.throwError("TypeError", "non-PlainDateTime");
    const cal = try toCalendarId(self, if (args.len > 0) args[0] else Value.undef());
    const t = this.asObj().temporal.?;
    const iso = calendarDateToIso(t.calendar, t.year, t.month, t.day);
    const cd = calendarDateFromIso(cal, iso.y, iso.m, iso.d);
    const o = try makeTemporal(self, .plain_date_time, "\x00T.PlainDateTime");
    o.temporal.?.* = t.*;
    o.temporal.?.year = @intCast(cd.y);
    o.temporal.?.month = cd.m;
    o.temporal.?.day = cd.d;
    o.temporal.?.calendar = cal;
    return Value.obj(o);
}

/// Nanoseconds since the Unix epoch for a local date+time (no time-zone offset
/// applied) held in `t`'s year/month/day + hour/.../nanosecond fields.
fn dtLocalNs(t: *const value.TemporalData) i128 {
    return @as(i128, tDaysFromCivil(t.year, t.month, t.day)) * 86_400_000_000_000 +
        @as(i128, t.hour) * 3_600_000_000_000 +
        @as(i128, t.minute) * 60_000_000_000 +
        @as(i128, t.second) * 1_000_000_000 +
        @as(i128, t.millisecond) * 1_000_000 +
        @as(i128, t.microsecond) * 1_000 +
        @as(i128, t.nanosecond);
}

/// ToTemporalTimeZoneSlotValue restricted to fixed-offset / named zones: a
/// ZonedDateTime contributes its own zone; otherwise `ToString` then `parseTimeZone`.
fn resolveTimeZoneArg(self: *Interpreter, v: Value) value.HostError!TimeZone {
    if (v.isObject()) if (v.asObj().temporal) |t| if (t.kind == .zoned_date_time)
        return TimeZone{ .name = t.tz_name, .offset_ns = t.tz_offset_ns };
    return parseTimeZone(self, try self.toStringV(v));
}

/// `Temporal.PlainDateTime.prototype.toZonedDateTime(timeZone, options)`.
fn temporalDateTimeToZonedDateTimeFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!tIsTemporal(this, .plain_date_time)) return self.throwError("TypeError", "non-PlainDateTime");
    if (args.len == 0 or args[0].isUndefined()) return self.throwError("TypeError", "toZonedDateTime requires a time zone");
    const tz = try resolveTimeZoneArg(self, args[0]);
    // GetTemporalDisambiguationOption (validated even though fixed-offset zones
    // ignore it — an invalid value must still throw).
    if (args.len > 1 and !args[1].isUndefined()) {
        if (!args[1].isObject()) return self.throwError("TypeError", "options must be an object");
        _ = try dtfGetStr(self, args[1], "disambiguation", &.{ "compatible", "earlier", "later", "reject" }, "compatible");
    }
    const local = dtLocalNs(this.asObj().temporal.?);
    const o = try zdtMake(self, local - @as(i128, tz.offset_ns), tz.name, tz.offset_ns);
    o.asObj().temporal.?.* = this.asObj().temporal.?.*;
    o.asObj().temporal.?.kind = .zoned_date_time;
    o.asObj().temporal.?.epoch_ns = local - @as(i128, tz.offset_ns);
    o.asObj().temporal.?.tz_name = tz.name;
    o.asObj().temporal.?.tz_offset_ns = tz.offset_ns;
    return o;
}

/// `Temporal.PlainDate.prototype.toZonedDateTime(item)` — `item` is a time-zone
/// (string/ZonedDateTime) or a `{ timeZone, plainTime }` bag (default midnight).
fn temporalDateToZonedDateTimeFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!tIsTemporal(this, .plain_date)) return self.throwError("TypeError", "non-PlainDate");
    const item = if (args.len > 0) args[0] else Value.undef();
    var tz: TimeZone = undefined;
    var time = value.TemporalData{ .kind = .plain_time }; // midnight
    if (item.isObject() and (item.asObj().temporal == null or item.asObj().temporal.?.kind != .zoned_date_time)) {
        // A bag: { timeZone (required), plainTime (optional) }.
        const tzv = try self.getProperty(item, "timeZone");
        if (tzv.isUndefined()) return self.throwError("TypeError", "toZonedDateTime: missing timeZone");
        tz = try resolveTimeZoneArg(self, tzv);
        const ptv = try self.getProperty(item, "plainTime");
        if (!ptv.isUndefined()) time = try toPlainTimeData(self, ptv);
    } else {
        if (item.isUndefined()) return self.throwError("TypeError", "toZonedDateTime requires a time zone");
        tz = try resolveTimeZoneArg(self, item);
    }
    const d = this.asObj().temporal.?;
    var combined = value.TemporalData{ .kind = .plain_date_time };
    combined.year = d.year;
    combined.month = d.month;
    combined.day = d.day;
    combined.hour = time.hour;
    combined.minute = time.minute;
    combined.second = time.second;
    combined.millisecond = time.millisecond;
    combined.microsecond = time.microsecond;
    combined.nanosecond = time.nanosecond;
    const local = dtLocalNs(&combined);
    const o = try zdtMake(self, local - @as(i128, tz.offset_ns), tz.name, tz.offset_ns);
    const out = o.asObj().temporal.?;
    out.year = d.year;
    out.month = d.month;
    out.day = d.day;
    out.hour = time.hour;
    out.minute = time.minute;
    out.second = time.second;
    out.millisecond = time.millisecond;
    out.microsecond = time.microsecond;
    out.nanosecond = time.nanosecond;
    out.calendar = d.calendar;
    return o;
}

/// `Temporal.Instant.prototype.toZonedDateTimeISO(timeZone)`.
fn temporalInstantToZonedDateTimeISOFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!tIsTemporal(this, .instant)) return self.throwError("TypeError", "non-Instant");
    if (args.len == 0 or args[0].isUndefined()) return self.throwError("TypeError", "toZonedDateTimeISO requires a time zone");
    const tz = try resolveTimeZoneArg(self, args[0]);
    return zdtMake(self, this.asObj().temporal.?.epoch_ns, tz.name, tz.offset_ns);
}

