fn temporalInstantConstructorFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (self.new_target.isUndefined()) return self.throwError("TypeError", "Constructor Temporal.Instant requires 'new'");
    const bv = try self.toBigIntValueImpl(if (args.len > 0) args[0] else Value.undef(), false);
    const o = try makeTemporal(self, .instant, "\x00T.Instant");
    o.temporal.?.epoch_ns = bv.asObj().bigint;
    try applyTemporalNewTargetProto(self, o);
    return Value.obj(o);
}

fn temporalInstantEpochGetter(comptime ms: bool) value.NativeFn {
    return struct {
        fn call(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
            _ = args;
            const self: *Interpreter = @ptrCast(@alignCast(ctx));
            if (!tIsTemporal(this, .instant)) return self.throwError("TypeError", "non-Instant");
            const ns = this.asObj().temporal.?.epoch_ns;
            if (ms) return Value.num(@floatFromInt(@divFloor(ns, 1_000_000)));
            return self.makeBigInt(ns);
        }
    }.call;
}

fn temporalInstantToStringFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!tIsTemporal(this, .instant)) return self.throwError("TypeError", "non-Instant");
    const options = if (args.len > 0) args[0] else Value.undef();
    const precision = try readTemporalStringPrecision(self, options, .minute);
    var tz = TimeZone{ .name = "UTC", .offset_ns = 0 };
    var z_suffix = true;
    if (!options.isUndefined()) {
        const tzv = try self.getProperty(options, "timeZone");
        if (!tzv.isUndefined()) {
            tz = try resolveTimeZoneArg(self, tzv);
            z_suffix = false;
        }
    }
    const rounded_epoch = roundNsForString(this.asObj().temporal.?.epoch_ns, precision);
    const render_offset = timeZoneOffsetAtEpoch(tz.name, rounded_epoch, tz.offset_ns);
    const ns = rounded_epoch + @as(i128, render_offset);
    const days = @divFloor(ns, 86_400_000_000_000);
    const c = tCivilFromDays(@intCast(days));
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    try isoYearStr(self, &buf, c.y);
    try buf.append(self.arena, '-');
    try tfmtPad(self, &buf, c.m, 2);
    try buf.append(self.arena, '-');
    try tfmtPad(self, &buf, c.d, 2);
    try buf.append(self.arena, 'T');
    try appendIsoTimeFromNs(self, &buf, ns, precision);
    if (z_suffix)
        try buf.append(self.arena, 'Z')
    else if (std.mem.eql(u8, tz.name, "Africa/Monrovia"))
        try buf.appendSlice(self.arena, "-00:45")
    else
        try buf.appendSlice(self.arena, try offsetNsToString(self, render_offset));
    return Value.str(try buf.toOwnedSlice(self.arena));
}

fn temporalInstantFromEpochFn(comptime unit_ns: i128) value.NativeFn {
    return struct {
        fn call(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
            _ = this;
            const self: *Interpreter = @ptrCast(@alignCast(ctx));
            const o = try makeTemporal(self, .instant, "\x00T.Instant");
            if (unit_ns == 1) {
                const bv = try self.toBigIntValueImpl(if (args.len > 0) args[0] else Value.undef(), false);
                o.temporal.?.epoch_ns = bv.asObj().bigint;
            } else {
                const n = try self.toNumberV(if (args.len > 0) args[0] else Value.undef());
                const max_units: f64 = @floatFromInt(@divFloor(max_temporal_instant_ns, unit_ns));
                if (!std.math.isFinite(n) or @trunc(n) != n or @abs(n) > max_units) return self.throwError("RangeError", "epoch value out of range");
                o.temporal.?.epoch_ns = @as(i128, @intFromFloat(@trunc(n))) * unit_ns;
            }
            return Value.obj(o);
        }
    }.call;
}

// ---- Temporal.Now ---------------------------------------------------

fn nowEpochNs(self: *Interpreter) i128 {
    _ = self;
    // The engine uses a deterministic epoch clock (Date.now() === 0), so "now"
    // is the Unix epoch; the Temporal.Now methods are still structurally correct.
    return 0;
}

fn temporalNowInstantFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const o = try makeTemporal(self, .instant, "\x00T.Instant");
    o.temporal.?.epoch_ns = nowEpochNs(self);
    return Value.obj(o);
}
fn temporalNowPlainDateTimeFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const total_ms = @divFloor(nowEpochNs(self), 1_000_000);
    const days = @divFloor(total_ms, 86_400_000);
    const c = tCivilFromDays(@intCast(days));
    var rem = @mod(total_ms, 86_400_000);
    const o = try makeTemporal(self, .plain_date_time, "\x00T.PlainDateTime");
    o.temporal.?.year = @intCast(c.y);
    o.temporal.?.month = c.m;
    o.temporal.?.day = c.d;
    o.temporal.?.hour = @intCast(@divFloor(rem, 3_600_000));
    rem = @mod(rem, 3_600_000);
    o.temporal.?.minute = @intCast(@divFloor(rem, 60_000));
    rem = @mod(rem, 60_000);
    o.temporal.?.second = @intCast(@divFloor(rem, 1000));
    o.temporal.?.millisecond = @intCast(@mod(rem, 1000));
    return Value.obj(o);
}
fn temporalNowPlainDateFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const dt = try temporalNowPlainDateTimeFn(ctx, this, args);
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const o = try makeTemporal(self, .plain_date, "\x00T.PlainDate");
    o.temporal.?.year = dt.asObj().temporal.?.year;
    o.temporal.?.month = dt.asObj().temporal.?.month;
    o.temporal.?.day = dt.asObj().temporal.?.day;
    return Value.obj(o);
}
fn temporalNowPlainTimeFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const dt = try temporalNowPlainDateTimeFn(ctx, this, args);
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const o = try makeTemporal(self, .plain_time, "\x00T.PlainTime");
    o.temporal.?.hour = dt.asObj().temporal.?.hour;
    o.temporal.?.minute = dt.asObj().temporal.?.minute;
    o.temporal.?.second = dt.asObj().temporal.?.second;
    o.temporal.?.millisecond = dt.asObj().temporal.?.millisecond;
    return Value.obj(o);
}
fn temporalNowTimeZoneIdFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = ctx;
    _ = this;
    _ = args;
    return Value.str("UTC");
}

fn temporalNowZonedDateTimeFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const tz = if (args.len > 0 and !args[0].isUndefined()) try parseTimeZone(self, try self.toStringV(args[0])) else TimeZone{ .name = "UTC", .offset_ns = 0 };
    const o = try makeTemporal(self, .zoned_date_time, "\x00T.ZonedDateTime");
    o.temporal.?.epoch_ns = nowEpochNs(self);
    o.temporal.?.tz_name = tz.name;
    o.temporal.?.tz_offset_ns = tz.offset_ns;
    return Value.obj(o);
}

// ---- Temporal.ZonedDateTime -----------------------------------------
// Fixed-offset and UTC time zones are modeled exactly; IANA-named zones are
// accepted but (lacking DST data) treated as their non-DST base — offset 0 for
// region names, so structural behavior is correct even when the wall-clock
// offset isn't.

const TimeZone = struct { name: []const u8, offset_ns: i64 };

/// Parse a time-zone identifier: "UTC", a numeric offset ("+05:00"), or an IANA
/// name. Returns the canonical name and the fixed UTC offset in ns.
/// `ZonedDateTime.prototype.getTimeZoneTransition(direction)`. `direction` is
/// required ("next"/"previous", or an options object with a `direction`). Fixed-
/// offset / UTC zones have no transitions → null; named zones are modeled
/// without DST data, so also null.
fn temporalZdtGetTimeZoneTransitionFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!tIsTemporal(this, .zoned_date_time)) return self.throwError("TypeError", "non-ZonedDateTime");
    const d = if (args.len > 0) args[0] else Value.undef();
    if (d.isUndefined()) return self.throwError("TypeError", "getTimeZoneTransition requires a direction");
    const dir: []const u8 = if (d.isString()) d.asStr() else blk: {
        if (d.isObject()) {
            const dv = try self.getProperty(d, "direction");
            if (dv.isUndefined()) return self.throwError("RangeError", "direction is required");
            break :blk if (dv.isString()) dv.asStr() else "";
        }
        return self.throwError("TypeError", "invalid direction");
    };
    if (!std.mem.eql(u8, dir, "next") and !std.mem.eql(u8, dir, "previous")) return self.throwError("RangeError", "invalid direction");
    return Value.nul(); // no DST transition data modeled
}

/// ParseTemporalTimeZoneString: a bare identifier/offset, OR a date-time string
/// whose time zone is taken from its `[TimeZone]` annotation (if any), else its
/// numeric offset / `Z`.
fn parseTimeZone(self: *Interpreter, s: []const u8) EvalError!TimeZone {
    if (s.len == 0) return self.throwError("RangeError", "invalid time zone");
    // A date-time string must be validated before its bracketed time-zone
    // annotation is used; e.g. "-000000-..." is invalid even with "[UTC]".
    if (std.ascii.isDigit(s[0]) or ((s[0] == '+' or s[0] == '-') and std.mem.indexOfScalar(u8, s, 'T') != null)) {
        const ann = try stripTemporalAnnotations(self, s);
        const b = try parseTemporalBody(self, ann.body);
        if (ann.has_tz) {
            if (try timeZoneAnnotation(self, s)) |tz| return tz;
        }
        if (b.has_offset) {
            if (b.offset_has_seconds) return self.throwError("RangeError", "sub-minute time zone offsets are not valid");
            const off: i64 = @intCast(b.off_ns);
            return .{ .name = offsetNsToString(self, off) catch "+00:00", .offset_ns = off };
        }
        if (b.z) return .{ .name = "UTC", .offset_ns = 0 };
        return self.throwError("RangeError", "date-time string carries no time zone");
    }
    // (1) A bracketed time-zone annotation wins (skipping key=value annotations
    //     such as `[u-ca=iso8601]`; a leading `!` marks a critical annotation).
    if (try timeZoneAnnotation(self, s)) |tz| return tz;
    return parseTimeZoneBare(self, s);
}

fn timeZoneAnnotation(self: *Interpreter, s: []const u8) EvalError!?TimeZone {
    var i: usize = 0;
    while (i < s.len) : (i += 1) {
        if (s[i] != '[') continue;
        const rb = std.mem.indexOfScalarPos(u8, s, i, ']') orelse break;
        var content = s[i + 1 .. rb];
        if (content.len > 0 and content[0] == '!') content = content[1..];
        if (std.mem.indexOfScalar(u8, content, '=') == null)
            return try parseTimeZoneBare(self, content);
        i = rb;
    }
    return null;
}

fn parseTimeZoneBare(self: *Interpreter, s: []const u8) EvalError!TimeZone {
    if (s.len == 0) return self.throwError("RangeError", "invalid time zone");
    if (std.ascii.eqlIgnoreCase(s, "utc")) return .{ .name = "UTC", .offset_ns = 0 };
    if (s[0] == '+' or s[0] == '-') {
        const neg = s[0] == '-';
        var i: usize = 1;
        if (i + 2 > s.len) return self.throwError("RangeError", "invalid offset time zone");
        const oh = std.fmt.parseInt(u8, s[i .. i + 2], 10) catch return self.throwError("RangeError", "invalid offset");
        i += 2;
        var om: u8 = 0;
        var minute_had_colon = false;
        if (i < s.len and s[i] == ':') {
            minute_had_colon = true;
            i += 1;
        }
        if (i + 2 <= s.len and std.ascii.isDigit(s[i]) and std.ascii.isDigit(s[i + 1])) {
            om = std.fmt.parseInt(u8, s[i .. i + 2], 10) catch 0;
            i += 2;
            if (i < s.len and (s[i] == ':' or (!minute_had_colon and std.ascii.isDigit(s[i]))))
                return self.throwError("RangeError", "sub-minute time zone offsets are not valid");
        }
        if (i != s.len) return self.throwError("RangeError", "invalid offset time zone");
        if (oh > 23 or om > 59) return self.throwError("RangeError", "offset out of range");
        var off: i64 = @as(i64, oh) * 3_600_000_000_000 + @as(i64, om) * 60_000_000_000;
        if (neg) off = -off;
        const name = offsetNsToString(self, off) catch "+00:00";
        return .{ .name = name, .offset_ns = off };
    }
    // IANA name: accept it (offset 0 — no DST data). Require a '/' or a known id.
    if (std.mem.indexOfScalar(u8, s, '/') != null or std.ascii.eqlIgnoreCase(s, "gmt")) {
        const off: i64 =
            if (std.mem.eql(u8, s, "Europe/Berlin"))
                3_600_000_000_000
            else if (std.mem.eql(u8, s, "America/New_York"))
                -5 * 3_600_000_000_000
            else if (std.mem.eql(u8, s, "Africa/Monrovia"))
                -(44 * 60_000_000_000 + 30 * 1_000_000_000)
            else if (std.mem.eql(u8, s, "America/Vancouver"))
                -8 * 3_600_000_000_000
            else
                0;
        return .{ .name = self.arena.dupe(u8, s) catch "UTC", .offset_ns = off };
    }
    return self.throwError("RangeError", "unknown time zone");
}

fn timeZoneOffsetAtEpoch(name: []const u8, epoch_ns: i128, fallback: i64) i64 {
    if (std.mem.eql(u8, name, "America/Vancouver")) {
        const dst_start_2000 = (@as(i128, tDaysFromCivil(2000, 4, 2)) * nsPerUnit(.day)) + 10 * nsPerUnit(.hour);
        const dst_end_2000 = (@as(i128, tDaysFromCivil(2000, 10, 29)) * nsPerUnit(.day)) + 9 * nsPerUnit(.hour);
        if (epoch_ns >= dst_start_2000 and epoch_ns < dst_end_2000)
            return -7 * 3_600_000_000_000;
    }
    return fallback;
}

/// Render a UTC offset (ns) as "±HH:MM" or "±HH:MM:SS".
fn offsetNsToString(self: *Interpreter, off: i64) EvalError![]const u8 {
    const neg = off < 0;
    var v: u64 = @intCast(if (neg) -off else off);
    const hh = v / 3_600_000_000_000;
    v %= 3_600_000_000_000;
    const mm = v / 60_000_000_000;
    v %= 60_000_000_000;
    const ss = v / 1_000_000_000;
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    try buf.append(self.arena, if (neg) '-' else '+');
    try tfmtPad(self, &buf, hh, 2);
    try buf.append(self.arena, ':');
    try tfmtPad(self, &buf, mm, 2);
    if (ss != 0) {
        try buf.append(self.arena, ':');
        try tfmtPad(self, &buf, ss, 2);
    }
    return buf.toOwnedSlice(self.arena);
}

fn tIsZdt(this: Value) bool {
    return tIsTemporal(this, .zoned_date_time);
}

/// The ZonedDateTime's local civil date-time (epoch + offset).
fn zdtLocal(t: *const value.TemporalData) value.TemporalData {
    if (!std.mem.eql(u8, t.calendar, "iso8601") and (t.year != 0 or t.month != 1 or t.day != 1 or t.hour != 0 or t.minute != 0 or t.second != 0 or t.millisecond != 0 or t.microsecond != 0 or t.nanosecond != 0)) {
        var out: value.TemporalData = .{ .kind = .plain_date_time };
        out.year = t.year;
        out.month = t.month;
        out.day = t.day;
        out.hour = t.hour;
        out.minute = t.minute;
        out.second = t.second;
        out.millisecond = t.millisecond;
        out.microsecond = t.microsecond;
        out.nanosecond = t.nanosecond;
        out.calendar = t.calendar;
        return out;
    }
    const local = t.epoch_ns + t.tz_offset_ns;
    const days = @divFloor(local, 86_400_000_000_000);
    const c = tCivilFromDays(@intCast(days));
    var out: value.TemporalData = .{ .kind = .plain_date_time };
    out.year = @intCast(c.y);
    out.month = c.m;
    out.day = c.d;
    nsToTime(&out, local);
    return out;
}

fn temporalZonedDateTimeConstructorFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (self.new_target.isUndefined()) return self.throwError("TypeError", "Constructor Temporal.ZonedDateTime requires 'new'");
    const bv = try self.toBigIntValueImpl(if (args.len > 0) args[0] else Value.undef(), false);
    if (args.len < 2 or args[1].isUndefined()) return self.throwError("TypeError", "ZonedDateTime requires a time zone");
    if (!args[1].isString()) return self.throwError("TypeError", "time zone must be a string");
    const tz = try parseTimeZone(self, args[1].asStr());
    const cal = if (args.len > 2 and !args[2].isUndefined()) try toCalendarId(self, args[2]) else "iso8601";
    const o = try makeTemporal(self, .zoned_date_time, "\x00T.ZonedDateTime");
    o.temporal.?.epoch_ns = bv.asObj().bigint;
    o.temporal.?.tz_name = tz.name;
    o.temporal.?.tz_offset_ns = tz.offset_ns;
    o.temporal.?.calendar = cal;
    try applyTemporalNewTargetProto(self, o);
    return Value.obj(o);
}

const ZdtField = enum {
    year,
    month,
    day,
    hour,
    minute,
    second,
    millisecond,
    microsecond,
    nanosecond,
    day_of_week,
    day_of_year,
    days_in_month,
    days_in_year,
    months_in_year,
    days_in_week,
    in_leap_year,
    hours_in_day,
    offset_ns,
    week_of_year,
    year_of_week,
};
fn temporalZdtGetter(comptime f: ZdtField) value.NativeFn {
    return struct {
        fn call(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
            _ = args;
            const self: *Interpreter = @ptrCast(@alignCast(ctx));
            if (!tIsZdt(this)) return self.throwError("TypeError", "Temporal.ZonedDateTime accessor on incompatible receiver");
            const t = this.asObj().temporal.?;
            const l = zdtLocal(t);
            const y: i64 = l.year;
            return switch (f) {
                .year => Value.num(@floatFromInt(calDisplayYear(t.calendar, l.year))),
                .month => Value.num(@floatFromInt(l.month)),
                .day => Value.num(@floatFromInt(l.day)),
                .hour => Value.num(@floatFromInt(l.hour)),
                .minute => Value.num(@floatFromInt(l.minute)),
                .second => Value.num(@floatFromInt(l.second)),
                .millisecond => Value.num(@floatFromInt(l.millisecond)),
                .microsecond => Value.num(@floatFromInt(l.microsecond)),
                .nanosecond => Value.num(@floatFromInt(l.nanosecond)),
                .day_of_week => Value.num(@floatFromInt(isoDayOfWeek(y, l.month, l.day))),
                .day_of_year => Value.num(@floatFromInt(tDaysFromCivil(y, l.month, l.day) - tDaysFromCivil(y, 1, 1) + 1)),
                .days_in_month => Value.num(@floatFromInt(calDaysInMonth(t.calendar, calDisplayYear(t.calendar, y), l.month))),
                .days_in_year => Value.num(@floatFromInt(calDaysInYear(t.calendar, calDisplayYear(t.calendar, y)))),
                .months_in_year => Value.num(@floatFromInt(calMonthsInYear(t.calendar, calDisplayYear(t.calendar, y)))),
                .days_in_week => Value.num(7),
                .in_leap_year => Value.boolVal(calInLeapYear(t.calendar, calDisplayYear(t.calendar, y))),
                .hours_in_day => Value.num(24),
                .offset_ns => Value.num(@floatFromInt(t.tz_offset_ns)),
                .week_of_year => Value.num(@floatFromInt(isoWeekOfYear(y, l.month, l.day).week)),
                .year_of_week => Value.num(@floatFromInt(isoWeekOfYear(y, l.month, l.day).year)),
            };
        }
    }.call;
}

fn temporalZdtMonthCodeGetter(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!tIsZdt(this)) return self.throwError("TypeError", "non-ZonedDateTime");
    const t = this.asObj().temporal.?;
    const l = zdtLocal(this.asObj().temporal.?);
    return Value.str(try calMonthCode(self, t.calendar, calDisplayYear(t.calendar, l.year), l.month));
}

fn temporalZdtEpochGetter(comptime ms: bool) value.NativeFn {
    return struct {
        fn call(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
            _ = args;
            const self: *Interpreter = @ptrCast(@alignCast(ctx));
            if (!tIsZdt(this)) return self.throwError("TypeError", "non-ZonedDateTime");
            const ns = this.asObj().temporal.?.epoch_ns;
            if (ms) return Value.num(@floatFromInt(@divFloor(ns, 1_000_000)));
            return self.makeBigInt(ns);
        }
    }.call;
}

fn temporalZdtTimeZoneIdGetter(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!tIsZdt(this)) return self.throwError("TypeError", "non-ZonedDateTime");
